-- Poems batch 171
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('12aaa9f1-321c-42c5-8a88-cfca35d539fc','送趙幾道邵武司戶','葉適','宋','宋诗','song-poetry','','[]','無灘秋水平，有句官曹清。',48,'全唐诗/poet.song.169000.json','["無灘秋水平，有句官曹清。", "楊柳欲落盡，菊花愁晚生。", "書多前益智，文古後垂名。", "功到闊深處，天教勤苦成。"]'),
('0a41d2c5-5bda-40c8-b15a-16ea2c9fc407','常德郎中林公挽詞','葉適','宋','宋诗','song-poetry','','[]','結佩聲名遠，懷沙興託深。',48,'全唐诗/poet.song.169000.json','["結佩聲名遠，懷沙興託深。", "惜無長綆繫，終使夕陽沉。", "蘭省空頻召，桃源不再尋。", "雖傷有北毀，難減是南金。"]'),
('3ff45fca-203a-4b7b-8a0a-b8e99dc34fb8','贈鄭秀才','葉適','宋','宋诗','song-poetry','','[]','文苦意尤切，色低聲轉微。',48,'全唐诗/poet.song.169000.json','["文苦意尤切，色低聲轉微。", "三生住淺土，一竁阻深歸。", "藝圃筆鋒掃，侯門麈柄揮。", "何慚素車集，回繞絳旌飛。"]'),
('08b0a067-bbe8-42d2-9933-af11651d96d4','贈李秀才順之','葉適','宋','宋诗','song-poetry','','[]','怒漲爭茅竹，安流節斗門。',48,'全唐诗/poet.song.169000.json','["怒漲爭茅竹，安流節斗門。", "行苗存水則，縮板護河源。", "士李昔陳義，守奚能聽言。", "便當生廟食，禾熟賽鷄豚。"]'),
('aad1f5af-65e2-4c33-a0bf-622e3236ffa1','送侯居父','葉適','宋','宋诗','song-poetry','','[]','宅古竹陰晚，書殘燈焰稀。',48,'全唐诗/poet.song.169000.json','["宅古竹陰晚，書殘燈焰稀。", "深知靜者趣，轉益宦情微。", "別殿行催甲，休工坐掩扉。", "御前清切地，重得薦皇闈。"]'),
('3e5289a4-efb5-4900-9b01-754ac303d9c4','贈高竹有外姪','葉適','宋','宋诗','song-poetry','','[]','娶女已爲客，參翁又別行。',48,'全唐诗/poet.song.169000.json','["娶女已爲客，參翁又別行。", "相隨小書卷，開讀短燈檠。", "野影晨迷樹，天文夜照城。", "須將遠遊什，題寄老夫評。"]'),
('f709d68d-c6d8-4f2d-b955-be7df602e9f0','贈夏肯甫','葉適','宋','宋诗','song-poetry','','[]','自識賢尊熟，常將遠到期。',48,'全唐诗/poet.song.169000.json','["自識賢尊熟，常將遠到期。", "忽傳千古信，虛抱一生疑。", "恨菊來何久，愁梅去轉遲。", "應留起春蟄，詞落未堪悲。"]'),
('0eeb6e2d-1495-4995-97ee-4b89d8719e71','趙知府母齊安郡太夫人挽詩','葉適','宋','宋诗','song-poetry','','[]','生死已無憾，杭人休淚傾。',48,'全唐诗/poet.song.169000.json','["生死已無憾，杭人休淚傾。", "惟留不盡德，常動故鄉情。", "霜浄水方落，風高山轉清。", "閑思與令子，幕府再同盟。"]'),
('1900a493-aece-4337-9d4d-93170a16f021','沈氏書堂','葉適','宋','宋诗','song-poetry','','[]','應與石渠並，又疑金匱存。',48,'全唐诗/poet.song.169000.json','["應與石渠並，又疑金匱存。", "曬書天象切，浴硯海光翻。", "我老行罷讀，君材重細論。", "猶言無一字，大道始歸根。"]'),
('b72206cc-f052-4154-9a9b-78cdcf5ca56f','薛子舒墓','葉適','宋','宋诗','song-poetry','','[]','悒悒西門路，樵歌占晚雲。',48,'全唐诗/poet.song.169000.json','["悒悒西門路，樵歌占晚雲。", "燐迷王弼宅，蒿長孟郊墳。", "少病憐醫錯，題書與父分。", "又言重把筆，兼欲使余聞。"]'),
('580be3b4-971b-4928-b873-d2f0693eb34d','項君先有幽興堂其子木即以名庵','葉適','宋','宋诗','song-poetry','','[]','平生意外事，身後有誰知。',48,'全唐诗/poet.song.169000.json','["平生意外事，身後有誰知。", "魄靜雲稀出，神游月共移。", "春茶翠旗展，霜荔錦檐垂。", "更欲添幽興，惟消桂幾枝。"]'),
('cc053267-db46-45f1-8064-2c69927bfbbf','施翔父掌教長沙','葉適','宋','宋诗','song-poetry','','[]','蓍蔡羲前識，簫韶舜後音。',48,'全唐诗/poet.song.169000.json','["蓍蔡羲前識，簫韶舜後音。", "追回賈誼貶，喚起屈原沉。", "湘水汀煙闊，梅花署雪深。", "余行陳迹久，因子一微吟。"]'),
('a69a0dd5-54a8-4f83-a8c3-795e3e9e8e58','送劉幾道惠安尉','葉適','宋','宋诗','song-poetry','','[]','少年嘗苦節，從我北城隈。',48,'全唐诗/poet.song.169000.json','["少年嘗苦節，從我北城隈。", "麗日明文苑，繁星讓斗魁。", "垂垂綠綬晚，冉冉白絲催。", "更菲游仙去，鯨波奏凱回。"]'),
('630c0862-dad3-4cee-bc47-95a665af6766','送陳約甫知永豐','葉適','宋','宋诗','song-poetry','','[]','四十未朝蹟，三經綰縣章。',48,'全唐诗/poet.song.169000.json','["四十未朝蹟，三經綰縣章。", "嫁頻知子熟，醫老悟身嘗。", "菊趁行時色，梅催到日香。", "還欣肺氣減，中熟變爲凉。"]'),
('613134fc-e53e-400f-b71b-e0b004eadb37','王祕監令人挽詩','葉適','宋','宋诗','song-poetry','','[]','頗憶朝除禫，俄驚夜徹帷。',48,'全唐诗/poet.song.169000.json','["頗憶朝除禫，俄驚夜徹帷。", "自堪從子住，何用與夫歸。", "起隧新藤茁，重轝宿菵排。", "通家只今盡，老淚逐風揮。"]'),
('708fa0f8-b75c-4c4f-a4da-04e2487b1fe5','奉送周知錄木叔祕監其舅也','葉適','宋','宋诗','song-poetry','','[]','謝傅悵何遠，羊甥良自嘉。',48,'全唐诗/poet.song.169000.json','["謝傅悵何遠，羊甥良自嘉。", "帝鄉沉迹顯，囹戶衆縲誇。", "釣冷客星雪，林疎處士花。", "衰年怕分手，閑發岸頭沙。"]'),
('3d0969ba-6129-4aa5-b3da-d466b221cd50','葉路分居思堂  其一','葉適','宋','宋诗','song-poetry','','[]','葉媼開新學，同人飯野蔬。',48,'全唐诗/poet.song.169000.json','["葉媼開新學，同人飯野蔬。", "明經傳一相，考古付三餘。", "苔色迷青簡，蟲文蝕素書。", "君能葺遺址，堂宇勝於初。"]'),
('25399b40-c5fa-4303-b8b8-5891fb80e123','葉路分居思堂  其二','葉適','宋','宋诗','song-poetry','','[]','苦說諸梁後，簪纓富遠孫。',48,'全唐诗/poet.song.169000.json','["苦說諸梁後，簪纓富遠孫。", "白袍雖屢捷，黄榜未霑恩。", "淡沱磨冰硯，蕭條倚帳門。", "嗟余忝宗末，老病不堪論。"]'),
('95ff7cbd-e2a0-45be-9774-768973132e53','王通判挽詞','葉適','宋','宋诗','song-poetry','','[]','祖德風規近，詩流句法超。',48,'全唐诗/poet.song.169000.json','["祖德風規近，詩流句法超。", "已多山邑政，恰少省郎招。", "旅館身俱寂，傳家道未消。", "長令漢楊震，名逐左原標。"]'),
('64c5bc8e-8ca8-40c0-8c4b-032193e7bf17','林簽判挽詩','葉適','宋','宋诗','song-poetry','','[]','作邑有何好，利民翻害身。',48,'全唐诗/poet.song.169000.json','["作邑有何好，利民翻害身。", "怕回湘水月，驚失象臺春。", "暮草已多碧，園花空復新。", "更嫌鶑自語，幽憤不勝陳。"]'),
('0b35168f-0685-4ea6-8c53-67fd974b7209','送張知錄','葉適','宋','宋诗','song-poetry','','[]','門閥飛龍後，家聲入館前。',48,'全唐诗/poet.song.169000.json','["門閥飛龍後，家聲入館前。", "身饒太常第，客欠廣文氈。", "流落無先譽，遭逢有宿緣。", "炎洲路多少，謾數去鴻邊。"]'),
('b6c9de9b-fb8f-41bd-a81c-559814fa1cc3','送鄭景望二首  其一','葉適','宋','宋诗','song-poetry','','[]','兩地旌旗一閏中，十年監牧九卿崇。',64,'全唐诗/poet.song.169000.json','["兩地旌旗一閏中，十年監牧九卿崇。", "安輿遍就東南養，遺俗將陶雅頌功。", "愛護元身如寶玉，節宣時序戒螟螽。", "遥知獨上千山路，處處梅花逐暖風。"]'),
('874ae435-c8fc-405a-919e-cc720b2bf2e7','送鄭景望二首  其二','葉適','宋','宋诗','song-poetry','','[]','江左諸賢盡凋落，邇來名字未深知。',64,'全唐诗/poet.song.169000.json','["江左諸賢盡凋落，邇來名字未深知。", "願公年德加前輩，救世勳庸莫後時。", "國重四維人建立，天還一統道藩籬。", "彌綸康濟何曾極，自古忠臣不遠期。"]'),
('23f48cae-05ae-4a46-b28b-b758fc37afcc','曾晦之挽詞','葉適','宋','宋诗','song-poetry','','[]','交游盛處失騑驂，筆硯窮時綰碧藍。',64,'全唐诗/poet.song.169000.json','["交游盛處失騑驂，筆硯窮時綰碧藍。", "驥老尚能舒駿逸，龜潜終不慕芳甘。", "壽過捌拾人人羨，恩在鄉閭事事談。", "埋沒平生無限意，夜深樵唱起溪南。"]'),
('51f1c90f-6021-4046-a5cc-5a90837217e8','次韻喻叔奇九日','葉適','宋','宋诗','song-poetry','','[]','遶湖秋色去茫茫，塔立峰端表自强。',64,'全唐诗/poet.song.169000.json','["遶湖秋色去茫茫，塔立峰端表自强。", "因上岧嶢覽吳越，逆從開闢數羲皇。", "暖風駐帽嚴公會，早閏勾花絆客觴。", "閑却陶潜玩幽獨，可憐車馬共誰忙。"]'),
('50f48828-0cea-4cba-9472-739e24efeff2','中洲處士折梅花并新語爲贈率易鄙句爲謝','葉適','宋','宋诗','song-poetry','','[]','中洲之中十樹梅，蟠枝著地照蒿萊。',64,'全唐诗/poet.song.169000.json','["中洲之中十樹梅，蟠枝著地照蒿萊。", "即非無主憑誰伴，自不衝寒要早開。", "午蝶只隨游子意，暮笳難寫遯夫哀。", "幽懷寂寂天應笑，插向歸帆雪滿桅。"]'),
('bd5ec3e1-0bee-4a7d-822e-8ebd06553bab','送劉德脩時在京口','葉適','宋','宋诗','song-poetry','','[]','日日秋風江倒回，江邊執手重悠哉。',64,'全唐诗/poet.song.169000.json','["日日秋風江倒回，江邊執手重悠哉。", "兩山只欲當中住，一舸還應却下來。", "說與蛟龍息豪怒，亦令鷗鷺少嫌猜。", "吳頭楚尾何時極，黏就前詩併展開。"]'),
('ad8197db-fe1d-4298-9123-01e69e1348c0','送范文叔知彭州','葉適','宋','宋诗','song-poetry','','[]','君今結束歸何勇，我獨棲遲去不能。',64,'全唐诗/poet.song.169000.json','["君今結束歸何勇，我獨棲遲去不能。", "江水入冬猶浩蕩，風帆逼歲合騫騰。", "相逢論事信徒爾，清坐矢心嗟未曾。", "想得彭州退公後，夜窗重整照書燈。"]'),
('1b0ff0d4-9a51-486c-851f-c4a0bf01bfc0','送潘德久','葉適','宋','宋诗','song-poetry','','[]','每携瘦竹身長隠，忽引文藤令頗嚴。',64,'全唐诗/poet.song.169000.json','["每携瘦竹身長隠，忽引文藤令頗嚴。", "聞道將軍如郤縠，不妨幕府有陶潜。", "江當闊處水新漲，春到極頭花倍添。", "未有羽書吟自好，全提白下入詩奩。"]'),
('d8fa02b0-fe7a-4b56-a4b6-bad663271099','樓參政挽詞','葉適','宋','宋诗','song-poetry','','[]','外補何多只近州，却於中禁賸淹留。',64,'全唐诗/poet.song.169000.json','["外補何多只近州，却於中禁賸淹留。", "晚參國論非無樂，苦說時難更有愁。", "天下知心古來少，人間此夢覺應休。", "自嗟不識鄞江路，清淚因公寄海流。"]'),
('0303d8bf-db50-494a-87e9-9d547bb36b1a','無相寺道中','葉適','宋','宋诗','song-poetry','','[]','傍水人家柳十餘，靠山亭子菊千株。',64,'全唐诗/poet.song.169000.json','["傍水人家柳十餘，靠山亭子菊千株。", "竹鷄露啄堪幽伴，蘆菔風乾待歲除。", "與僕抱樵趨絕澗，隨僧尋磬禮精廬。", "不知身外誰爲主，更覺求名計轉疎。"]'),
('7ba88e91-9cb6-4769-ba06-cee8911b2b56','趙路分挽詞','葉適','宋','宋诗','song-poetry','','[]','平生王孫忘太康，承家孝友更溫良。',64,'全唐诗/poet.song.169000.json','["平生王孫忘太康，承家孝友更溫良。", "鴻冥鵠舉須言命，桂死蘭摧不斷香。", "古有失時堪恨惜，從今虧處取酬償。", "佳城况遇朱公子，大旆高牙屬令郎。"]'),
('7e79cdda-ac7a-4da2-9bad-20ed00fc8499','陳益謙挽詞','葉適','宋','宋诗','song-poetry','','[]','舍南巷北水同流，稻菽參差各自謀。',64,'全唐诗/poet.song.169000.json','["舍南巷北水同流，稻菽參差各自謀。", "不料多材能轉物，更憐無地與伸頭。", "蛛絲委架詩書慍，鷺羽空陂菡萏愁。", "好在夜深明月滿，人間地下兩悠悠。"]'),
('43937e73-bc63-4202-ac2e-35a9131221d0','寄呂巽伯換酒亭','葉適','宋','宋诗','song-poetry','','[]','瑯琊初址未完牢，猶倚虛名用我曹。',64,'全唐诗/poet.song.169000.json','["瑯琊初址未完牢，猶倚虛名用我曹。", "自可全將醒前了，何因偏向醉中逃。", "艱危未肯當時共，誕逸空傳後代高。", "還有遠孫留墓側，繞亭寒葉夜騷騷。"]'),
('bfa5e4b5-423a-4196-8954-5f82d90ec517','併工','葉適','宋','宋诗','song-poetry','','[]','併工催作趁春前，又值春歸一莞然。',64,'全唐诗/poet.song.169000.json','["併工催作趁春前，又值春歸一莞然。", "新筍頓能長數尺，晚花寬與待明年。", "回廊寂寂爲苔地，後塔陰陰造雨天。", "坐睡不驚還自覺，鬢鬚將老到衰邊。"]'),
('a1a8745e-0a1c-4f0d-b28a-516574b1c7c1','菊花開送徐靈淵','葉適','宋','宋诗','song-poetry','','[]','白頭幾度逢重九，方是今年種菊花。',64,'全唐诗/poet.song.169000.json','["白頭幾度逢重九，方是今年種菊花。", "衰病自憐何處看，馨香聊向小園誇。", "討論摇落生光怪，暖熱風霜與麗華。", "正好行吟君已去，別移秋色付誰家。"]'),
('115ed167-805b-48a9-a1b2-794fbd78c87c','次韻韓仲止','葉適','宋','宋诗','song-poetry','','[]','塞戶低眠畏北風，詩來喚起自江東。',64,'全唐诗/poet.song.169000.json','["塞戶低眠畏北風，詩來喚起自江東。", "林迷久已隨牲鹿，磐止何曾有漸鴻。", "常日錐刀希楚富，千年鉛槧諱丘窮。", "莫將新意翻棋局，一等成虧付國工。"]'),
('5adac5e5-0b16-4ff9-b9d8-b23d3c09aa9b','齊國太夫人挽詞','葉適','宋','宋诗','song-poetry','','[]','風樹秋悲乞暫閑，壽星宵隕幾時還。',64,'全唐诗/poet.song.169000.json','["風樹秋悲乞暫閑，壽星宵隕幾時還。", "子同房杜經綸地，夫在荀陳伯仲間。", "恩重七封開表海，行高三美勒名山。", "猶言未足平生養，看即元台恨莫攀。"]'),
('672f3d48-fdad-4789-a979-ec71abb0f618','安撫待制侍郎徐公挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','玉質金章映海濱，養成天德異凡倫。',64,'全唐诗/poet.song.169000.json','["玉質金章映海濱，養成天德異凡倫。", "曾顔窈渺關前聖，管葛粗疎付後人。", "惆悵窮途三訖癸，吁嗟厄歲再逢寅。", "送公何物堪將去，留在埋銘石色新。"]'),
('acc49c92-9edc-46f3-a715-1c575a66258f','安撫待制侍郎徐公挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','飲冰那得不醒然，北看成南醜又妍。',64,'全唐诗/poet.song.169000.json','["飲冰那得不醒然，北看成南醜又妍。", "建策須爲萬世慮，孤忠亦有一身全。", "星文忍向生前墜，夢事方從死日傳。", "莫指鳴山歸路熟，青林黄葉度年年。"]'),
('338a3d10-dd13-44d5-a2f3-a1f01f98e024','許相公挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','容成堂上光華別，謝客巖前意象閑。',64,'全唐诗/poet.song.169000.json','["容成堂上光華別，謝客巖前意象閑。", "身到三台良未滿，年添九老定誰慳。", "高期落落塵囂外，苦論喧喧醉夢間。", "我欲爲公深著語，桂林芝樹不同刪。"]'),
('86edcc11-f510-45eb-985f-091f3abbf2f7','許相公挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','行露空多曉色催，夜香燒斷作飛埃。',64,'全唐诗/poet.song.169000.json','["行露空多曉色催，夜香燒斷作飛埃。", "松江鱠好憑誰憶，金谷花濃只自開。", "玉女雲中應盡去，仙人霧裏更重來。", "千年一判禁銷得，涕掩寒塘錯莫回。"]'),
('fe130d09-4110-42e4-a3e2-066c3bdf395b','送丁子齊主簿','葉適','宋','宋诗','song-poetry','','[]','明經六十未收科，自取南官計若何。',64,'全唐诗/poet.song.169000.json','["明經六十未收科，自取南官計若何。", "來歲須將一戰霸，浮家今厭百程過。", "預愁菊蕊行中破，還喜梅花到後多。", "從古功名致身早，誤隨陶令晚蹉跎。"]'),
('a485ce52-3c9d-4fcb-865c-9b55ecfb743d','丁少明挽詩','葉適','宋','宋诗','song-poetry','','[]','枕冷秋山不記年，時時逸想醉看天。',64,'全唐诗/poet.song.169000.json','["枕冷秋山不記年，時時逸想醉看天。", "吟成絕妙驚人句，散盡粗浮使鬼錢。", "萬卉有情風暖後，一筇無伴月明邊。", "新來王子碑能說，筆意堪將此共傳。"]'),
('1b3d5945-c7ea-43d5-9b8e-49b66383b7eb','宋仲方遊吳袖文索詩爲別','葉適','宋','宋诗','song-poetry','','[]','九曲絃歌滿巷傳，儒林聲價有誰先。',64,'全唐诗/poet.song.169000.json','["九曲絃歌滿巷傳，儒林聲價有誰先。", "昔憐少學隨翁久，今喜新文信汝賢。", "刪後畫前元未聖，南花北葉定誰妍。", "終期猛進一篙力，透過龍門急水船。"]'),
('df41afd0-f42a-4d61-aa3a-47ec04a430d6','毛崈夫挽詞','葉適','宋','宋诗','song-poetry','','[]','我昔髫年侍此翁，自甘窮僻古人同。',64,'全唐诗/poet.song.169000.json','["我昔髫年侍此翁，自甘窮僻古人同。", "道修白業曾先悟，官近青雲却未通。", "庭長嫩蝌新戲雨，徑存衰柳舊摇風。", "世間榮落私情盡，留得清名是至公。"]'),
('e53cb1c8-ba6e-4cdf-8194-5798e5067ea5','直院中書莫公殂往哀痛不能成文輒留小詩靈几并致鱸魚金柑爲奠','葉適','宋','宋诗','song-poetry','','[]','閣老今無地上身，黄麻紫誥兩沉淪。',64,'全唐诗/poet.song.169000.json','["閣老今無地上身，黄麻紫誥兩沉淪。", "虛懸東嶺來時月，難挽西山去後春。", "試割冰鱸猶脆薄，重餐野橘尚甘辛。", "最憐趙子同心事，相看題封淚染茵。"]'),
('33c994c3-d3f3-441d-bef5-c68ecd0b0874','薛君季常挽詞','葉適','宋','宋诗','song-poetry','','[]','汨羅謾隕離騷經，伊洛源流今更清。',64,'全唐诗/poet.song.169000.json','["汨羅謾隕離騷經，伊洛源流今更清。", "自別三年無信息，忽驚一日有銘旌。", "乾坤未放虛空壞，蠻觸猶須事業成。", "桂樹團圓半丘土，春風還許爲君榮。"]'),
('49e2fb63-c3ad-4a75-a772-8946749896ba','題彭澤縣尉廳林壑之勝','葉適','宋','宋诗','song-poetry','','[]','彭澤西山天祕惜，淵明未敢發幽緘。',64,'全唐诗/poet.song.169000.json','["彭澤西山天祕惜，淵明未敢發幽緘。", "始從石尉兼王尉，洗出前巖到後巖。", "也只暫時供步履，可能終老卸朝衫。", "應須却誦歸來句，重把家園草自芟。"]'),
('b1fcd06e-4e1e-4642-b52c-33263c3f8aad','送趙提幹','葉適','宋','宋诗','song-poetry','','[]','與君中外情偏厚，嗟我龍鍾志已摧。',64,'全唐诗/poet.song.169000.json','["與君中外情偏厚，嗟我龍鍾志已摧。", "豈有尋常墮泥滓，不教宛轉助風雷。", "花枝買笑前村趁，柳带牽情別浦催。", "細雨酒亭東望處，應將新語寄潮回。"]'),
('3b913cce-1974-4222-b1c2-56a2eb4d0e70','賀縣尉','葉適','宋','宋诗','song-poetry','','[]','端龐還有北人風，大雅元非楚士同。',64,'全唐诗/poet.song.169000.json','["端龐還有北人風，大雅元非楚士同。", "此日深探應徹底，他時直上定摩空。", "離家杳杳百灘外，過我昏昏三伏中。", "籬破屋荒無路入，荷花招手席門東。"]'),
('cef297e4-9bbb-4a85-98cc-625f10920ee7','送曹潜夫','葉適','宋','宋诗','song-poetry','','[]','東南作闕歎年徂，遠遠參司到蜀都。',64,'全唐诗/poet.song.169000.json','["東南作闕歎年徂，遠遠參司到蜀都。", "元帥幕中須受辟，生羌界上也分符。", "閑吟杜甫詩千字，時載楊雄酒一壺。", "只我衰殘望君切，杜鵑聲裏認歸塗。"]'),
('d729c4c4-b0c8-4882-b5e3-a5e802c60d99','謝李參政因送曹瀘州寄簡','葉適','宋','宋诗','song-poetry','','[]','大厦元須獨木枝，李公補處屬良時。',64,'全唐诗/poet.song.169000.json','["大厦元須獨木枝，李公補處屬良時。", "千年立國唐虞上，一念勤民禹稷思。", "恨昔寡聞空自誤，况今消盡有誰知。", "雙鳬雙鴈蕭蕭影，孤嶼亭邊正著黐。"]'),
('abb765bc-6f7f-40bf-918c-088c48c163bf','贈李秀才肖舒','葉適','宋','宋诗','song-poetry','','[]','帆來帆去海中山，自笑臞仙歲月閑。',64,'全唐诗/poet.song.169000.json','["帆來帆去海中山，自笑臞仙歲月閑。", "忽值巡遊防豕突，也叨扈從識龍顔。", "寺傳弓劍烟嵐外，門掩詩書浪泊間。", "待得諸孫上金榜，九重高拱報堯班。"]'),
('66232231-8564-4273-b3c8-5e20f3fc1c9e','郭伯山挽詞','葉適','宋','宋诗','song-poetry','','[]','兄弟窮經各一時，百年義塾尚留炊。',64,'全唐诗/poet.song.169000.json','["兄弟窮經各一時，百年義塾尚留炊。", "講燈常照鶴窺坐，壇杏半紅猿揀枝。", "未奏邊功明主惜，將成京秩故人悲。", "挽君已老應先盡，安得埋銘更後垂。"]'),
('6928daa2-fe63-4dd2-b865-efe9fd2bb1f5','題王叔範自耕園','葉適','宋','宋诗','song-poetry','','[]','自耕不要從人得，知在盧南第幾街。',64,'全唐诗/poet.song.169000.json','["自耕不要從人得，知在盧南第幾街。", "吳地于今說佳麗，浙人自昔巧安排。", "包容花竹春留巷，謝遣蒲荷雪滿涯。", "必想新園名字出，故時臺館半沉埋。"]'),
('fcda8c95-6f2d-44ab-9105-4cf4a4cfe75b','福國太夫人陳氏挽詩','葉適','宋','宋诗','song-poetry','','[]','曾經天語贊華簪，應是忠多報獨深。',64,'全唐诗/poet.song.169000.json','["曾經天語贊華簪，應是忠多報獨深。", "寂寂孤鸞羞鑑影，輝輝雙鳳失梧陰。", "沖心自與家規競，空性都無世網侵。", "聞說埋銘親付祝，照碑斜日下寒林。"]'),
('3ba110c2-ed25-46e1-ad6f-6f73b65ff49b','送郭黄中','葉適','宋','宋诗','song-poetry','','[]','鴈山削玉上青雲，仙侶常游遣俗紛。',64,'全唐诗/poet.song.169000.json','["鴈山削玉上青雲，仙侶常游遣俗紛。", "飛舄可無能少駐，洞簫何幸復親聞。", "看承下戶恩尤重，賓禮高賢意自欣。", "忽憶門西貧士宅，蟄雷繞甑黍初饙。"]'),
('62daab58-2593-463a-b34a-c40277f10b5a','劉孺人挽詩','葉適','宋','宋诗','song-poetry','','[]','嗃嗃當年女手縫，一家從此更雍雍。',64,'全唐诗/poet.song.169000.json','["嗃嗃當年女手縫，一家從此更雍雍。", "性安於善行無迹，兒自爲銘筆有蹤。", "聞說湖清見龍首，還疑墓長羃雲峰。", "哀情變化何終極，留澤凌霄絳遶松。"]'),
('1963a433-556b-4dc7-8b0a-732c53ff0942','張提舉挽詞','葉適','宋','宋诗','song-poetry','','[]','令祖親扶日馭升，孫今喜復似翁清。',64,'全唐诗/poet.song.169000.json','["令祖親扶日馭升，孫今喜復似翁清。", "恩波再入淮流滿，信節初傳嶺外名。", "夏木千重添野趣，秋風三疊寄幽情。", "長年慣唱漁家曲，難聽茲晨薤露聲。"]'),
('dc30f953-f293-43dd-a329-8c171b88eee5','薛端明挽詩二首  其一','葉適','宋','宋诗','song-poetry','','[]','可但補闕名官日，不逢引裾强諫時。',64,'全唐诗/poet.song.169000.json','["可但補闕名官日，不逢引裾强諫時。", "上朝有疏天常納，下殿無行誰獨疑。", "論道何如出綸晚，督軍頗嘆封侯遲。", "凌烟畫手今寂寞，豆蔻林高荔子垂。"]'),
('2d45f2a0-1fb9-4680-91e6-288696e041bb','薛端明挽詩二首  其二','葉適','宋','宋诗','song-poetry','','[]','冰稼初融闕月沉，英豪四坐地爐深。',64,'全唐诗/poet.song.169000.json','["冰稼初融闕月沉，英豪四坐地爐深。", "爭看麈尾頻揮處，難了朱絃未盡音。", "怪我輕談當世事，知公默會古人心。", "空山穩對梅花宿，錯向林逋墓裏尋。"]'),
('677f0c24-c96a-4783-8448-6c3176651ee0','送林子高','葉適','宋','宋诗','song-poetry','','[]','老我追隨亦賸人，研軒標格久成塵。',64,'全唐诗/poet.song.169000.json','["老我追隨亦賸人，研軒標格久成塵。", "意先遠水常趨海，節與修篁自作筠。", "諫苑舊知欣有信，漆坊新隠嘆無鄰。", "梅花應待行時發，野岸山房探得春。"]'),
('6b559d64-d09c-4edc-8a80-06162c0ec599','塔頭林君挽詩','葉適','宋','宋诗','song-poetry','','[]','之河繞浦各紆縈，結束樓臺穩更清。',64,'全唐诗/poet.song.169000.json','["之河繞浦各紆縈，結束樓臺穩更清。", "全與好人修實地，任教流俗趁虛名。", "兒應自了書林債，淚苦還滋墓柏榮。", "今歲田荒望周急，鄉村憶著倍關情。"]'),
('5dfdf63f-f778-4981-92ba-bd761403fb1a','題劉潜夫詩什併以將行','葉適','宋','宋诗','song-poetry','','["\u8861\u5c71"]','寄來南嶽第三藁，穿盡遺珠簇盡花。',64,'全唐诗/poet.song.169000.json','["寄來南嶽第三藁，穿盡遺珠簇盡花。", "幾度驚教祝融泣，一齊傳與尉佗誇。", "龍鳴自滿空中韻，鳳咮都無巧後哇。", "庾信不留何遜往，評君應得當行家。"]'),
('3d7c4109-1bed-49b3-811f-184ba2931d85','送宋知錄','葉適','宋','宋诗','song-poetry','','[]','與子比鄰計未疎，河梁新駕月明初。',64,'全唐诗/poet.song.169000.json','["與子比鄰計未疎，河梁新駕月明初。", "老人輕作三年別，强記難忘一覽餘。", "節相喜材添局務，寺丞引類借朝裾。", "只愁戀著衙樓好，回厭家山道不如。"]'),
('4a956316-67f2-404e-a46e-fc6b13b89b2a','和王宗卿白兔詩','葉適','宋','宋诗','song-poetry','','[]','鴉带初陽照廣津，兔隨斜月滿虧輪。',64,'全唐诗/poet.song.169000.json','["鴉带初陽照廣津，兔隨斜月滿虧輪。", "瑞登韓筆名尤重，喜動歐吟事轉神。", "不道奇毛妬霜雪，應知雅意合松椿。", "龜年鶴歲猶嫌少，獻與尊堂別紀春。"]'),
('b2f49532-5166-4d23-a481-941d9a1793f1','李處士挽詩','葉適','宋','宋诗','song-poetry','','[]','憶吟詩句與君兒，曾說高宗涕自揮。',64,'全唐诗/poet.song.169000.json','["憶吟詩句與君兒，曾說高宗涕自揮。", "兩地兵休重富樂，百年家活共輕肥。", "多留螢火明書案，閑看魚蓑傍釣磯。", "身內已無塵土僻，霜阡雪塢送將歸。"]'),
('b3d0ce7d-7069-403a-b0e8-a9a0c55a1259','衢州雜興二首  其一','葉適','宋','宋诗','song-poetry','','[]','玉研朱弓不可尋，暖風催綠麥成陰。',64,'全唐诗/poet.song.169000.json','["玉研朱弓不可尋，暖風催綠麥成陰。", "越山行盡見平野，江上水流無逝音。", "地跨京師都邑壯，俗兼吳楚智謀深。", "詔書寬大邦人誦，知有賢侯緩轡臨。"]'),
('38c590fb-7c99-4dd4-b0fb-f34f240b12d7','衢州雜興二首  其二','葉適','宋','宋诗','song-poetry','','[]','樊梅野雪掃成泥，桃李紛紛照舊蹊。',64,'全唐诗/poet.song.169000.json','["樊梅野雪掃成泥，桃李紛紛照舊蹊。", "行子束書輕駟馬，主人炊蓐候鳴鷄。", "百年囹圄荒蓬藋，萬里耕桑接町畦。", "堪笑腐儒何用此，只今飄轉楚江西。"]'),
('0d8f5ce3-d63d-478c-bd27-ecd1326c1dfd','送劉晉卿','葉適','宋','宋诗','song-poetry','','[]','草黄木脫何所適，使我感歎生百疾。',64,'全唐诗/poet.song.169000.json','["草黄木脫何所適，使我感歎生百疾。", "天驥屢爲駑駘笑，良玉空遭碔砆黜。", "少年壯志思絕塵，只今作計常後人。", "明堂巨棟吾何有，護竹養花甘隠淪。"]'),
