('5f1f9714-b2d1-410b-afab-548891caa194','因在秀州寄王道夫詩三首  其一','葉適','宋','宋诗','song-poetry','','[]','衮衮紅塵五月留，來時落木不勝秋。',32,'全唐诗/poet.song.169000.json','["衮衮紅塵五月留，來時落木不勝秋。", "只今春事濃如許，萬里滄浪又一舟。"]'),
('c487a173-6409-4a45-9c31-9af4fd3b97cc','因在秀州寄王道夫詩三首  其二','葉適','宋','宋诗','song-poetry','','[]','魚龍遠避水光浮，草木怒長山意豪。',32,'全唐诗/poet.song.169000.json','["魚龍遠避水光浮，草木怒長山意豪。", "獨立和風清宿酒，晚雲收盡月痕高。"]'),
('f116df1a-5f10-4b32-9c51-6bd23db61a52','因在秀州寄王道夫詩三首  其三','葉適','宋','宋诗','song-poetry','','[]','潘君狂甚詩能古，葉子文高世莫驚。',32,'全唐诗/poet.song.169000.json','["潘君狂甚詩能古，葉子文高世莫驚。", "何處有田求二頃，向來三月决歸耕。"]'),
('664dec7a-3c2f-48d5-8bdc-e4d734a33c00','送趙紫芝游天台','葉適','宋','宋诗','song-poetry','','[]','寒退糊碑閣，春留種藥城。',48,'全唐诗/poet.song.169000.json','["寒退糊碑閣，春留種藥城。", "幽居自可樂，暫出豈無名。", "綜水援藍聚，裙山翦繡迎。", "文殊扣野衲，癡語爲誰清。"]'),
('94a3b30d-ddb2-4bf1-b6d7-03b97398a0dd','石洞書院','葉適','宋','宋诗','song-poetry','','[]','好泉好石入君廬，霧鎖雲封未敢居。',64,'全唐诗/poet.song.169000.json','["好泉好石入君廬，霧鎖雲封未敢居。", "若挹風光當豪饌，豈同經史作寒菹。", "庭中蓍老易無過，畹內蘭滋詩有餘。", "只此盡知賢聖樂，世閒青紫亦空虛。"]'),
('e443ef34-e742-49f9-a828-7d9b0abe017a','前日入寺觀牡丹不覺已謝惜其穠豔故以詩悼之敢冀見和','葉適','宋','宋诗','song-poetry','','[]','牡丹乘春芳，風雨苦相妒。',48,'全唐诗/poet.song.169000.json','["牡丹乘春芳，風雨苦相妒。", "朝來小庭中，零落已無數。", "魂銷梓澤園，腸斷馬嵬路。", "盡日向欄干，踟躕不能去。"]'),
('96fb59b5-39f0-4c7d-97e2-abcc575b5bdb','仙壇','葉適','宋','宋诗','song-poetry','','[]','堂堂人物地行仙，勾漏丹砂信有緣。',32,'全唐诗/poet.song.169000.json','["堂堂人物地行仙，勾漏丹砂信有緣。", "彈壓松篁知暫爾，未應謝屐久林泉。"]'),
('762d3eab-4a2a-4ac6-b128-0db131fb5ab9','句  其一','葉適','宋','宋诗','song-poetry','','[]','花傳春色枝枝到，雨遞秋聲點點分。',16,'全唐诗/poet.song.169000.json','["花傳春色枝枝到，雨遞秋聲點點分。"]'),
('d87a0ea3-71db-42d9-8398-0115f89d135b','句  其二','葉適','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','不待歸來霜後熟，蒸來便作洞庭香。',16,'全唐诗/poet.song.169000.json','["不待歸來霜後熟，蒸來便作洞庭香。"]'),
('6ff27172-0ea1-4ea9-8216-2e97da22709c','句  其三','葉適','宋','宋诗','song-poetry','','[]','初分大道非常道，纔有先天未後天。',16,'全唐诗/poet.song.169000.json','["初分大道非常道，纔有先天未後天。"]'),
('6f0ba5fc-12b5-47b7-826f-613983bcab8f','句  其四','葉適','宋','宋诗','song-poetry','','[]','獨立孔門無一事，惟傳顔氏得心齋。',16,'全唐诗/poet.song.169000.json','["獨立孔門無一事，惟傳顔氏得心齋。"]'),
('370d38b2-559c-42a6-b207-09f7f13dda96','題絜齋書院','姚穎','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鵝湖鹿洞兩優游，吾道南來誰與儔。',64,'全唐诗/poet.song.169000.json','["鵝湖鹿洞兩優游，吾道南來誰與儔。", "鄮地傳心化已洽，堇山遺教澤長留。", "空階向日春風度，棟宇凌雲化雨周。", "聲譽已垂百世後，長江虹水不空流。"]'),
('0b323574-f120-486f-83dd-ca9bf963f5d8','句','姚穎','宋','宋诗','song-poetry','','[]','六典未新周禮樂，三河正想漢官儀。',32,'全唐诗/poet.song.169000.json','["六典未新周禮樂，三河正想漢官儀。", "平生作計非溫飽，可但區區詫郄枝。"]'),
('99bc6b1c-4811-4439-9385-cddba27d8561','喜雨望巴羅二山','羅點','宋','宋诗','song-poetry','','[]','叔元不冠椎兩髽，縈青綰綠如堆鴉。',224,'全唐诗/poet.song.169000.json','["叔元不冠椎兩髽，縈青綰綠如堆鴉。", "䰐鬖遠望毛髮古，日日惟聞餐暮霞。", "吾家公遠更清絕，带眼不穿衣不結。", "好風吹袂任飄颻，夜夜惟聞弄明月。", "餐霞弄月固不惡，不道農田布龜灼。", "令君盛服道民苦，偃然袒裼猶不怍。", "敬持此意款浮丘，浮丘乃與令同憂。", "急呼風馬駕雲車，二仙方覺裸裎羞。", "旋加冠巾更束带，一見浮丘望塵拜。", "便將凶歲變豐年，談笑之間作霶霈。", "油雲雖出南北峰，開端實自浮丘翁。", "浮丘詩家老仙伯，故知憂國願年豐。", "邦人一飽誰所賜，父應詔子兄詔弟。", "若還此雨後五日，將見索汝枯魚肆。"]'),
('b9021d55-bb8d-4e2f-be25-7bc4b263d8e0','龍巖寺','羅點','宋','宋诗','song-poetry','','[]','直上龍巖第一層，參回斗轉夜縱橫。',32,'全唐诗/poet.song.169000.json','["直上龍巖第一層，參回斗轉夜縱橫。", "試將拄杖敲巖石，喚覺蟠龍速起行。"]'),
('54bda7f3-a7d0-4c79-bf5f-0c9f83f1e640','褒禪山有于湖所題寶塔二字','羅點','宋','宋诗','song-poetry','','[]','古剎浮屠映碧山，狀元題墨最爲嫺。',32,'全唐诗/poet.song.169000.json','["古剎浮屠映碧山，狀元題墨最爲嫺。", "遊人倦憇塵心寂，雲自青天水自閑。"]'),
('d2762a27-c5ef-4375-8937-807884531fb0','過洞庭','來廷紹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','日落君山暮，秋風過洞庭。',48,'全唐诗/poet.song.169000.json','["日落君山暮，秋風過洞庭。", "一官身外物，千里客中情。", "北望鄉關遠，南來旅雁鳴。", "孤帆無限恨，斜指岳陽城。"]'),
('37ff124e-1bab-4566-b16f-4caca7abbb50','洞庭夜泊','來廷紹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兩岸樹蒼蒼，孤舟湘水旁。',24,'全唐诗/poet.song.169000.json','["兩岸樹蒼蒼，孤舟湘水旁。", "猿聲啼不住，明月照篷窗。"]'),
('26be0c16-5ce6-4661-8be9-70efd44a0308','正命詩','來廷紹','宋','宋诗','song-poetry','','[]','病卧僧房兩月多，英雄壯志漸消磨。',64,'全唐诗/poet.song.169000.json','["病卧僧房兩月多，英雄壯志漸消磨。", "昨宵飲藥疑嘗膽，今日披衣似挽戈。", "分付家人扶旅櫬，莫教釋子念彌陀。", "此心不死誰如我，臨了連聲三渡河。"]'),
('0dfe701c-e9b6-4931-9089-d2aa05908468','澤卿蘭亭考用工深矣携攻媿大參詩見訪次韵併呈放翁待制','黄由','宋','宋诗','song-poetry','','[]','字入昭陵不可摹，後來僅及晉之餘。',32,'全唐诗/poet.song.169000.json','["字入昭陵不可摹，後來僅及晉之餘。", "識真盍向龜堂問，敢謂牽聯亦得書。"]'),
('1cab9989-9684-4790-8061-295b81cbdbf9','盤墅 共樂堂','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，滿堂佳客滿園花。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，滿堂佳客滿園花。", "看花揖客須清賞，休向人間俗子誇。"]'),
('2e6a453f-bc97-45f9-89d7-30f9d7b318bb','盤墅 聯德堂','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，便須洗盞泛流霞。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，便須洗盞泛流霞。", "軟紅塵裏風波惡，不似江艫與海槎。"]'),
('6c5854e4-5e5f-4efb-b066-4bd8a0f841b4','盤墅 茅堂觀弈','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，茅堂萬竹綠交加。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，茅堂萬竹綠交加。", "午窗睡起無他想，坐看圍棋到日斜。"]'),
('f28d799c-cef4-44da-b53e-7e13933e5e2b','盤墅 登明月臺 其一','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，擎空皎月瑩無瑕。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，擎空皎月瑩無瑕。", "自須臺上分明看，擬欲呼仙泛海槎。"]'),
('735e4cff-4a67-424e-8d88-2d7e4f60bfec','盤墅 登明月臺 其二','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，樓高不管綠楊遮。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，樓高不管綠楊遮。", "有書萬卷時翻弄，千古興亡幾歎嗟。"]'),
('08c19a47-9954-4159-acc7-8db9897a850d','盤墅 道院獨步','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，參天檜柏古槎牙。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，參天檜柏古槎牙。", "杖藜終日頻來往，不羨堤邊路築沙。"]'),
('709ff9a5-ec40-44ce-b40c-6663df9f16a9','盤墅 登三清閣','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，三清閣下寂無譁。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，三清閣下寂無譁。", "小臣愧乏絲毫報，深炷爐香靜點茶。"]'),
('976b039a-16bb-4ca8-9b23-194ed708acb7','盤墅 入園','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，故園喜聽雀喳喳。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，故園喜聽雀喳喳。", "上人只爲貪風月，蠻觸交爭笑爾蝸。"]'),
('c2d63a4b-2da9-4507-a99c-8594d184abb8','盤墅 睦鄰','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，民間何處不桑麻。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，民間何處不桑麻。", "欣欣老稚迎門笑，斗酒相歡亦孔嘉。"]'),
('699aa34e-4304-48b5-a0b9-72827434afcc','盤墅 無題','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，休論恬淡與榮華。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，休論恬淡與榮華。", "古來顔跖俱塵土，自有時賢定等差。"]'),
('4c861133-7db6-420c-93e1-2e08aef5a1ed','盤墅 思親','黄由','宋','宋诗','song-poetry','','[]','纔到松陵即是家，仙翁詩句發天葩。',32,'全唐诗/poet.song.169000.json','["纔到松陵即是家，仙翁詩句發天葩。", "鈍才不及賡餘韵，留取時時罩碧紗。"]'),
('853ce178-8b24-4978-819d-661aaba36cfe','還吳江','黄由','宋','宋诗','song-poetry','','[]','歸來三閲月，無事一關心。',48,'全唐诗/poet.song.169000.json','["歸來三閲月，無事一關心。", "刈草尋花徑，開池漾柳陰。", "江邊問明月，天際數歸禽。", "幸有高賓至，相逢似竹林。"]'),
('3fc7f41f-d9e2-4c71-929d-844d3c5f4151','題桃源','黄{田}','宋','宋诗','song-poetry','','[]','本自深村老圃來，偶分符竹到天台。',32,'全唐诗/poet.song.169000.json','["本自深村老圃來，偶分符竹到天台。", "漫山幸可容桃李，莫待劉郎去後栽。"]'),
('02ce65d8-cab9-4651-9949-0879536ced54','遊石橋  其一','黄{田}','宋','宋诗','song-poetry','','[]','橫石圓峰豈偶然，上懸雙瀑下澄淵。',32,'全唐诗/poet.song.169000.json','["橫石圓峰豈偶然，上懸雙瀑下澄淵。", "我來不爲橋難過，待了區中未盡緣。"]'),
('4997efff-e13c-44fa-99a8-3f32161d81f4','遊石橋  其二','黄{田}','宋','宋诗','song-poetry','','[]','人道靈瓜有護持，蜿蜒果見著青枝。',32,'全唐诗/poet.song.169000.json','["人道靈瓜有護持，蜿蜒果見著青枝。", "一時耳目窮何盡，萬事由來不可知。"]'),
('83671209-bec8-4709-81b7-28fac3507c82','無絃琴','饒延年','宋','宋诗','song-poetry','','[]','月作金徽風作絃，清音不在指端傳。',32,'全唐诗/poet.song.169000.json','["月作金徽風作絃，清音不在指端傳。", "有時彈罷無生曲，露滴松梢鶴未眠。"]'),
('11e51a18-ec16-466d-a73d-d5ba4d6ac74f','題光華亭','葉簵','宋','宋诗','song-poetry','','[]','畫棟朱簾勢翼然，鼎新氣象冠山川。',64,'全唐诗/poet.song.169000.json','["畫棟朱簾勢翼然，鼎新氣象冠山川。", "鵝黄楊柳浮春晚，鴨綠烟波送客船。", "輪奐不妨農事日，風光好近麥秋天。", "佐君治簡有餘暇，杯酒從教盡日傳。"]'),
('04315d4a-107a-405e-96f7-eac6a91889d8','初至郡講禊飲於江上夜歸賦此','馮伯規','宋','宋诗','song-poetry','','[]','身墜千峰不自知，尚修故事水之麋。',64,'全唐诗/poet.song.169000.json','["身墜千峰不自知，尚修故事水之麋。", "真居峻嶺崇山下，又過綠陰青子時。", "幻出流觴共頃刻，款留歸棹展娛嬉。", "史君澹泊隨民樂，先賦豐年一首詩。"]'),
('c39bb665-ddab-4752-af7a-6e2fa099bc97','繼而稍旱禱而復雨喜而作詩','馮伯規','宋','宋诗','song-poetry','','[]','連夕滂沱類建瓴，送將凉意滿郊坰。',64,'全唐诗/poet.song.169000.json','["連夕滂沱類建瓴，送將凉意滿郊坰。", "江邊草木太半綠，天外一峰無限青。", "却信神龍元解事，豈容旱魃更爭靈。", "從今懷抱如冰釋，閉閣燒香伴六經。"]'),
('b56bae30-bdd6-4f9b-ad44-3d24dc6de32c','次韻謝史提幹見知','馮伯規','宋','宋诗','song-poetry','','[]','呼得蜿蜒入小瓴，便能飛雨挾林坰。',64,'全唐诗/poet.song.169000.json','["呼得蜿蜒入小瓴，便能飛雨挾林坰。", "油雲頓失千山赤，丹篆嘗騰一紙青。", "漢節可眠知免曠，仙祠屢扣信通靈。", "欲同此樂君西去，歷想三峨舊所經。"]'),
('dc60a5ca-6f66-4872-9db9-8e11dd5094e1','次韻酬李通江','馮伯規','宋','宋诗','song-poetry','','[]','長官禱雨信精誠，便覺豐年徧遠坰。',64,'全唐诗/poet.song.169000.json','["長官禱雨信精誠，便覺豐年徧遠坰。", "繅繭齊頭絲卷白，插秧隨手稻翻青。", "行篘秫酒酣天祿，益長香芽發地靈。", "守令愛民須表裏，君其爲緯我爲經。"]'),
('b10ecbf4-63de-40ed-8fe7-a0f1275f0d14','次韻中秉教授喜雨之作','馮伯規','宋','宋诗','song-poetry','','[]','入春絕無一聲雷，赤日又將近夏末。',224,'全唐诗/poet.song.169000.json','["入春絕無一聲雷，赤日又將近夏末。", "陰霾蔽天動經月，草木葉上積寸埃。", "朝朝群望俱徧走，一毫及民更無有。", "雨師遠逃龍亦睡，江澀魚跳鼉空吼。", "初雖一雨慰望霓，明晨驕陽射到西。", "田如石堅耕不得，欄卧牛犢壁倚犁。", "訴天搏手嗟亡策，上山默扣真人宅。", "忽然斗暗雲墨黑，盡化焚焦作膏澤。", "稽首謝天拜低頭，郡寄且許臣分憂。", "擊甌樓上望四野，只願保此三年秋。", "吾儕風萍偶接際，剩醖新秫儲年計。", "稻苗便秧粟已芽，穩藉清尊度今歲。", "五更復聞簷溜聲，欹枕不眠隔窗聽。", "公餘一榻安禪處，姑借民謠當詩句。"]'),
('f0535bfb-78fa-424e-99d4-91d0a14f8fc0','季春下澣遊南龕','馮伯規','宋','宋诗','song-poetry','','[]','四山如蝟毛，中有線路縈。',168,'全唐诗/poet.song.169000.json','["四山如蝟毛，中有線路縈。", "誰人導我來，得此掌許平。", "雨後天宇空，夏氣和且清。", "休日一無事，駕言南山行。", "南山有何好，翠壁列崢嶸。", "巨木老已仆，頼有紅石撐。", "自從嚴大夫，廢興今幾更。", "穉幹亦合抱，知幾閲晦明。", "幽壑架危亭，無風涼自生。", "少間上絕頂，四望圍長城。", "漲江籠篆紋，小市分棋枰。", "俛仰忘身世，獨慨呼酒傾。", "何知玉堂客，分雜巴叟耕。", "下山喜同步，元自脚力輕。"]'),
('7ac7c7fc-d54d-47a0-a11d-ff5e56dd1c1a','觀漲','馮伯規','宋','宋诗','song-poetry','','[]','孤城如深村，過客絕輪鞅。',72,'全唐诗/poet.song.169000.json','["孤城如深村，過客絕輪鞅。", "江流卷初霽，晚風納微爽。", "我來適幽懷，新漲逸遠響。", "汀沒鷗鷺翔，牧罷牛羊上。", "郡古安陋樸，事簡謝鞅掌。", "小酌便陶然，倚欄送輕槳。"]'),
('1b833a05-2e0a-4421-b0fb-0ea66b7a3110','次韻泛舟仲秉有詩','馮伯規','宋','宋诗','song-poetry','','[]','且喜山城未傍邊，漫從錦水學遊舡。',64,'全唐诗/poet.song.169000.json','["且喜山城未傍邊，漫從錦水學遊舡。", "何時官裏真無事，是處壺中別有天。", "豈復江湖增遠興，强憑絲竹寫中年。", "接䍦雖醉無勞著，恰要臨流揖望僊。"]'),
('87e64e2a-221b-4442-9c9d-3323cc72d5be','次日遊西龕再用韻','馮伯規','宋','宋诗','song-poetry','','[]','倚闌一覽興無邊，好舉尊前藥玉舡。',64,'全唐诗/poet.song.169000.json','["倚闌一覽興無邊，好舉尊前藥玉舡。", "一水雲昏失羅带，萬松風偃舞鈞天。", "早評月旦參群彥，老上霜鬢近十年。", "解后登臨都樂事，酣餘爭恐史君僊。"]'),
('dce40fcd-6bab-4da1-93f3-c0766f818fbb','端午前三日觀坡詩首夏官舍即事因次其韻','馮伯規','宋','宋诗','song-poetry','','[]','簾陰不捲漏烏遲，數朶庭萱也自菲。',64,'全唐诗/poet.song.169000.json','["簾陰不捲漏烏遲，數朶庭萱也自菲。", "公退萬緣俱謝絕，心空一氣自知歸。", "但期菽粟令民足，未覺詩書與願違。", "聞旱問龍求一雨，乘凉約客扣巖扉。"]'),
('e13f0137-f11c-42fc-a373-3bb42d3cd724','登雲間閣','馮伯規','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔年嚴大夫，偶來怨遷謫。',132,'全唐诗/poet.song.169000.json','["昔年嚴大夫，偶來怨遷謫。", "我本麋鹿姿，得此已自適。", "乘閑陟上方，徧尋唐人石。", "豈期當三伏，一天雲四幕。", "快哉風時來，萬籟相呼吸。", "雨餘禾麻潤，是山皆喜色。", "一杯傾晚飲，綠瓜間朱實。", "是非不到耳，休厭山城寂。", "樹影抹橫烟，角聲暗落日。", "長江去不返，况此百年客。", "企首老玉僊，白髮何由摘。"]'),
('a2922a4d-3f95-4ab8-a05a-4b22f767442d','浄凉夜坐','馮伯規','宋','宋诗','song-poetry','','[]','水光灧灧竹陰□，何□□香露泛襟。',32,'全唐诗/poet.song.169000.json','["水光灧灧竹陰□，何□□香露泛襟。", "更欲□闌看身轉，一鈎弦月過□心。"]'),
('075ae7e8-cc6e-48cb-afa6-8bbdb5c72173','偶得新粳□送仲秉','馮伯規','宋','宋诗','song-poetry','','[]','東來五月見新秔，舂出□圓顆粒明。',32,'全唐诗/poet.song.169000.json','["東來五月見新秔，舂出□圓顆粒明。", "端羨□堂有母遺，數匙晚炊助嘗羹。"]'),
('95c8a8f5-d051-4670-bdd3-e74e691c1007','雨後觀漲','馮伯規','宋','宋诗','song-poetry','','[]','聞得江頭洶湧聲，不知何處雨盆傾。',64,'全唐诗/poet.song.169000.json','["聞得江頭洶湧聲，不知何處雨盆傾。", "兩涯牛馬那容辨，一夕蛟龍怒不平。", "浪盡橫汀孤樹在，微開頑翳夕陽明。", "儘饒河伯乘秋旺，潦涸霜寒水自清。"]'),
('fb7a359e-43d3-4db9-8447-dc2839aa814c','禱晴獲應喜而賦詩','馮伯規','宋','宋诗','song-poetry','','[]','才通香火上高穹，雨脚隨收不見蹤。',64,'全唐诗/poet.song.169000.json','["才通香火上高穹，雨脚隨收不見蹤。", "豈但五民保狼戾，也緣造物相龍鍾。", "連山柿栗難勝摘，入市禾麻乍出舂。", "一飽可期秋釀熟，青山綠水即過從。"]'),
('d42bcba3-e6c0-4fc1-a77f-860ffd14afce','先期登高觀菊巖新榜','馮伯規','宋','宋诗','song-poetry','','[]','先得重陽五日來，清江晚日與人諧。',64,'全唐诗/poet.song.169000.json','["先得重陽五日來，清江晚日與人諧。", "共搜磊磊落落句，要敵奇奇怪怪崖。", "烏帽幾容羅此影，黄花每喜近吾儕。", "山城酒熟渾無客，一笑臨風寄老懷。"]'),
('4e52a846-c0f0-44fd-9e7e-a23dc98bca25','次韻忠甫初見菊開','馮伯規','宋','宋诗','song-poetry','','[]','積雨曉放霽，紅日照我帷。',108,'全唐诗/poet.song.169000.json','["積雨曉放霽，紅日照我帷。", "起來步幽蹊，金蕊燦朱扉。", "芳姿自嫵媚，微香襲人衣。", "令節無多日，更宜擁培之。", "三徑豈不富，最喜先開枝。", "此意誰領解，惟有淵明知。", "子詩正芳潤，白露與俱滋。", "未□泛杯酌，且要滌甘肥。", "落英行可餐，樂哉遂忘饑。"]'),
('405238bc-d4bc-4e2b-a31e-e50eb6ebaa10','擊甌樓夜飲  其一','馮伯規','宋','宋诗','song-poetry','','[]','不上江亭數日間，雨餘山色带清寒。',32,'全唐诗/poet.song.169000.json','["不上江亭數日間，雨餘山色带清寒。", "西風峭湛休圍却，要放秋光入畫闌。"]'),
('c2617cb3-281c-4b08-8b85-5025022ec0db','擊甌樓夜飲  其二','馮伯規','宋','宋诗','song-poetry','','[]','去□□月莫回頭，又見清商醖凜秋。',32,'全唐诗/poet.song.169000.json','["去□□月莫回頭，又見清商醖凜秋。", "悵望一雙鴻鵠下，徑衝煙雨占滄洲。"]'),
('89663de3-1aba-429d-a4a9-0d6cb8d8140d','次韻仲秉木犀','馮伯規','宋','宋诗','song-poetry','','[]','金借顔色月借光，作團穠綠綴深黄。',64,'全唐诗/poet.song.169000.json','["金借顔色月借光，作團穠綠綴深黄。", "合令范曄添成傳，曾向維摩飯此香。", "尚憶□□披御賜，頗疑妙舞簇霓裳。", "當陪玉樹栽天上，肯學夭桃露短牆。"]'),
('07f2f3c9-bb18-427d-9d8b-892b365484b7','游北巖','馮伯規','宋','宋诗','song-poetry','','[]','遥指蒙茸雲木堆，入門小剎傍巖偎。',32,'全唐诗/poet.song.169000.json','["遥指蒙茸雲木堆，入門小剎傍巖偎。", "放懷邱壑興未盡，隔岸角聲招我回。"]'),
('69b0fd72-a6d1-41f6-82e5-11f86530a867','約同僚游佳陰  其一','馮伯規','宋','宋诗','song-poetry','','[]','老木垂垂綠覆欄，欄前髣髴見山□。',32,'全唐诗/poet.song.169000.json','["老木垂垂綠覆欄，欄前髣髴見山□。", "儘教富貴饒公等，未許林泉□數廉。"]'),
('e4cd71f0-b3f8-40f9-a40b-5edba74e273a','約同僚游佳陰  其二','馮伯規','宋','宋诗','song-poetry','','[]','晚霽青山無處逃，秋來乘興便登高。',32,'全唐诗/poet.song.169000.json','["晚霽青山無處逃，秋來乘興便登高。", "□君欲暮休催去，小驛依然□嫩醪。"]'),
('2dbe6c5f-cac3-4f70-a6ac-8afbad00b404','約同僚游佳陰  其三','馮伯規','宋','宋诗','song-poetry','','[]','□□時山漏夕陽，下山草木響□□。',32,'全唐诗/poet.song.169000.json','["□□時山漏夕陽，下山草木響□□。", "□來望到山盡處，一片明冰□□光。"]'),
('bb6fef20-ee90-47b8-9267-190b29c0fe55','□後圃成三絕句  其一','馮伯規','宋','宋诗','song-poetry','','[]','重陽過後菊方開，引得幽人日日來。',32,'全唐诗/poet.song.169000.json','["重陽過後菊方開，引得幽人日日來。", "從□□開到花落，每來傾飲兩三杯。"]'),
('c4aed5e5-86a9-43a0-9714-e4db69beb08d','□後圃成三絕句  其二','馮伯規','宋','宋诗','song-poetry','','[]','摇落枝頭□半空，紛紛群崔啅寒叢。',32,'全唐诗/poet.song.169000.json','["摇落枝頭□半空，紛紛群崔啅寒叢。", "四山□合如封鎖，霜角憑晴聲更雄。"]'),
('9d057709-86e0-44f5-ba56-719530df3889','□後圃成三絕句  其三','馮伯規','宋','宋诗','song-poetry','','[]','家山稍遠夢難到，郡事漸希詩作魔。',32,'全唐诗/poet.song.169000.json','["家山稍遠夢難到，郡事漸希詩作魔。", "句就欲煩相催和，夜窗無奈透霜何。"]'),
('70e172b4-7a3c-4558-995f-a1350c854205','歲晚倚欄','馮伯規','宋','宋诗','song-poetry','','[]','倏忽秋又盡，明朝恰立冬。',48,'全唐诗/poet.song.169000.json','["倏忽秋又盡，明朝恰立冬。", "細傾碧瀲灧，喜對白芙蓉。", "問信遲賓雁，催寒有響蛩。", "暝煙都不見，聞得望□鐘。"]'),
('ff212e7d-c21a-4c4f-b5e6-c1c3c8de72cb','登賦詩樓','馮伯規','宋','宋诗','song-poetry','','[]','高樓無一塵，適此半日閑。',96,'全唐诗/poet.song.169000.json','["高樓無一塵，適此半日閑。", "請以老杜句，賦詩榜其顔。", "井邑各參差，峰巒共回環。", "歲月行且換，星斗如可攀。", "不堪霜風勁，未許酒膽慳。", "祇緣期會急，勿怪題詠艱。", "所喜談聖賢，大勝醉髦蠻。", "倚欄遥夜寂，一笑喧千山。"]'),
('239f88e2-2ab1-4266-a1bc-d5e8232d03a4','次韻劉閬州謝送菊巖春','馮伯規','宋','宋诗','song-poetry','','[]','山中有佳菊，足以配古巖。',48,'全唐诗/poet.song.169000.json','["山中有佳菊，足以配古巖。", "飲酒對此菊，何用薦芳甘。", "不妨玉山頹，對卧千載楠。", "清賞不可共，妙句傳巴南。"]'),
('302e5b5e-1805-4d78-af96-07c6995ca827','無題','馮伯規','宋','宋诗','song-poetry','','[]','暇時結客小舂容，路直重巖紫翠峰。',64,'全唐诗/poet.song.169000.json','["暇時結客小舂容，路直重巖紫翠峰。", "雲閣翬飛翼鸞鳳，石楠盤屈老虬龍。", "林扉雨過便秋菊，山寺風清度晚鍾。", "快展眉頭須劇飲，天開霽色不妨農。"]'),
('88c7684d-e388-4e24-81f4-05ba6960e234','碧沼寺  其一','劉大綱','宋','宋诗','song-poetry','','[]','夜色清無滓，虛涼月滿亭。',48,'全唐诗/poet.song.169000.json','["夜色清無滓，虛涼月滿亭。", "螢飛時度竹，魚躍乍翻萍。", "冉冉雲歸盡，霏霏露欲零。", "劇談渾得趣，相對兩忘形。"]'),
('cf07b452-f19c-4261-979b-f75cb5ad1c92','碧沼寺  其二','劉大綱','宋','宋诗','song-poetry','','[]','地僻人稀到，唐賢句尚存。',48,'全唐诗/poet.song.169000.json','["地僻人稀到，唐賢句尚存。", "觀魚尋曲沼，弔古入名園。", "山翠沾夜袂，苔紋印屐痕。", "暫陪尊俎樂，簫鼓出丘樊。"]'),
('bed6616c-abd0-4ecc-ae04-9ddf3ff596f8','鑑軒','劉大綱','宋','宋诗','song-poetry','','[]','一泓清澈底，明可燭鬚眉。',48,'全唐诗/poet.song.169000.json','["一泓清澈底，明可燭鬚眉。", "漾月摇金影，涵風皺綠漪。", "臺高懸寶鑑，水定照摩尼。", "宴坐宜臨賦，難忘此段奇。"]'),
('73daaef1-2f85-46a0-b373-fd51765dc720','寄萍鄉密老','趙鳴鐸','宋','宋诗','song-poetry','','[]','匹馬飄然似轉蓬，一年兩度過湘東。',64,'全唐诗/poet.song.169000.json','["匹馬飄然似轉蓬，一年兩度過湘東。", "襟間潤带黄梅雨，枕上涼生苦楝風。", "亟亟窮途將底用，區區苟祿有何功。", "輸他燕坐長廳老，默對濃香丈室中。"]'),
('478c705e-4aba-4b6a-8e00-a11d535fb1cd','礲巖','林岊','宋','宋诗','song-poetry','','[]','嘗聞仙人渡海術，授以尺杖如飛龍。',112,'全唐诗/poet.song.169000.json','["嘗聞仙人渡海術，授以尺杖如飛龍。", "憑虛閉目不敢瞬，波濤洶涌喧天風。", "茲巖山窟飛海岸，直掃一澗聲何雄。", "瞑行千步水入耳，明探萬壑雲生胸。", "嶔崖滴乳芝玉脆，剜穴噴水蓮腮紅。", "神仙縹緲在何許，心平意定天爲通。", "此行况復匪游戲，出門借問春耕農。"]'),
('21ac2f20-75c6-4754-987d-5ef8f379557a','波斯巖','林岊','宋','宋诗','song-poetry','','[]','何物波斯有此巖，巖前巖後著深潭。',64,'全唐诗/poet.song.169000.json','["何物波斯有此巖，巖前巖後著深潭。", "雙猊顧母魚鱗脊，峙闕迎賓玉筍簪。", "立塑崩崖天入牖，垂纓寶蓋佛留龕。", "使君勸課親來此，謾與邦人父老談。"]'),
('19c516e4-4309-4509-b958-bb27fd4a5e9f','青田巖','林岊','宋','宋诗','song-poetry','','[]','老鶴回翔去幾年，至今巖壑此名傳。',64,'全唐诗/poet.song.169000.json','["老鶴回翔去幾年，至今巖壑此名傳。", "躋攀分寸疑無路，飛入方壺却有天。", "白象綠獅呈怪石，神泉深洞隠真仙。", "細看滴乳流脂處，不是青田是玉田。"]'),
('f0778bb2-790e-4b4d-90a4-835355201bb8','盤石','林岊','宋','宋诗','song-poetry','','[]','捲煙閣西官道長，一水東注襟滄浪。',64,'全唐诗/poet.song.169000.json','["捲煙閣西官道長，一水東注襟滄浪。", "山連踞虎巖如屋，棧接飛鸞石作梁。", "田野四時歌樂土，關河千里隔蠻鄉。", "我來九載叨民牧，億萬斯年說太康。"]'),
('7eb543c4-6ec5-4c83-8b99-2e043ceb886b','句','林岊','宋','宋诗','song-poetry','','[]','山中有寺寺有閣，閣外之山橫翠來。',16,'全唐诗/poet.song.169000.json','["山中有寺寺有閣，閣外之山橫翠來。"]'),
('d75d9036-dae3-4881-ba05-c5e7adae8bc5','題釣臺','俞成','宋','宋诗','song-poetry','','[]','千古英風想子陵，釣臺緣此幾人登。',32,'全唐诗/poet.song.169000.json','["千古英風想子陵，釣臺緣此幾人登。", "誰知避諱更嚴氏，灘與州名總誤稱。"]'),
('b7c79f1e-5d41-44dd-8fe2-3ed8fef588c6','句','黄元夫','宋','宋诗','song-poetry','','[]','葦村風下鴉千點，麥隴天垂月一梳。',16,'全唐诗/poet.song.169000.json','["葦村風下鴉千點，麥隴天垂月一梳。"]'),
('09bde38d-bfa3-4d3c-8fba-20e4bb419955','南劍州','黄卓','宋','宋诗','song-poetry','','[]','化成丹碧出鰲頭，獨占閩川最上游。',32,'全唐诗/poet.song.169000.json','["化成丹碧出鰲頭，獨占閩川最上游。", "兩劍合來靈一境，雙溪分處带三州。"]'),
('04109059-1953-432f-86df-303617bbbab2','句  其一','黄卓','宋','宋诗','song-poetry','','[]','延平商閣瞰雙溪，神劍光芒衝斗極。',16,'全唐诗/poet.song.169000.json','["延平商閣瞰雙溪，神劍光芒衝斗極。"]'),
('76bdfff7-e488-435a-93ab-a34e976dc59c','句  其二','黄卓','宋','宋诗','song-poetry','','[]','浪捲雙溪神物化，烟橫三岸電光飛。',16,'全唐诗/poet.song.169000.json','["浪捲雙溪神物化，烟橫三岸電光飛。"]'),
('95781a4b-0025-4574-bc2d-b5f1ee79da8a','題睢陽五老圖','歐陽謙之','宋','宋诗','song-poetry','','[]','厚德良多積善根，賢才他日在兒孫。',64,'全唐诗/poet.song.169000.json','["厚德良多積善根，賢才他日在兒孫。", "當知相里非凡壻，豈有陳平久席門。", "五老繪圖千載譽，群公詩禮百年存。", "憑君挾取傳家學，青史賢良有後昆。"]'),
('d16f3fad-8245-460e-87f4-f478e8253b74','送考亭朱夫子赴天台','陳邦鑰','宋','宋诗','song-poetry','','[]','羸馬踏殘月，荷策登泮宮。',128,'全唐诗/poet.song.169000.json','["羸馬踏殘月，荷策登泮宮。", "入門見先生，先生何從容。", "循循善誘能啟下，青蒿因得附長松。", "短檠相對三百六十夜，高談雄辨磊落沃胸中。", "吾王求士苦匆匆，未許先生久卧龍。", "乘驄直上天台路，祗緣此去何由從。", "嗚唏吁，小齋從此冷如水，虀鹽朝暮怏怏爾。", "空留絳悵照孤燈，窗外西風寒起葦。"]'),
('a64d7178-8251-47d5-9781-8cb57bf42f6f','和劉叔通','游開','宋','宋诗','song-poetry','','[]','昨夜劉郎叩角歌，朔雲寒雪滿山阿。',64,'全唐诗/poet.song.169000.json','["昨夜劉郎叩角歌，朔雲寒雪滿山阿。", "文章無用乃如此，富貴不來爭奈何。", "邴鄭向嘗依北海，晁張今復事東坡。", "吹噓合有飛騰便，未用溪頭買釣蓑。"]'),
('2eff3706-9f7a-48cd-b3d2-9c4c9903b0f3','絕句','游開','宋','宋诗','song-poetry','','[]','黄陵廟前湘水春，春烟愁殺渡湘人。',32,'全唐诗/poet.song.169000.json','["黄陵廟前湘水春，春烟愁殺渡湘人。", "人隨歸雁去無迹，水遠山長歌又新。"]'),
('859e4cd0-c57e-44ed-a88c-8ce6c81e53e4','王剛仲惠詩醉筆聊和','劉琰','宋','宋诗','song-poetry','','[]','君不見山澤之癯蒙野服，爲彼隰桑還自沃。',198,'全唐诗/poet.song.169000.json','["君不見山澤之癯蒙野服，爲彼隰桑還自沃。", "又不見侯門公子貴且嬌，飽豢膏粱猶未足。", "人生貴賤不難分，唯有聖賢無等倫。", "朝爲塗人暮爲禹，窮崖斷壑看回春。", "君方妙齡截不住，萬里飛黄又騰世。", "王良造父不得施，耳側風聲未爲遽。", "我思古人愛其宇，青蘋堂兮杜若廡。", "芰荷可裳菊可餐，肯逐纖埃與塵土。", "是中非聲亦非色，安得與君一馮軾。", "鵾鵬變化不可量，要指天池爲一息。", "悠悠此道誰能將，從知可玩不可忘。", "慎勿隨風學飄絮，春光駘蕩成飛揚。"]'),
('c064a45a-c3d5-4bb6-b529-7a43d639d6d7','詰貓','劉琰','宋','宋诗','song-poetry','','[]','古人養客乏車魚，今汝何功客不如。',32,'全唐诗/poet.song.169000.json','["古人養客乏車魚，今汝何功客不如。", "飯有溪魚眠有毯，忍教鼠齧案頭書。"]'),
('3ac9358e-ee32-4f9e-9de0-327a56bad12c','句','劉琰','宋','宋诗','song-poetry','','[]','嗚呼諸將官日穹，豈知萬鬼號陰風。',16,'全唐诗/poet.song.169000.json','["嗚呼諸將官日穹，豈知萬鬼號陰風。"]'),
('1257cd86-8743-443b-84b2-2ac4f4c4e730','詩一首','王過','宋','宋诗','song-poetry','','[]','荔子雨晴紅點點，葡萄江漲綠流流。',32,'全唐诗/poet.song.169000.json','["荔子雨晴紅點點，葡萄江漲綠流流。", "夢魂不啻三千里，倦翮難勝九萬風。"]'),
('394f3a6d-3d42-4f6f-a66f-5e0a06b5b94d','句  其一','王過','宋','宋诗','song-poetry','','[]','心存北闕馳魂夢，身漸東歸出鬼關。',16,'全唐诗/poet.song.169000.json','["心存北闕馳魂夢，身漸東歸出鬼關。"]'),
('87f5282d-2875-44b7-9224-5e6b2959356d','句  其二','王過','宋','宋诗','song-poetry','','[]','危亭北據水南流，檻外頻來海上舟。',16,'全唐诗/poet.song.169000.json','["危亭北據水南流，檻外頻來海上舟。"]'),
('10a5833f-a172-4ccc-a0be-137a9442e1aa','句  其三','王過','宋','宋诗','song-poetry','','[]','寄語往來荆廣客，鬼門關在鬰林西。',16,'全唐诗/poet.song.169000.json','["寄語往來荆廣客，鬼門關在鬰林西。"]'),
('d2de3a4e-74d7-454c-9b9f-19ac5d58960c','送僧還日本','鍾唐傑','宋','宋诗','song-poetry','','[]','上人海東秀，才華衆推優。',132,'全唐诗/poet.song.169000.json','["上人海東秀，才華衆推優。", "學道慕中國，於焉一來遊。", "武林忽相遇，鍼芥意頗投。", "儒道雖云異，詩酒喜共酬。", "况茲古名郡，佳麗罕與儔。", "湖山快吟覽，勝跡恒追求。", "合并惜未久，又理東歸舟。", "揚帆渡鯨浪，帖帖如安流。", "慇懃不忍別，繾綣難爲留。", "臨風極遐睇，目斷扶桑陬。", "他時託芳字，還能寄余不。"]'),
('db69afde-a226-4bc2-82ba-a16221e987dd','呈朱晦翁','余大雅','宋','宋诗','song-poetry','','[]','三見先生道愈尊，言提切切始能安。',64,'全唐诗/poet.song.169000.json','["三見先生道愈尊，言提切切始能安。", "如今抉破本根說，不作從前料想看。", "有物有常須自盡，中倫中慮覺猶難。", "願言克己功夫熟，便得周旋事仰鑽。"]'),
('b033ee6d-5c3c-42e1-b369-b526cfb18ab6','題武夷  其一','呂天澤','宋','宋诗','song-poetry','','[]','書林追慕紫陽翁，出入嘗沾教雨中。',32,'全唐诗/poet.song.169000.json','["書林追慕紫陽翁，出入嘗沾教雨中。", "緬仰高山難企及，大開茅塞逕能通。"]'),
('0c642b0c-5e25-439b-b178-98a44b082370','題武夷  其二','呂天澤','宋','宋诗','song-poetry','','[]','乘興來尋杜使君，亂山矗矗白雲深。',32,'全唐诗/poet.song.169000.json','["乘興來尋杜使君，亂山矗矗白雲深。", "武夷仙子能知己，謾寫新詩訴此心。"]'),
('a30a9b06-df82-4da5-a255-9275c3936305','題武夷  其三','呂天澤','宋','宋诗','song-poetry','','[]','南北相看一嶺分，長懷欲謁武夷君。',32,'全唐诗/poet.song.169000.json','["南北相看一嶺分，長懷欲謁武夷君。", "箇中果隠神仙客，握手交談迥不群。"]'),
('31e678da-74d6-4198-b784-a1e9a27b3990','次朱文公廓然亭韻','李倜','宋','宋诗','song-poetry','','[]','清晨出西郊，危徑甃滑石。',96,'全唐诗/poet.song.169000.json','["清晨出西郊，危徑甃滑石。", "徐登九日山，眼觀天地窄。", "滄溟渺無涯，雲林森削壁。", "徙倚極遐觀，感今懷往昔。", "而我遂幽尋，塵事忽如失。", "頎然隠君子，未審果何得。", "磨崖古題名，半含蒼蘚碧。", "日夕促歸鞍，青山雲亂白。"]'),
('874c62b1-24aa-493d-992d-c1f3dae91b1e','讀莊子','陳藻','宋','宋诗','song-poetry','','[]','堯無是處桀無非，此語堪驚與道違。',32,'全唐诗/poet.song.169000.json','["堯無是處桀無非，此語堪驚與道違。", "造物恩私多嵬瑣，始知莊子得真機。"]'),
('d652fc15-17d8-4262-a2c9-e4eb573fc90d','偶游白渡懷劉九','陳藻','宋','宋诗','song-poetry','','[]','心隨飛鳥過寒沙，兩岸沿江曲又斜。',32,'全唐诗/poet.song.169000.json','["心隨飛鳥過寒沙，兩岸沿江曲又斜。", "便有隻船乘月渡，都無五里到君家。"]'),
('84caedcc-7ba2-4607-b1ba-2a1829ad0a14','寄劉九','陳藻','宋','宋诗','song-poetry','','[]','一生閉門不結交，彙緣遇我如同胞。',164,'全唐诗/poet.song.169000.json','["一生閉門不結交，彙緣遇我如同胞。", "年年客裏故人多，飲水逢君朱顔酡。", "鵲去鳩來有空屋，牝乳雛飛無啄粟。", "香火飄零甘死休，無辜憐我兄遭戮。", "暗中魑魅籍姓名，我有朋儔等不足。", "十事上心九事忘，一日囘首千日長。", "誰登百丈嶺，我到鍾山傍。", "登堂拜丘嫂，携手戲諸郎。", "諸郎挽衣幼女親，汝母磊落如吾人。", "哀我若見韓氏孤，敬我寧知蘇子貧。", "吁嗟尺布謠，空道天屬真。"]'),
('3db4e9e8-164e-4462-bd6e-a24e1cac6aae','寄劉八','陳藻','宋','宋诗','song-poetry','','[]','六度封書向小孤，一度逢人寄書無。',180,'全唐诗/poet.song.169000.json','["六度封書向小孤，一度逢人寄書無。", "劉郎嗔我無短吟，素書百紙難論心。", "我愛劉郎可無詩，劉郎愛客還笞兒。", "我爲父執倍其年，見我呼兄挾渠賢。", "撥棄勿復陳，對君吟此身。", "憶昔在桂堂，瘧鬼罹我殃。", "世情疎客病，移我君家床。", "兒女不辭勞，僕妾何憚忙。", "秋風黄葉飛，明燈藥爐傍。", "我身何日殞，此念何時忘。", "丘嫂晚歲歸，敬我如小郎。", "他年山下結吾廬，朝暮往來摩白鬚。", "我抱子，君抱孫，却使相敘爲弟昆。"]'),
('28e12155-a534-4c4b-8a0d-8d628252d04c','黄石還漁溪寄劉九四首  其一','陳藻','宋','宋诗','song-poetry','','[]','孤青湖外幾時歸，想極吟孤落月知。',32,'全唐诗/poet.song.169000.json','["孤青湖外幾時歸，想極吟孤落月知。", "身似南飛烏與鵲，歸來何處不相思。"]'),
('d2fbee1a-eed3-4169-b114-fdecf5e912eb','黄石還漁溪寄劉九四首  其二','陳藻','宋','宋诗','song-poetry','','[]','多少人家好弟兄，不堪閨婦似吹笙。',32,'全唐诗/poet.song.169000.json','["多少人家好弟兄，不堪閨婦似吹笙。", "十年再拜如丘嫂，更盡劉郎故舊情。"]'),
('2c2e75f0-2e7e-4cd3-aff2-a1d04046dafc','黄石還漁溪寄劉九四首  其三','陳藻','宋','宋诗','song-poetry','','[]','老去今秋迹轉孤，憐君幼女似童烏。',32,'全唐诗/poet.song.169000.json','["老去今秋迹轉孤，憐君幼女似童烏。", "窮通何事關渠甚，便問明朝有試無。"]'),
('68f49323-6cc4-481b-8965-4c4ae5fc8d3e','黄石還漁溪寄劉九四首  其四','陳藻','宋','宋诗','song-poetry','','[]','南北東西語別頻，白頭何計作比隣。',32,'全唐诗/poet.song.169000.json','["南北東西語別頻，白頭何計作比隣。", "便留久客如前度，無暇長年作主人。"]'),
('3eb1ed1f-08d1-457d-8bae-cb3b98b6f6b0','久不得劉九書因題寄之','陳藻','宋','宋诗','song-poetry','','[]','劉郎蹤跡若爲疎，蟹井山前似里閭。',64,'全唐诗/poet.song.169000.json','["劉郎蹤跡若爲疎，蟹井山前似里閭。", "少小麻風今半愈，長成項疾喜全除。", "豐年誰與嘗新稻，吉日因知仄舊廬。", "何事別君纔百里，可堪終歲斷來書。"]'),
('0911fa76-2202-409d-a391-be22f04f0e37','重山論易贈吳叔達','陳藻','宋','宋诗','song-poetry','','[]','似汝論三易，何人閲五車。',24,'全唐诗/poet.song.169000.json','["似汝論三易，何人閲五車。", "白頭長作侶，黄石即爲家。"]'),
('80d95563-1e05-4cbd-af73-323a5e1f155e','丹井懷叔達','陳藻','宋','宋诗','song-poetry','','[]','喜稱吾子賦，羞道少年時。',48,'全唐诗/poet.song.169000.json','["喜稱吾子賦，羞道少年時。", "別去休論易，愁來欲寄詩。", "夕陽書不到，殘月夢相隨。", "晚歲傷心事，松峬獨語誰。"]'),
('caf2240d-b185-44f0-8cee-e6f91c5e91e9','憑欄','陳藻','宋','宋诗','song-poetry','','[]','少壯營營正苦心，憑欄況味不如今。',32,'全唐诗/poet.song.169000.json','["少壯營營正苦心，憑欄況味不如今。", "如今飯散憑欄立，一本寒枯木在林。"]'),
('e480bfdc-bda4-4613-b274-7e0106dfc588','桂堂秋夜','陳藻','宋','宋诗','song-poetry','','[]','熒熒燈火臨書卷，續續蛙聲入桂林。',32,'全唐诗/poet.song.169000.json','["熒熒燈火臨書卷，續續蛙聲入桂林。", "背後曲肱眠小子，床頭酌酒服玄參。"]'),
('e9444a23-3f25-4b82-a72d-fd8427e9766d','題劉氏翠微亭','陳藻','宋','宋诗','song-poetry','','[]','舊屋紅蕖外，新亭綠樹傍。',48,'全唐诗/poet.song.169000.json','["舊屋紅蕖外，新亭綠樹傍。", "江晴孤棹見，雨近衆山藏。", "學圃未成趣，催詩何太忙。", "他年多橘柚，此地一瀟湘。"]'),
('38780e4c-c19f-4539-bd4b-8767a7ed9e29','誦少陵詩集','陳藻','宋','宋诗','song-poetry','','[]','麻鞋奔走杜陵翁，卧盡風帆雨驛中。',32,'全唐诗/poet.song.169000.json','["麻鞋奔走杜陵翁，卧盡風帆雨驛中。", "天也不愁窮餓殺，年年催促要詩工。"]'),
('a70fb2cb-06fc-4942-88f0-4503a30f70ab','福州城北吳氏新樓之作','陳藻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千山匼匝繞三山，盡屬危樓一覷間。',64,'全唐诗/poet.song.169000.json','["千山匼匝繞三山，盡屬危樓一覷間。", "雲漢星辰誰道遠，鄰家花木不容慳。", "憑欄要取西湖盡，落葉尤宜朔吹寒。", "況是先生莊列輩，眼高人境幾層看。"]'),
('fbfc2086-b31b-42dc-9602-ca783dfb529d','過黄州訪東坡雪堂遺跡擬作','陳藻','宋','宋诗','song-poetry','','[]','謫來誰作久長居，便擬明朝歸舊廬。',64,'全唐诗/poet.song.169000.json','["謫來誰作久長居，便擬明朝歸舊廬。", "誦遍離騷情不已，讀殘鵩賦恨如初。", "斯翁直是憂黎庶，到處仍看似里閭。", "父老無人堪問訊，黄昏立馬轉躊躇。"]'),
('b8ab80e9-bef5-4a98-b1cf-2ffbc4880b7f','寓居','陳藻','宋','宋诗','song-poetry','','[]','到處情親即寓居，從他相狎又相疎。',64,'全唐诗/poet.song.169000.json','["到處情親即寓居，從他相狎又相疎。", "年衰骨肉多埋土，身賤交朋少寄書。", "萬象去來無了日，一元開闔不關渠。", "逢人問我今何在，寥落空山誦子虛。"]'),
('568fc287-e369-4079-8509-3f4a3b1d0e9c','述懷','陳藻','宋','宋诗','song-poetry','','[]','病身四十未妻孥，墟墓那堪兩世孤。',16,'全唐诗/poet.song.169000.json','["病身四十未妻孥，墟墓那堪兩世孤。"]'),
('00d9dc96-e9a4-4ff5-9922-d18a936ab26b','蟹井','陳藻','宋','宋诗','song-poetry','','[]','此山鼇不動，此井蟹如何。',48,'全唐诗/poet.song.169000.json','["此山鼇不動，此井蟹如何。", "小阜爲拳石，晴田看盡波。", "俯知雲障下，却放日輪過。", "一上一囘首，層層眼界多。"]'),
('aaa07a13-de1a-4ad8-88a4-7a2ab9607957','虎丘','陳藻','宋','宋诗','song-poetry','','[]','竹瘦門逾靜，樓高山太低。',48,'全唐诗/poet.song.169000.json','["竹瘦門逾靜，樓高山太低。", "白煙青樹走，細雨大江迷。", "野水東西渡，園蔬上下畦。", "僧無城市去，岩有鬼神棲。"]'),
('057d89b9-89c3-4c03-b1b0-fba8f8adf105','山中有感','陳藻','宋','宋诗','song-poetry','','[]','每看風月非人世，錯認江山是畫圖。',32,'全唐诗/poet.song.169000.json','["每看風月非人世，錯認江山是畫圖。", "誰解吟詩追李杜，何須涉海訪蓬壺。"]'),
('9515bd23-38e7-409e-8307-ce358196d245','城山偶題','陳藻','宋','宋诗','song-poetry','','[]','四天圍一地，濁少判清多。',24,'全唐诗/poet.song.169000.json','["四天圍一地，濁少判清多。", "人氣翻相敵，無如俗物何。"]'),
('de472889-1fcb-4acc-b864-ef18cc5e969a','漁溪西軒','陳藻','宋','宋诗','song-poetry','','[]','千尋好景羣峰起，一抹寒烟半壁留。',64,'全唐诗/poet.song.169000.json','["千尋好景羣峰起，一抹寒烟半壁留。", "日影漸高魚網曬，雨聲長響桔槔休。", "種麻賣布皆貧婦，伐蔗炊糖無末遊。", "狂客寂寥貪看月，初旬已看月如鈎。"]'),
('d1228eee-06a6-4002-91be-fcc8c2f9ccf7','紫瑞香三首  其一','陳藻','宋','宋诗','song-poetry','','[]','中開素粉笑濃霜，外带凝脂妬夕陽。',32,'全唐诗/poet.song.169000.json','["中開素粉笑濃霜，外带凝脂妬夕陽。", "縱有寒梅祇一色，暗香不似撲人香。"]'),
('238444d4-6431-4133-9856-171a49b00af4','紫瑞香三首  其二','陳藻','宋','宋诗','song-poetry','','[]','無數枝頭簇簇葩，大枝直上細枝斜。',32,'全唐诗/poet.song.169000.json','["無數枝頭簇簇葩，大枝直上細枝斜。", "商量開盡商量落，全要前花見後花。"]'),
('29abaaa4-ba80-4def-bd0b-3c9e1040a771','紫瑞香三首  其三','陳藻','宋','宋诗','song-poetry','','[]','放蕊爭先見菊彫，逐花旋拆到桃夭。',32,'全唐诗/poet.song.169000.json','["放蕊爭先見菊彫，逐花旋拆到桃夭。", "若爲耐久還柔脆，莫折仙枝本易摇。"]'),
('d3d1bf39-7dfa-4af5-b3b1-affe50b484b0','丘叔喬七十生朝二首  其一','陳藻','宋','宋诗','song-poetry','','[]','人生七十爲稀有，强健如公有幾人。',32,'全唐诗/poet.song.169000.json','["人生七十爲稀有，强健如公有幾人。", "況是上元燈火夜，兒孫楚楚賀生辰。"]'),
('7926c492-0394-4493-9ab0-9e7e5763e15a','丘叔喬七十生朝二首  其二','陳藻','宋','宋诗','song-poetry','','[]','大兒別有論文眼，樸實無他是次丁。',32,'全唐诗/poet.song.169000.json','["大兒別有論文眼，樸實無他是次丁。", "長女嫁夫能儉約，小娘駡婿見財輕。"]'),
('24acd66b-9fd1-41c8-b54c-bc997620b1e0','與宗上人同飲','陳藻','宋','宋诗','song-poetry','','[]','同年同月又同時，邂逅僧房把酒巵。',32,'全唐诗/poet.song.169000.json','["同年同月又同時，邂逅僧房把酒巵。", "五十年來未相識，鄰州兩舍賀生兒。"]'),
('6ce56587-debd-42a6-8bd2-f4c5ce0f66c0','試後自題因送從弟敬之赴省','陳藻','宋','宋诗','song-poetry','','[]','銀袍二萬縱人多，筆誤無如鬼魅何。',64,'全唐诗/poet.song.169000.json','["銀袍二萬縱人多，筆誤無如鬼魅何。", "祇恐有司長莽鹵，那知昏病自蹉蛇。", "交遊解散文因怪，門戶誰興鬢欲皤。", "頼有阿連才思逸，乘槎好好上天河。"]'),
('4bdce61c-1d7b-4903-99d9-d054dbf67f3a','貧婦行','陳藻','宋','宋诗','song-poetry','','[]','故人身死妻貧病，買藥無錢留性命。',170,'全唐诗/poet.song.169000.json','["故人身死妻貧病，買藥無錢留性命。", "半簞赤飯一盂蔬，對不能餐雙淚迸。", "阿官賣田妾未歸，稅在夫家田賣誰。", "鄉胥改割全隠匿，妾典衣裳空被追。", "零落生涯種片園，朝朝夜夜盜開門。", "鄰翁苦妾妾租客，客也無輸叫妾論。", "那更雙棺四缶灰，伐山博米圖葬埋。", "嗚呼豪强欺妾奪山去，不許鹽丁燃妾柴。", "十歲孤兒出縣庭，空手携狀投杳冥，黄堂走罷走使軿。", "文書送縣已三月，依舊含冤說我聽。"]'),
('fe15caf9-3e8c-4a5c-a8b3-000cab700a92','問太虛','陳藻','宋','宋诗','song-poetry','','[]','生前百事無如意，死後浮名總是空。',32,'全唐诗/poet.song.169000.json','["生前百事無如意，死後浮名總是空。", "剛把窮愁作題目，哦詩不要晚年工。"]'),
('8b3b7f36-f30c-407a-89ee-c83c93fce241','西窗晚眺','陳藻','宋','宋诗','song-poetry','','[]','兩年無事坐窗間，數盡西邊不老山。',32,'全唐诗/poet.song.169000.json','["兩年無事坐窗間，數盡西邊不老山。", "薄暮忽迷雲與樹，驚來乍見別峰巒。"]'),
('42d4758e-a9f1-49b9-a67f-da492f7834b5','海口吟','陳藻','宋','宋诗','song-poetry','','[]','按圖自古無人到，二百年來戶口添。',64,'全唐诗/poet.song.169000.json','["按圖自古無人到，二百年來戶口添。", "架屋上山成市井，張官近海課魚鹽。", "估客趁潮撐米入，沒人忍凍采蠔粘。", "仲尼有廟塵誰掃，寺觀崢嶸香火嚴。"]'),
('f3c042c9-a140-4b34-859a-40025882537d','和林子望二絕  其一','陳藻','宋','宋诗','song-poetry','','[]','勸君莫要嘆無官，門廕何如自致難。',32,'全唐诗/poet.song.169000.json','["勸君莫要嘆無官，門廕何如自致難。", "誰肯宦途爲第二，玉階好好唱名還。"]'),
('11b717f3-def8-4125-a4d5-c79773217f82','和林子望二絕  其二','陳藻','宋','宋诗','song-poetry','','[]','勸君莫要嘆無官，幸有田園在故山。',32,'全唐诗/poet.song.169000.json','["勸君莫要嘆無官，幸有田園在故山。", "滿室清風滿林月，人生何事勝於閒。"]'),
('82ffd7bc-e381-4e7f-96fe-649b6bc78670','劉五十丈生日','陳藻','宋','宋诗','song-poetry','','[]','與君他語自差殊，獨愛交財是丈夫。',32,'全唐诗/poet.song.169000.json','["與君他語自差殊，獨愛交財是丈夫。", "願見年年生日會，老來活計尚關渠。"]'),
('626d731d-1b78-48a6-9dd9-40ec4bb3f6e9','雲菴覓詩','陳藻','宋','宋诗','song-poetry','','[]','百級危階上翠巒，四邊山色自低環。',32,'全唐诗/poet.song.169000.json','["百級危階上翠巒，四邊山色自低環。", "海鄉無限蕭條景，收到樓前是美觀。"]'),
('450e278d-b78f-4ba8-8f92-dc27f1ddb311','一古一律賀嬾翁宏仲七十  其一','陳藻','宋','宋诗','song-poetry','','[]','醵飲高堂慶古希，名存寔是節常儀。',64,'全唐诗/poet.song.169000.json','["醵飲高堂慶古希，名存寔是節常儀。", "百篇自號嬾翁詩，一句誰吟持侑巵。", "我見前程多險巇，朝聞夕可寧不怡。", "健如此叟更待時，黄金散盡呼來歸。"]'),
('a7db9dda-ca9b-4ffa-80e4-348b4cdc6e49','一古一律賀嬾翁宏仲七十  其二','陳藻','宋','宋诗','song-poetry','','[]','當年嗽卧丈人家，鼓笛村村改歲華。',64,'全唐诗/poet.song.169000.json','["當年嗽卧丈人家，鼓笛村村改歲華。", "選肉必多儲胃腎，忌鮮緣不啗魚蝦。", "閨房德義談雖切，事業身窮報自賒。", "肺疾晚侵誰是主，看君七十更寒些。"]'),
('cdee011a-a614-498d-b100-03baa0bfb06c','次子望肯堂之什','陳藻','宋','宋诗','song-poetry','','[]','酒樽開處是陽春，有屋休論舊與新。',64,'全唐诗/poet.song.169000.json','["酒樽開處是陽春，有屋休論舊與新。", "才子綠袍能賦詠，乃翁青冢亦精神。", "人心多向醒時僞，情話無如醉後真。", "莫要孟光同遯去，急須榮祿奉偏親。"]'),
('8ec030d8-04cd-4f87-afc7-c821c73e9400','陳叔盥兩惠詩以一首謝','陳藻','宋','宋诗','song-poetry','','[]','休要逢人誦六經，紅泉往事已凋零。',64,'全唐诗/poet.song.169000.json','["休要逢人誦六經，紅泉往事已凋零。", "向來未壞恭王壁，到處閒摇普化鈴。", "幾歲寒窗頭也白，兩篇新什眼空青。", "還鄉舊識多農賈，那得柴門自掩扃。"]'),
('ff540bfd-6d04-48ad-83c4-db0c965cac40','穀城山下作','陳藻','宋','宋诗','song-poetry','','[]','遠來便見兩山睽，一大隆高一小低。',32,'全唐诗/poet.song.169000.json','["遠來便見兩山睽，一大隆高一小低。", "及到近看如合璧，壺公祗與穀城齊。"]'),
('d08deff8-a7e4-4328-ab49-fdae2b537d51','城山讀書','陳藻','宋','宋诗','song-poetry','','[]','雨響泉流樂不如，月明松柏勝旌旟。',32,'全唐诗/poet.song.169000.json','["雨響泉流樂不如，月明松柏勝旌旟。", "誰能五十猶勤苦，祗向山間受用書。"]'),
('c95c39da-a752-4911-841d-11689953b2b2','送年','陳藻','宋','宋诗','song-poetry','','[]','一味清貧好送年，堪嗟柴炭買無錢。',32,'全唐诗/poet.song.169000.json','["一味清貧好送年，堪嗟柴炭買無錢。", "生涯幸與干戈遠，不管天明聽雨眠。"]'),
('60f32f4d-b4b0-4f0f-b6ab-5a2b16d47156','秋雨','陳藻','宋','宋诗','song-poetry','','[]','早禾收罷晚禾青，再插秧開滿眼成。',32,'全唐诗/poet.song.169000.json','["早禾收罷晚禾青，再插秧開滿眼成。", "誰道秋風專肅殺，依然四月雨中行。"]'),
('82d4ea30-af16-497d-839c-2da9932cc2a7','林若愚七十','陳藻','宋','宋诗','song-poetry','','[]','思我從網山，問道紅泉市。',192,'全唐诗/poet.song.169000.json','["思我從網山，問道紅泉市。", "託翁自漁溪，餉我百餘里。", "數窮初值變，巢穴夜焚毀。", "我恰還君家，曉霜失行李。", "君家一物無，宦學吾請已。", "艱難全信義，勉强圖終始。", "三載客招提，饋遺無廢弛。", "薄莫聞叩門，奔走勞僕使。", "先生顧之笑，以我匹子美。", "他時誓作銘，自送此老死。", "新春方七十，行步追鹿豕。", "犀斜宿草多，惆悵餘一紀。", "幸有活頭顱，見君松竹比。", "屈伸隨變化，貧富休悲喜。", "人生飽諳曆，熟識興衰理。", "身佚心鎮愚，千歲焉用彼。"]'),
('00900c9c-4b18-485a-a0e6-e577ba9cc166','網山先生諱日寄綺伯','陳藻','宋','宋诗','song-poetry','','[]','先生一去三十年，蘋藻聊修諱日虔。',112,'全唐诗/poet.song.169000.json','["先生一去三十年，蘋藻聊修諱日虔。", "雌劍忽尋雄劍逝，恰恰歲暮吾無錢。", "乃知毫髮有造化，此禮終與吾毋緣。", "人生損益固常理，韓門仍被流俗牽。", "鳳毛辭采非不美，再拜焚香符水前。", "驅邪院中諸將吏，或書或畫縱橫縣。", "網山有靈應大笑，安得師友尚流傳。"]'),
('2a897ca9-5eaa-4196-943a-54164b55be12','三教','陳藻','宋','宋诗','song-poetry','','[]','枉費工夫是學仙，聖門妙處與僧傳。',32,'全唐诗/poet.song.169000.json','["枉費工夫是學仙，聖門妙處與僧傳。", "百年合死千年贅，一物都無萬物全。"]'),
('9896d8f9-be34-4ac5-9875-eb102326bbbc','贈叔嘉叔平劉丈','陳藻','宋','宋诗','song-poetry','','[]','木槽壓油三石餘，半爲燈火半煮蔬。',96,'全唐诗/poet.song.169000.json','["木槽壓油三石餘，半爲燈火半煮蔬。", "上山伐柴五十束，九分賣錢一燒肉。", "等閑八月舉場歸，早禾囷畢晚禾稀。", "道行願見國人肥，高才久屈當奮飛。", "萬一主司仍見遺，課奴種麥家相宜。", "老夫借屋蓄妻兒，寂寥慣便亦何悲。"]'),
('c105f9c2-9e9c-4b2e-8252-83532c55c381','丘德基七十','陳藻','宋','宋诗','song-poetry','','[]','斯翁千歲也何愁，七十真堪賀禮修。',32,'全唐诗/poet.song.169000.json','["斯翁千歲也何愁，七十真堪賀禮修。", "多少人間貧病客，不貪天地久相留。"]'),
('e968bc5c-d5a2-4840-9d2f-d52ecb93df20','賀丘子從遷居','陳藻','宋','宋诗','song-poetry','','[]','老夫昨者亦遷居，只是他人借屋廬。',64,'全唐诗/poet.song.169000.json','["老夫昨者亦遷居，只是他人借屋廬。", "道義交親無罣礙，妻孥慮遠自嗟吁。", "迺翁能殖千金去，令子均分甲第餘。", "醉卧市心年月久，南橋依舊賦歸歟。"]'),
('3f4d5236-ee3d-4e77-9745-5fad01c86bd7','賀子永爲令郎醮婦','陳藻','宋','宋诗','song-poetry','','[]','咿呀喝擔禮筵開，無物聊堪表下懷。',32,'全唐诗/poet.song.169000.json','["咿呀喝擔禮筵開，無物聊堪表下懷。", "天遣腐儒人事省，三冬不放一錢來。"]'),
('1789e1e1-0221-4339-9948-05cde019289a','將有遠行走筆效江西體贈叔嘉','陳藻','宋','宋诗','song-poetry','','[]','我非無伴侶，少壯皆黄泉。',72,'全唐诗/poet.song.169000.json','["我非無伴侶，少壯皆黄泉。", "獨我成小巫，何人呼大禪。", "有時欲覽月，誰與爲飛仙。", "萌芽一二輩，世俗輒變遷。", "之子略可語，猶之火未燃。", "淮浙有同調，已辦青鞋錢。"]'),
('2f2d299a-ff11-4996-8261-dc38bc9b2908','適武林入延平界作','陳藻','宋','宋诗','song-poetry','','[]','人烟隨山窟，家家自生理。',48,'全唐诗/poet.song.169000.json','["人烟隨山窟，家家自生理。", "木杪插秧青，泉流仙杵起。", "開邊憶漢皇，航海通南鄙。", "黄昏更不愁，客舍連甍美。"]'),
('b9f8668a-be24-4855-84a4-bc0574f91aa5','建劍風土','陳藻','宋','宋诗','song-poetry','','[]','瞰水比連閣，開山上下廬。',48,'全唐诗/poet.song.169000.json','["瞰水比連閣，開山上下廬。", "四時篁有笋，兩岸鱔多魚。", "白苧男抽剝，新絲女捲舒。", "吾曹嗟跋涉，不合早看書。"]'),
('fffc43b1-3fac-48bd-9d73-3abd57640314','除夜過延平書所見','陳藻','宋','宋诗','song-poetry','','[]','東家兒婦試新衣，西家殘織方下機。',124,'全唐诗/poet.song.169000.json','["東家兒婦試新衣，西家殘織方下機。", "東家宰牲嫌不肥，西家呼兒去采薇。", "欲掩不掩留半扉，等彼良人心依依。", "小兒出門看落暉，平章去時霜未晞。", "須臾忽見扁舟飛，雙槳掝破清漣漪。", "抖擻裙兒牽兒上釣磯，手掩蓬鬢漸覺面生輝。", "遽呼良人何來遲，稅苗更管中限違，且買豚肩連夜歸。"]'),
('9e28574c-91fb-4551-9a8f-d89b00b1d715','過蓋竹祠','陳藻','宋','宋诗','song-poetry','','[]','人心有想自然靈，夢寐之間兆眹成。',32,'全唐诗/poet.song.169000.json','["人心有想自然靈，夢寐之間兆眹成。", "蓋竹山前英惠廟，暗中贏得四方名。"]'),
('febc8839-8d97-4341-9ab2-50d6d445e887','至浦城界聞武林失火而還','陳藻','宋','宋诗','song-poetry','','[]','幾年要入武林遊，今日中塗却罷休。',32,'全唐诗/poet.song.169000.json','["幾年要入武林遊，今日中塗却罷休。", "剩得紀行詩數首，前途有便是良謀。"]'),
('bde67564-7e51-4136-80d5-d1b9a402d13a','新村阻水','陳藻','宋','宋诗','song-poetry','','[]','前途聞火整裝回，又向新村值水災。',32,'全唐诗/poet.song.169000.json','["前途聞火整裝回，又向新村值水災。", "縱道人生爲客好，這般風味稍關懷。"]'),
('e6edfc0d-a783-4104-898c-283805c54ca4','看船','陳藻','宋','宋诗','song-poetry','','[]','迅步如何却放遲，貪看船子下灘奇。',32,'全唐诗/poet.song.169000.json','["迅步如何却放遲，貪看船子下灘奇。", "身貧也守垂堂戒，自覺年高命未知。"]'),
('533af5e7-90ea-4eab-bd7d-086544c7204f','由建陽抵浦城界遂歸崇下','陳藻','宋','宋诗','song-poetry','','[]','臨溪行盡却穿山，山盡依然出水間。',32,'全唐诗/poet.song.169000.json','["臨溪行盡却穿山，山盡依然出水間。", "崇下不貪歸去近，最憐山水要環看。"]'),
('805d9102-32c9-4008-92e0-97405c6ce185','浙漕不成還勉諸同行','陳藻','宋','宋诗','song-poetry','','[]','此去相期泰茹連，歸來鄉舉賽登天。',32,'全唐诗/poet.song.169000.json','["此去相期泰茹連，歸來鄉舉賽登天。", "秋風少壯猶堪想，人閙何由識老顛。"]'),
('cd71fd88-4fe6-4cfe-bfae-c4c89f52addf','擬別爲浙江之行','陳藻','宋','宋诗','song-poetry','','[]','兩浙彙緣未，聊窮福建回。',48,'全唐诗/poet.song.169000.json','["兩浙彙緣未，聊窮福建回。", "雪鹽晞黑土，朱李細黄梅。", "男子皆强鬭，村姑亦嬾腮。", "在家無活計，此路欠芒鞋。"]'),
('2c62e80d-11f3-4371-95a9-af7c9beb6d71','歸入古田界作','陳藻','宋','宋诗','song-poetry','','[]','步步谿山勝，橋亭建劍風。',48,'全唐诗/poet.song.169000.json','["步步谿山勝，橋亭建劍風。", "土宜辭荔子，村塢盡油桐。", "南店炊初滑，西舟石漸窮。", "豈知旬日外，便訪去時蹤。"]'),
('3616e74e-4af4-40a5-b02c-693a5ad849d4','同行歸急困倦不能詩','陳藻','宋','宋诗','song-poetry','','[]','行李放遲遲，周遭好拾詩。',48,'全唐诗/poet.song.169000.json','["行李放遲遲，周遭好拾詩。", "歸程催我急，脚力與神疲。", "來往成虛費，科名未有期。", "流傳堪膾炙，造物不相虧。"]'),
('816e3bfd-6dab-4b9e-9c7e-8713459fb4c4','觀漁船水碓有感','陳藻','宋','宋诗','song-poetry','','[]','水淋槽滿舂應響，人降槎登網自沉。',32,'全唐诗/poet.song.169000.json','["水淋槽滿舂應響，人降槎登網自沉。", "萬事低昂惟兩勢，乾坤闔闢箇中尋。"]'),
('58626372-c9e9-4240-b4cb-0d080c4c15a6','建劍板橋之什','陳藻','宋','宋诗','song-poetry','','[]','數里一板橋，亭欄各清楚。',72,'全唐诗/poet.song.169000.json','["數里一板橋，亭欄各清楚。", "長亭且百間，頻憇忘羈旅。", "人道賁乾坤，溪山失其阻。", "莊生達未充，無梁思太古。", "行行降復登，川廣湍流聚。", "急下看飛船，髣髴聞端午。"]'),
('e057540e-1b0d-4c2c-89e3-abdf74daa310','適武林途中作','陳藻','宋','宋诗','song-poetry','','[]','道途奔走固然非，閒坐真空度歲時。',32,'全唐诗/poet.song.169000.json','["道途奔走固然非，閒坐真空度歲時。", "誰解胸中無窒礙，兩隨造化不相譏。"]'),
('278e2c22-17f0-4443-a9ca-3338baa02367','道中酒壚','陳藻','宋','宋诗','song-poetry','','[]','千村亭榭酒旗揚，收盡山光與水光。',32,'全唐诗/poet.song.169000.json','["千村亭榭酒旗揚，收盡山光與水光。", "風物到來城郭閙，杖頭隨處去休忙。"]'),
('191b18c4-2084-4238-823c-0e9b3b602e77','夜宿溪館偶成','陳藻','宋','宋诗','song-poetry','','[]','世間多福是行人，到處風光屬此身。',32,'全唐诗/poet.song.169000.json','["世間多福是行人，到處風光屬此身。", "戲效堯夫吟數首，芒鞋楮蓋不知貧。"]'),
('74d418c9-ce2d-46a9-864b-2f04e4cd7316','夜宿延平水東二首  其一','陳藻','宋','宋诗','song-poetry','','[]','晚向溪西岸上行，溪東一带水爲城。',32,'全唐诗/poet.song.169000.json','["晚向溪西岸上行，溪東一带水爲城。", "兩山相距能多少，聽盡傍邊叫賣聲。"]'),
('1a1dcfd7-dad6-4a38-8e75-16aa7742fc2a','夜宿延平水東二首  其二','陳藻','宋','宋诗','song-poetry','','[]','浮橋暫拆阻狂瀾，懶問津船趁往還。',32,'全唐诗/poet.song.169000.json','["浮橋暫拆阻狂瀾，懶問津船趁往還。", "雙劍廟前酤酒喫，水西燈火水東看。"]'),
('d23a4ebc-2aa0-40b1-bd43-04d29985ef40','山泉','陳藻','宋','宋诗','song-poetry','','[]','山山迸出細泉流，更瀉高峰瀑布幽。',32,'全唐诗/poet.song.169000.json','["山山迸出細泉流，更瀉高峰瀑布幽。", "盡入大溪灘石裏，古今翻覆幾人舟。"]'),
('2ced70ea-ef17-457c-92e4-dac9b0ce60fb','建劍途中即事','陳藻','宋','宋诗','song-poetry','','[]','山化千般障，田敷百級階。',48,'全唐诗/poet.song.169000.json','["山化千般障，田敷百級階。", "林杉森似戟，灘水叫如雷。", "蔬笋常供膳，雞魚間有盃。", "吾鄉多食物，女慕白粳來。"]'),
('77454306-64c5-4d6c-8456-e236f8134ed1','田家婦','陳藻','宋','宋诗','song-poetry','','[]','蒔秧郎婿晚歸來，白面勻粧是乃妻。',32,'全唐诗/poet.song.169000.json','["蒔秧郎婿晚歸來，白面勻粧是乃妻。", "笑說福唐風俗惡，一田夫婦兩身泥。"]'),
('509bc179-edf1-40ad-a1c5-b370b9dfdb6a','過建劍書所聞見','陳藻','宋','宋诗','song-poetry','','[]','日夜灘聲急，相忘不閙人。',48,'全唐诗/poet.song.169000.json','["日夜灘聲急，相忘不閙人。", "兒孫猶棄水，農圃各文身。", "眼出平洋豁，眉逢大雨顰。", "谿藏山脇裏，遶水每逡巡。"]'),
('a7fd58f0-f2f2-4f59-84ce-ecd60bc18318','過建劍飲食','陳藻','宋','宋诗','song-poetry','','[]','賣食鮮雖少，開酤賤却醇。',24,'全唐诗/poet.song.169000.json','["賣食鮮雖少，開酤賤却醇。", "不知天地裏，何處享全珍。"]'),
('48521211-2a80-4190-ac56-2ac84017f83a','早下蓬嶺','陳藻','宋','宋诗','song-poetry','','[]','烟雲深裏日攀躋，嶺上宵眠雨電低。',32,'全唐诗/poet.song.169000.json','["烟雲深裏日攀躋，嶺上宵眠雨電低。", "清曉携筇遵下路，高峰對面與胸齊。"]'),
('aed43e3e-e196-42dc-b85c-73978a5b36f6','過江山作','陳藻','宋','宋诗','song-poetry','','[]','疊疊青山相送迎，遶溪幽樹萬蜩嗚。',32,'全唐诗/poet.song.169000.json','["疊疊青山相送迎，遶溪幽樹萬蜩嗚。", "我來場屋無聲字，也在神仙洞裏行。"]'),
('fa3a79cb-f87e-4b12-a3ad-60963d56b36b','自哂','陳藻','宋','宋诗','song-poetry','','[]','自小何曾識帝鄉，姓名却挂武林廂。',32,'全唐诗/poet.song.169000.json','["自小何曾識帝鄉，姓名却挂武林廂。", "祝融今歲爲災甚，亦費貲糧奔走忙。"]'),
('dad58fbd-8e90-4048-b64f-d53474e61fac','看潮','陳藻','宋','宋诗','song-poetry','','[]','何處飛來白鷺多，潮頭已減數分□。',32,'全唐诗/poet.song.169000.json','["何處飛來白鷺多，潮頭已減數分□。", "西旋衝却東流散，陣陣將軍引戰過。"]'),
('fa2fd382-ec14-4ea1-b4a3-563d17473c78','重陽臨安舟中作','陳藻','宋','宋诗','song-poetry','','[]','小船獨坐看平洋，歷歷登高舊事長。',32,'全唐诗/poet.song.169000.json','["小船獨坐看平洋，歷歷登高舊事長。", "戲把此身觀變化，今年無酒過重陽。"]'),
('09223bf9-97c3-4832-9cf3-7f442afba8c8','到平江遇雨次日見元鼎揚丈','陳藻','宋','宋诗','song-poetry','','[]','此來便擬見揚雄，席帽那堪走雨中。',64,'全唐诗/poet.song.169000.json','["此來便擬見揚雄，席帽那堪走雨中。", "漫刺修成還自袖，高門許入不能通。", "姓名多謝曾相問，糧屨從今未解窮。", "孟子休須嗔樂克，無車只等日輪東。"]'),
('1897c60f-4657-4809-8c9b-89558cf14f54','贈揚元鼎','陳藻','宋','宋诗','song-poetry','','[]','老泉早別閩中去，君在姑蘇臺下生。',64,'全唐诗/poet.song.169000.json','["老泉早別閩中去，君在姑蘇臺下生。", "每見鄉閭新到客，便尋香火舊來情。", "百年念祖心田孝，一種論文眼力明。", "歲晚已無場屋累，古書真味勝浮名。"]'),
('d07bea49-83cd-4518-81f3-0914e5a1cc11','平江清明書所聞見','陳藻','宋','宋诗','song-poetry','','[]','早插綠楊簷外去，晚携黄胖杖頭歸。',32,'全唐诗/poet.song.169000.json','["早插綠楊簷外去，晚携黄胖杖頭歸。", "富者幾家貧者衆，年年漸見賞人稀。"]'),
('dbaa6385-fe22-4248-a742-a89943389d1b','平江課賦待試混補蕭中立見之有相憐色因成四韻','陳藻','宋','宋诗','song-poetry','','[]','吾鄉猶自哂吾徒，易道東來話得無。',64,'全唐诗/poet.song.169000.json','["吾鄉猶自哂吾徒，易道東來話得無。", "幸有蔡邕過爨下，獨憐賈島作原夫。", "昌黎俗筆何曾短，永叔文衡不到輸。", "多少科名成底事，聊安飄泊老江湖。"]'),
('2c484275-3ab7-496c-97be-936b6c8ce25a','鄭簿約飲不赴以詩謝之','陳藻','宋','宋诗','song-poetry','','[]','浪遊人到北，佳節日穹南。',48,'全唐诗/poet.song.169000.json','["浪遊人到北，佳節日穹南。", "多謝棲鸞意，相期汎蟻酣。", "桃源迷去路，玉麈失清談。", "寄語鄭莊驛，難逃負約慚。"]'),
('b00a0f9d-ddf3-4adf-92a9-c7f9dc8edfcf','寄叔嘉叔平','陳藻','宋','宋诗','song-poetry','','[]','秋暮家書到武林，平江臘盡未聞音。',64,'全唐诗/poet.song.169000.json','["秋暮家書到武林，平江臘盡未聞音。", "兒添一巽還三艮，詩賦雙魚抵萬金。", "故國桃花應爛漫，北天梅蕊尚沉吟。", "橋門待補行新令，早趣行裝慰老心。"]'),
('d2ded887-9fe8-4f36-8ee6-a8c3b6b29006','讀李翰林詩','陳藻','宋','宋诗','song-poetry','','[]','杜陵尊酒罕相逢，舉世誰堪入此公。',32,'全唐诗/poet.song.169000.json','["杜陵尊酒罕相逢，舉世誰堪入此公。", "莫怪篇篇吟婦女，別無人物與形容。"]'),
('e41cf155-19b9-45ac-811b-f8e683e469b8','鄭主簿宅看雪訪梅聽僧撫琴偶成四韻倩蕭中立書之','陳藻','宋','宋诗','song-poetry','','[]','鵝毛散亂三朝雪，烏帽沾濡六出花。',64,'全唐诗/poet.song.169000.json','["鵝毛散亂三朝雪，烏帽沾濡六出花。", "梅吐萬枝香滿室，桐聽幾曲興乘槎。", "蓬萊借問仙仇覽，人世何妨醉釋迦。", "騷客平生揮字拙，蕭郎爲我走龍蛇。"]'),
('201712dc-a40b-47c9-994a-b0d5c6e7be87','呼盧','陳藻','宋','宋诗','song-poetry','','[]','年少相看百慮無，纔過旅邸便呼盧。',32,'全唐诗/poet.song.169000.json','["年少相看百慮無，纔過旅邸便呼盧。", "熱中更不知行李，却把黄粱付老夫。"]'),
('b23f91f3-c782-4987-ae49-c3743c2d6be1','賦京口蘇園','陳藻','宋','宋诗','song-poetry','','[]','揚子江邊犬吠村，蘇公宅畔蝶遊園。',64,'全唐诗/poet.song.169000.json','["揚子江邊犬吠村，蘇公宅畔蝶遊園。", "滄波對景標層塔，野市逃喧植外樊。", "亭榭高低隨卉木，門庭光彩屬兒孫。", "本朝名相青氈在，傍築書齋細討論。"]'),
('58834f38-8fa6-4a99-a506-abc36a75fe26','十月一日毗陵作','陳藻','宋','宋诗','song-poetry','','[]','聽得常州多菜色，到來市井亦安然。',32,'全唐诗/poet.song.169000.json','["聽得常州多菜色，到來市井亦安然。", "今朝正值焦糟節，車馬翩翩上墓田。"]'),
('758667b2-9db2-4d58-9ed3-1a6f2baa6c92','題東湖林氏所居','陳藻','宋','宋诗','song-poetry','','[]','遠來東望見門牆，到後西看不見洋。',32,'全唐诗/poet.song.169000.json','["遠來東望見門牆，到後西看不見洋。", "四面近山圍遶密，卜居如此合綿長。"]'),
('792ed86a-394c-4ef2-a2d1-12dc84f03e2a','平江送連亨叟赴省','陳藻','宋','宋诗','song-poetry','','[]','吾廬元在亮功坊，祖母東街家姓張。',320,'全唐诗/poet.song.169000.json','["吾廬元在亮功坊，祖母東街家姓張。", "舅翁官小先富强，有子破蕩開書堂。", "我隨表伯學文章，忽然好怪不好常。", "走師月魚舍莆陽，三山士子厭我狂。", "避我談吐如簸糠，北郭先君吳諱驤。", "姨弟余入京朝行，惟此二人見科場。", "期我前列每參商，面嗔考官識未長。", "我因隨老客他鄉，一錢亦欠真空囊。", "君出鳳池遊上庠，長洲適值日同房。", "我憶東街往事詳，得君情話勝瓊漿。", "百盃飲我何以償，欲餞一醉難賒嘗。", "雖然旅困顔無光，狂言欲發藉激昂。", "自矜到此亦可傷，末篇聽我送行裝。", "臨軒策試亮陰妨，首擢南宮丹桂芳。", "奉常格法經先揚，亞魁誰賦非君當。", "占牌前引歸騎忙，藍袍色映萱草蒼。", "美人二八宮樣粧，閥閲貴盛金多藏。", "愛君坦腹羲之床，紅紬扇鼓迎新郎。", "我還盡糶簞食糧，賽君痛飲尋歌娼。", "莫學淺夫唾肥羊，傲岸賀客峻門牆。"]'),
('03e3418b-0eea-467e-9721-d236e3114572','冬至寄行甫騰叔','陳藻','宋','宋诗','song-poetry','','[]','江浙羈棲怕雪霜，早年聽得晚年嘗。',64,'全唐诗/poet.song.169000.json','["江浙羈棲怕雪霜，早年聽得晚年嘗。", "生涯敗意多諳歷，節序隨緣少感傷。", "鴨肉餛飩看土俗，糯丸麻汁阻家鄉。", "二千里外尋君話，今日那堪各一方。"]'),
('08a42686-f658-42bc-8171-938a94f6e5e1','贈王叔平','陳藻','宋','宋诗','song-poetry','','[]','龜山與我說於潛，忽向平江問酒帘。',32,'全唐诗/poet.song.169000.json','["龜山與我說於潛，忽向平江問酒帘。", "何日龜山山下坐，共談江浙擘蠔粘。"]'),
('36d29b9f-864e-4f4e-a272-0ba8f9578a89','贈蕭中立','陳藻','宋','宋诗','song-poetry','','[]','相逢知己向非無，木未逢春一樣枯。',32,'全唐诗/poet.song.169000.json','["相逢知己向非無，木未逢春一樣枯。", "雙眼如君今有力，困窮那得到狂夫。"]'),
('12d17b31-3e5a-4a59-8356-86af1e8b65ec','平江臘月廿五夜作','陳藻','宋','宋诗','song-poetry','','[]','昨日宰豬家祭竈，今宵洗豆俗爲糜。',64,'全唐诗/poet.song.169000.json','["昨日宰豬家祭竈，今宵洗豆俗爲糜。", "燔柴夾水明如晝，截竹當階爆禦魑。", "故國賽還新歲願，老翁回憶幼年時。", "才高命薄天相戲，我亦剛腸不肯悲。"]'),
('5c15e51f-8859-448d-9940-9ec00fc66edb','除夜寄妻叔劉丈','陳藻','宋','宋诗','song-poetry','','[]','一自鄰居十二年，幾番爲客更從前。',64,'全唐诗/poet.song.169000.json','["一自鄰居十二年，幾番爲客更從前。", "入同飲酒柴爐畔，出看呼盧竹爆邊。", "鼓吹兒童隨處閙，庖厨烟火幾家眠。", "今宵莫恨輕離別，此地蹉跎豈偶然。"]'),
('b026f85e-8e4a-40a5-8d35-557c5a5155ad','元日平江作','陳藻','宋','宋诗','song-poetry','','[]','草粿京糰要賀年，玉融風俗不同天。',32,'全唐诗/poet.song.169000.json','["草粿京糰要賀年，玉融風俗不同天。", "元正卯醉長洲市，又憶浮家厭海鮮。"]'),
('fe65a57f-ec6d-4629-9732-3f0e118376b8','寄叔廣','陳藻','宋','宋诗','song-poetry','','[]','君在於潛未語歸，姑蘇我到事多違。',64,'全唐诗/poet.song.169000.json','["君在於潛未語歸，姑蘇我到事多違。", "母衰妹弱那能幹，婦拙兒頑孰可依。", "海近一天風漠漠，朔寒兩地雪霏霏。", "行裝稍辦還家急，年少應須慕虎闈。"]'),
('fa57da14-3105-4b4d-8b98-44465e82eb86','平江送王騰叔','陳藻','宋','宋诗','song-poetry','','[]','交情早已有何蕃，爲我揚聲梁楚間。',64,'全唐诗/poet.song.169000.json','["交情早已有何蕃，爲我揚聲梁楚間。", "秋暮姑蘇身自到，春來行李處猶難。", "十年爲客思親切，一第從人奏凱還。", "莫笑衰翁頻鑷鬢，雕蟲更擬入賢關。"]'),
('15b1e072-9cc3-40f9-b6f0-0e7c38c17b9b','別平江揚元鼎二首  其一','陳藻','宋','宋诗','song-poetry','','[]','染指鼀羹有子雲，乃能留客話皇墳。',32,'全唐诗/poet.song.169000.json','["染指鼀羹有子雲，乃能留客話皇墳。", "不知造化何慳甚，遣出平江要別君。"]'),
('cc46daee-b4a9-4f3a-89ce-87d7709e1735','別平江揚元鼎二首  其二','陳藻','宋','宋诗','song-poetry','','[]','黄菊來時正遶籬，真柑續到蟹偏肥。',32,'全唐诗/poet.song.169000.json','["黄菊來時正遶籬，真柑續到蟹偏肥。", "嘗罷河豚歸楫動，消梅初熟柳花飛。"]'),
('9183ebb9-e42f-448b-9f5b-3a729e6055da','壬戌重午於潛李氏作','陳藻','宋','宋诗','song-poetry','','[]','我來於潛縣，知有老聃族。',96,'全唐诗/poet.song.169000.json','["我來於潛縣，知有老聃族。", "王氣歇唐家，孫支散幽谷。", "居然多仕版，壁列登科錄。", "生兒皆可愛，大小芝蘭馥。", "大者初試歸，兩眼如明燭。", "小者纔讀書，應對機鋒速。", "他鄉客重午，菖蒲隨飲俗。", "老去卧家山，如夢開詩牘。"]'),
('405ffbc2-9dc7-4374-af1d-2701c575cbb5','土風','陳藻','宋','宋诗','song-poetry','','[]','錢塘直出過長洲，質直都無俗太浮。',32,'全唐诗/poet.song.169000.json','["錢塘直出過長洲，質直都無俗太浮。", "路入餘杭昌化境，土風淳樸似閩甌。"]'),
('d528d8e9-4213-40ae-a4e9-24df9ceae144','道中戲嘲朱叔緯','陳藻','宋','宋诗','song-poetry','','[]','畏日在征途，心涼不知苦。',84,'全唐诗/poet.song.169000.json','["畏日在征途，心涼不知苦。", "青山千百態，相契無相忤。", "芒鞋有至貴，道眼開方睹。", "行行遂吾性，萬物與同祖。", "殺雞固不忍，從衆那得阻。", "嫩菜送香粳，頗覺清肺腑。", "同游自疎懶，共飯何嗔怒。"]'),
('6585775b-a5cd-4dc8-8167-fd1fc26e79ee','詠快活三首  其一','陳藻','宋','宋诗','song-poetry','','[]','客舍寒窗月色明，紙衾展罷睡縱橫。',32,'全唐诗/poet.song.169000.json','["客舍寒窗月色明，紙衾展罷睡縱橫。", "傍人正是無聊景，怪我狂呼快活聲。"]'),
('84feb841-7cf5-493d-affd-a73ef3ea2b53','詠快活三首  其二','陳藻','宋','宋诗','song-poetry','','[]','小船密坐頸難伸，盡是饑寒不遇身。',32,'全唐诗/poet.song.169000.json','["小船密坐頸難伸，盡是饑寒不遇身。", "快活幾聲天地裏，相看疑我是顛人。"]'),
('cde12ab0-e054-4c24-a86b-67137d58dd7e','詠快活三首  其三','陳藻','宋','宋诗','song-poetry','','[]','武林試罷過仙霞，行路崎嶇各憶家。',32,'全唐诗/poet.song.169000.json','["武林試罷過仙霞，行路崎嶇各憶家。", "怪問老夫何所喜，飄摇飛舞似楊花。"]'),
('aa4410a1-c064-4091-abee-04fee4f8f1bb','歸入福建界作','陳藻','宋','宋诗','song-poetry','','[]','行旅名雖惡，遊山興亦深。',48,'全唐诗/poet.song.169000.json','["行旅名雖惡，遊山興亦深。", "酒無官榷價，松有道傍陰。", "鵝鴨谿谿浴，蜩蟬樹樹吟。", "逍遥儔侶怪，駡我失常心。"]'),
('0f70618f-59a5-47a3-9188-6f49e5bf14f7','甲子應舉','陳藻','宋','宋诗','song-poetry','','[]','場屋悠悠四十年，這回弄鏡已華顛。',64,'全唐诗/poet.song.169000.json','["場屋悠悠四十年，這回弄鏡已華顛。", "也知枯木春稀到，却想寒灰火復燃。", "高尚難攀生有累，往來莫厭喜隨緣。", "傷心自是離鄉客，幾度因歸上墓田。"]'),
('8eace7e2-5de6-488a-8e37-d9460c84bb27','子從生兒席上作','陳藻','宋','宋诗','song-poetry','','[]','我身如浮雲，出入無程期。',180,'全唐诗/poet.song.169000.json','["我身如浮雲，出入無程期。", "別君夫與婦，戲約歸來時。", "夫問婦何娠，我卜生男兒。", "出房拜阿姑，我得酣酒巵。", "遊脫城山屐，香聞漁市炊。", "雖無童僕遣，若有音信知。", "回思一紀先，君吟弄瓦詩。", "亦開滿月筵，我行適值之。", "親交信有緣，飲啄主者誰。", "前言成讖兆，笑訝因陳詞。", "詩法久無辭，請繼關雎爲。", "十九成數終，陰偶配陽奇。", "晉文在外還，霸業一朝基。", "伉儷今幾秋，倒指恰如茲。", "造化安排生，必也非凡兒。"]'),
('ea720109-974c-4852-a7c2-34da63f677fb','與景晦','陳藻','宋','宋诗','song-poetry','','[]','鄉閭好事喜人傳，聞說當初賦斷弦。',64,'全唐诗/poet.song.169000.json','["鄉閭好事喜人傳，聞說當初賦斷弦。", "得暇灌花花造化，有方種藥藥神仙。", "忽看脚下相隨處，又是人間別樣天。", "數畝南園誰更管，任他荒草欲平肩。"]'),
('a86e5bd4-6645-4faa-ba73-07a1a25fa92f','丘叔喬八十','陳藻','宋','宋诗','song-poetry','','[]','樂欲永千年，愁難禁一夕。',108,'全唐诗/poet.song.169000.json','["樂欲永千年，愁難禁一夕。", "大家於此且貪生，八十孩兒題向額。", "今朝門下慶相符，坐有繡衣爲上客。", "況乎二弟古稀餘，左酬右勸皆精力。", "阿婆纔小三五秋，卜婚日者神無敵。", "燈火鰲山弧矢晨，姓名往往登仙籍。", "借問人間見幾多，答云造化慳斯席。"]'),
('638c0898-26a9-4607-9ca8-9b9f3a8d41a5','丘子中生日','陳藻','宋','宋诗','song-poetry','','[]','名卿先達陳君舉，年將三十登州補。',96,'全唐诗/poet.song.169000.json','["名卿先達陳君舉，年將三十登州補。", "袖中有啟謝主文，爲緣場屋新推許。", "斯翁自小學雕蟲，性情樸直浮誰語。", "旗鈴絕不到門庭，却有兒郎能戰取。", "高名前日掛縣庠，引此壽觴來獻父。", "莫嫌小勝未當論，知是敘封初步武。"]'),
('3752811d-3f1a-4532-a07b-67a585db4cc5','中元連宿竹園劉叔嘉宅','陳藻','宋','宋诗','song-poetry','','[]','朝朝風雨過中元，已熟之禾未易存。',32,'全唐诗/poet.song.169000.json','["朝朝風雨過中元，已熟之禾未易存。", "正是忙時人却暇，且偷佳節倒芳尊。"]'),
('821ab0ae-5b9a-4cee-a266-85e1dacb49f5','仲秋過盧北山子俞嘗新醖作','陳藻','宋','宋诗','song-poetry','','[]','白秫新收釀得紅，洗鍋吹火煮油葱。',32,'全唐诗/poet.song.169000.json','["白秫新收釀得紅，洗鍋吹火煮油葱。", "莫嫌傾出清和濁，勝是嘗來辣且濃。"]'),
('208ad9ba-e915-4291-b66a-c0d913b3c034','過盧北山','陳藻','宋','宋诗','song-poetry','','[]','西成課罷赴羣居，中路誰家倦憇予。',32,'全唐诗/poet.song.169000.json','["西成課罷赴羣居，中路誰家倦憇予。", "恰見主人方早起，簷前觀我所爲書。"]'),
('ee0c7a31-c0bd-4c8c-9c24-54c757ab11ea','盧子俞幼孫晬日','陳藻','宋','宋诗','song-poetry','','[]','我與良翁似有緣，命名與述戰龍天。',32,'全唐诗/poet.song.169000.json','["我與良翁似有緣，命名與述戰龍天。", "事忙不記垂弧旦，恰到渠家遇晬筵。"]'),
('4fc5cb1b-eeba-4437-b5c1-6c4b59417c0b','小除過盧子俞作','陳藻','宋','宋诗','song-poetry','','[]','今夜人間是小除，歸途迂曲訪君居。',32,'全唐诗/poet.song.169000.json','["今夜人間是小除，歸途迂曲訪君居。", "村深事簡携杯外，閒把詩篇細卷舒。"]'),
('74ab47c1-2bc5-4a33-8618-fc83153acb6b','賀劉叔猷爲用甫納婦','陳藻','宋','宋诗','song-poetry','','[]','生平小我一全干，十五字問揚雄難。',96,'全唐诗/poet.song.169000.json','["生平小我一全干，十五字問揚雄難。", "納幣孟冬猶丱角，記得迎長方祀冠。", "倒指新春五十七，先春女嫁男婚畢。", "采真園裏東風回，主公無事花添色。", "少貧嗟我老更貧，塵累何時是了人。", "況且郎君賦語神，使我見兒祗欲嗔。"]'),
('eaad11ff-7228-44ed-95aa-29a80e41eb93','百丈書懷寄丘子深','陳藻','宋','宋诗','song-poetry','','[]','離騷休唱逐臣愁，此曲思君可寄不。',64,'全唐诗/poet.song.169000.json','["離騷休唱逐臣愁，此曲思君可寄不。", "百歲都來如過客，一生大半似幽囚。", "那堪泣玉空懷寶，剛道雕蟲勝飯牛。", "山館無聊春睡美，日高丈五正蒙頭。"]'),
('b5aebf5a-912c-4826-9724-aa6def897ff2','紅泉明日還福清作','陳藻','宋','宋诗','song-poetry','','[]','獨坐無聊日已西，忽經蒜嶺過漁溪。',32,'全唐诗/poet.song.169000.json','["獨坐無聊日已西，忽經蒜嶺過漁溪。", "一枝何處空歸去，却整行裝羨鳥栖。"]'),
('8e8d5bfb-3ae1-4c14-9afa-a0b094a20b22','誦中庸','陳藻','宋','宋诗','song-poetry','','[]','端把中庸誦一篇，眼前神物頓森然。',32,'全唐诗/poet.song.169000.json','["端把中庸誦一篇，眼前神物頓森然。", "塵埃掃盡無他慮，儘管高樓自在眠。"]'),
('c7da7c13-a9c7-40c4-8101-fbad460ae602','梅','陳藻','宋','宋诗','song-poetry','','[]','野水橋邊幾樹梅，歲寒款款向人開。',64,'全唐诗/poet.song.169000.json','["野水橋邊幾樹梅，歲寒款款向人開。", "精神別带陽春到，造化勻分臘月來。", "滿眼松筠皆臭味，一天霜雪是胚胎。", "看花遠地身還老，買屋何年手自栽。"]'),
('8e433e5e-0e34-41a8-9641-05b3b87550d7','城山','陳藻','宋','宋诗','song-poetry','','[]','雲霧成佳景，天明又幾回。',72,'全唐诗/poet.song.169000.json','["雲霧成佳景，天明又幾回。", "忽携詩句入，別放畫圖開。", "遠樹沉如立，行歌去似來。", "小舡衝雨過，高柳接湖栽。", "月自孤青月，臺呼怪石臺。", "故園無夢想，近擬築巖隈。"]'),
('4ea7ba28-1f1e-48f7-94d5-c59c15dfba23','壺山二首  其一','陳藻','宋','宋诗','song-poetry','','[]','萬古凌空孤拄軒，百年那得此身存。',64,'全唐诗/poet.song.169000.json','["萬古凌空孤拄軒，百年那得此身存。", "醉醒欲掃雲開眼，興逸誰歸月掩門。", "走遍莆陽隨處有，遊觀天下見人論。", "細瞻五岳神來舍，旁聳諸山勢更尊。"]'),
('e3a9c3f1-1719-4963-92f2-e3992113625a','壺山二首  其二','陳藻','宋','宋诗','song-poetry','','[]','遠看顛狂近轉迷，有才老死便幽棲。',64,'全唐诗/poet.song.169000.json','["遠看顛狂近轉迷，有才老死便幽棲。", "咄嗟萬里雲彌合，昏黑孤城日正西。", "北極河通千澗近，中央天接兩傍低。", "頓令病眼還蘇醒，誰向他山更品題。"]'),
('811e912f-8feb-4c0c-9bf2-ff489e5e79e0','虎溪','陳藻','宋','宋诗','song-poetry','','[]','四圍山木合，百磴屋簷重。',48,'全唐诗/poet.song.169000.json','["四圍山木合，百磴屋簷重。", "古穴成幽井，疎林散曉峰。", "響泉那更月，啼鳥此無冬。", "臺上朝朝看，天邊處處供。"]'),
('ff0cb254-aad7-4c98-ad8a-3eb7aff5aeff','過延平書懷','陳藻','宋','宋诗','song-poetry','','[]','幾程便要買歸舟，身在延平已倦遊。',32,'全唐诗/poet.song.169000.json','["幾程便要買歸舟，身在延平已倦遊。", "但有菜羹供祭禮，人生何必到融州。"]'),
('639d9b0f-da09-40c9-aad7-dabcbe92961f','紀夢','陳藻','宋','宋诗','song-poetry','','[]','自從弱冠爲游子，玉融丹井壺山市。',271,'全唐诗/poet.song.169000.json','["自從弱冠爲游子，玉融丹井壺山市。", "哦詩不用著工夫，已謫牂牁四千里。", "柳侯未五十，羅池作刺史。", "翰苑失詞華，蛟龍怨泥滓。", "我今四十貧無官，六合飄零到融水。", "來時三宿柳城村，再拜前賢我如此。", "才卑何怨嗟，且述西征始。", "奔走豈吾心，跬步思桑梓。", "江右湖湘抵桂林，青山爭獻雙眸美。", "青山縱好興不生，萬斛羈愁懷抱裏。", "夜長正好夢，征夫何早起。", "合眼見故鄉，開眼知行李。", "交朋無恨別，親戚常孔邇。", "天明同登途，薄暮共棲止。", "一更春酒熟，街頭逢伯氏。", "二更桑麻園，仲氏談生理。", "三更四更，平時往還人，見我早歸呼我喜。", "五更茅店寒，鄰鷄振吾耳。", "忽驚身在竹床眠，天外七閩何處是，隻淚汪汪沾布被。"]'),
('a8f95e3c-0c57-472c-81d5-65f13bfc5036','過臨川懷劉氏弟兄','陳藻','宋','宋诗','song-poetry','','[]','臨川幾日到長沙，聞道黔南路更賒。',32,'全唐诗/poet.song.169000.json','["臨川幾日到長沙，聞道黔南路更賒。", "行見一村籬落好，誰家此住憶君家。"]'),
('903b1cca-54cd-498e-9afb-21f948810416','過新喻','陳藻','宋','宋诗','song-poetry','','[]','四顧茫茫水接天，遠山如卧白雲邊。',32,'全唐诗/poet.song.169000.json','["四顧茫茫水接天，遠山如卧白雲邊。", "馬頭忽看孤峰起，錯喜鄉關是目前。"]'),
('6735b911-147a-47ae-ba90-a82abf7c065c','宿衡陽','陳藻','宋','宋诗','song-poetry','','[]','一見行人一下車，行人都說異鄉居。',32,'全唐诗/poet.song.169000.json','["一見行人一下車，行人都說異鄉居。", "別來閩嶺三千里，夜宿衡陽夢寄書。"]'),
('4bc817b1-595e-4924-a949-d4ea66a69c7a','自哂','陳藻','宋','宋诗','song-poetry','','[]','且安愚分住天涯，休問明朝買馬回。',32,'全唐诗/poet.song.169000.json','["且安愚分住天涯，休問明朝買馬回。", "濠上有人留此老，去年不到異鄉來。"]'),
('e0620055-b44f-44f6-829d-ed0bd72d7e47','題清暉樓','陳藻','宋','宋诗','song-poetry','','[]','茲樓名郡郭，何處別林泉。',48,'全唐诗/poet.song.169000.json','["茲樓名郡郭，何處別林泉。", "一水遥通蜀，千崖利插天。", "鸕鷀晴舞雪，桑柘月生烟。", "欲醉囊羞澀，愁看度兩年。"]'),
('cd8b03cd-997d-434a-baf1-820f7041694a','融州西樓望山','陳藻','宋','宋诗','song-poetry','','[]','西樓門外數峰青，合看芙蓉展看屏。',32,'全唐诗/poet.song.169000.json','["西樓門外數峰青，合看芙蓉展看屏。", "回首東郊晴日出，千人躍馬上天庭。"]'),
('47c3569f-ee48-4598-be24-01ed010e5650','融州除夜寄福清劉九兄','陳藻','宋','宋诗','song-poetry','','[]','臘月牂牁三十日，相思覓句上譙樓。',32,'全唐诗/poet.song.169000.json','["臘月牂牁三十日，相思覓句上譙樓。", "遥知今夜柴爐會，說我無家更遠遊。"]'),
('6bd76aaf-bd87-47f7-b257-2beac09fc7e9','題融州城樓','陳藻','宋','宋诗','song-poetry','','[]','除却譙樓環廨舍，蕭條市井客懷悲。',64,'全唐诗/poet.song.169000.json','["除却譙樓環廨舍，蕭條市井客懷悲。", "高高下下山無數，淺淺深深江有時。", "大布紅裙猺女著，半規白扇野人持。", "城中昨夜亡羊豕，聞得誰家虎入籬。"]'),
('f33b7c5b-fb46-430b-b115-2af11cbdac0f','融州望鄉','陳藻','宋','宋诗','song-poetry','','[]','故國來來八十程，登樓迷却桂州城。',32,'全唐诗/poet.song.169000.json','["故國來來八十程，登樓迷却桂州城。", "望鄉不分千山隔，上趁金烏日裏行。"]'),
('0d51b50b-9a3c-403d-afa5-7759c953517f','東樓夜望','陳藻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','愁來無酒話無人，明月樓中萬里身。',32,'全唐诗/poet.song.169000.json','["愁來無酒話無人，明月樓中萬里身。", "說與長江流水去，汝今穿海入吾閩。"]'),
('91c96c16-3b9f-49a3-891d-760883a17352','客中書事','陳藻','宋','宋诗','song-poetry','','[]','千載蠻風尚有存，此來聞見不堪論。',64,'全唐诗/poet.song.169000.json','["千載蠻風尚有存，此來聞見不堪論。", "豬膏澤髮湘南婦，牛勃塗門嶺右村。", "行客下床調瘴藥，吏人抱甕灌蔬園。", "豈無佳麗堪娛目，別有淒涼只斷魂。"]'),
('7dd8ba32-9ef0-4e55-95e1-127f7cd60808','秋雨','陳藻','宋','宋诗','song-poetry','','[]','梅花五鼓城頭角，吹向愁人枕前落。',72,'全唐诗/poet.song.169000.json','["梅花五鼓城頭角，吹向愁人枕前落。", "一聲心膽碎無餘，三聲兩聲那更作。", "天明起坐壁爲鄰，簷外垂垂秋雨脚。", "雨脚强，鬢毛弱，若爲一滴白幾莖，縱使赤松猶老却。"]'),
('397a7b26-e7ba-4041-9434-77bbb3b095e8','冬日','陳藻','宋','宋诗','song-poetry','','[]','冬日何曾短，寒更有許長。',48,'全唐诗/poet.song.169000.json','["冬日何曾短，寒更有許長。", "紅爐那作伴，白髮早還鄉。", "舊酒誰賒飲，新詩自寫藏。", "故人思不見，獨遶野梅香。"]'),
('f405d3e6-d054-4972-93b6-6d064e2374a8','冬日融州絕句','陳藻','宋','宋诗','song-poetry','','[]','四隻漁船叩板木，幾家茅屋長兒孫。',32,'全唐诗/poet.song.169000.json','["四隻漁船叩板木，幾家茅屋長兒孫。", "天寒水淺江成路，地僻人稀郭賽村。"]'),
('42660ebd-0d1d-45c1-8173-90fa9dba196b','東寧初夏得叔達書自都下來言去秋與鄉薦尋聞下第想就試上庠賦詩寄之','陳藻','宋','宋诗','song-poetry','','[]','天涯無伴只思渠，知在杭州有故廬。',64,'全唐诗/poet.song.169000.json','["天涯無伴只思渠，知在杭州有故廬。", "閩嶺秋空翔一鶚，融江夏日煮雙魚。", "合看髫齕登科去，却有髭鬚落第初。", "大學好還元祐體，松峬莫便賦歸歟。"]'),
('ff35c1e1-58bd-41aa-ac7f-9b0974263d7e','余融州生日','陳藻','宋','宋诗','song-poetry','','[]','牂牁相遇說長年，一在公堂一洞天。',32,'全唐诗/poet.song.169000.json','["牂牁相遇說長年，一在公堂一洞天。", "清遠使君黄石老，西周柱史混元仙。"]'),
('8bfaa803-3f3a-46ea-8a42-1e4d75c071f1','春日','陳藻','宋','宋诗','song-poetry','','[]','獨上譙樓日一迴，春風桃李滿城開。',32,'全唐诗/poet.song.169000.json','["獨上譙樓日一迴，春風桃李滿城開。", "狂夫欲語無人聽，呼取閑雲共酒盃。"]'),
('68eecda7-c7b6-4592-99b7-abbfce868ab4','融州東樓','陳藻','宋','宋诗','song-poetry','','[]','燈火無蠻市，江山遶暗城。',48,'全唐诗/poet.song.169000.json','["燈火無蠻市，江山遶暗城。", "漁舟關柝響，野燒日頭生。", "雨闊千村暝，天高一月行。", "夜樓多好景，都不礙陰晴。"]'),
('8c170301-a8ea-47d3-9068-9c7338e4d27a','別融州','陳藻','宋','宋诗','song-poetry','','[]','兩年爲客憶鄉關，樽酒何時別此間。',32,'全唐诗/poet.song.169000.json','["兩年爲客憶鄉關，樽酒何時別此間。", "今日移舟出城市，多情却戀眼中山。"]'),
('0bd68504-aef3-432a-bd92-18015bf70724','謁羅池廟','陳藻','宋','宋诗','song-poetry','','[]','平生不作羅池夢，今日還來謁柳祠。',32,'全唐诗/poet.song.169000.json','["平生不作羅池夢，今日還來謁柳祠。", "忽憶故人曾得句，鬼神先我七年知。"]'),
('2bdc7363-c4ea-4e85-a316-3ff93249641b','真仙洞','陳藻','宋','宋诗','song-poetry','','[]','洞裏清溪可泛舟，入觀洞府出高丘。',64,'全唐诗/poet.song.169000.json','["洞裏清溪可泛舟，入觀洞府出高丘。", "老聃尸解今還在，黄帝生前有此不。", "滴乳解添無數巧，携燈何用不曾幽。", "乾坤自大人身小，拳石空中作勝遊。"]'),
('d3385862-3300-438a-b1ad-b9864acc866b','寄吳提幹','陳藻','宋','宋诗','song-poetry','','[]','不見河南二十年，若爲再拜畫堂前。',64,'全唐诗/poet.song.169000.json','["不見河南二十年，若爲再拜畫堂前。", "來尋八桂瓜期滿，歸訪蒼梧蓮幕遷。", "幸對夫人如母在，喜看令子似公賢。", "府僚共約黄花去，業已還鄉種薄田。"]'),
('dee05162-4923-4aea-a8ab-97af8f1c33cf','別王司法','陳藻','宋','宋诗','song-poetry','','[]','維舟江岸偶相鄰，還與吾翁是故人。',64,'全唐诗/poet.song.169000.json','["維舟江岸偶相鄰，還與吾翁是故人。", "顔貌不知今日改，姓名方記舊時親。", "少年壯筆生應貴，白髮青衫今尚貧。", "一笑羊城聊適意，明朝話別兩酸辛。"]'),
('5580b15a-ee30-4a1e-8865-911703229a39','題靜江','陳藻','宋','宋诗','song-poetry','','[]','桂林多洞府，疑是館群仙。',24,'全唐诗/poet.song.169000.json','["桂林多洞府，疑是館群仙。", "四野皆平地，千峰直上天。"]'),
('93879371-13c7-4ef6-af12-89a95dca9d9e','舟行','陳藻','宋','宋诗','song-poetry','','[]','衆流江漸闊，百怪石如生。',24,'全唐诗/poet.song.169000.json','["衆流江漸闊，百怪石如生。", "錯聽人聲閙，空岩答槳鳴。"]'),
('327f668b-ba1a-405b-bc7b-bac150d6fa89','過桂平','陳藻','宋','宋诗','song-poetry','','[]','嶺南太半尚鴻荒，城壁空堅草莽長。',32,'全唐诗/poet.song.169000.json','["嶺南太半尚鴻荒，城壁空堅草莽長。", "忽到潯州江上飲，喜他風物近吾鄉。"]'),
('de49df11-8e9a-41b9-b9cc-d6317dc303ff','過象州','陳藻','宋','宋诗','song-poetry','','[]','都無一物作生涯，坊巷蕭條有幾家。',32,'全唐诗/poet.song.169000.json','["都無一物作生涯，坊巷蕭條有幾家。", "料得寒梅應悵恨，滿城開作寂寥花。"]'),
('0a0af0a6-8423-4e3b-8b2e-afd5108f125c','過海豐','陳藻','宋','宋诗','song-poetry','','[]','梅花結子已紅青，歸路猶愁一月程。',32,'全唐诗/poet.song.169000.json','["梅花結子已紅青，歸路猶愁一月程。", "忽聽兒音鄉語熟，不知方到海豐城。"]'),
('7ac9891f-599b-4010-b1a5-3aa129fb5f29','除夜憶福清塘東諸友','陳藻','宋','宋诗','song-poetry','','[]','去年除夜作吟思，除夜今年久別離。',32,'全唐诗/poet.song.169000.json','["去年除夜作吟思，除夜今年久別離。", "幸喜此身貧却健，柴爐更隔一年期。"]'),
('746b6d0f-b3ce-4a5b-a32a-d0ca92519375','喜次漳浦','陳藻','宋','宋诗','song-poetry','','[]','江灘已過瘴烟收，野象逢人自縮頭。',32,'全唐诗/poet.song.169000.json','["江灘已過瘴烟收，野象逢人自縮頭。", "官路十程如砥去，舉杯先賀到漳州。"]'),
('09810c75-5669-4578-9510-3894573e5195','次韻林子衡惡夢之什','陳藻','宋','宋诗','song-poetry','','[]','昔人賡詩不賡韻，韻恐不與事相關。',64,'全唐诗/poet.song.169000.json','["昔人賡詩不賡韻，韻恐不與事相關。", "後人未得詩中趣，賡得韻來誇甚難。", "相逢索我一夢吟，我欲可以呈孔顔。", "若要夜間無惡夢，朝朝心鏡好頻看。"]'),
('df152187-ab6a-4f19-8459-af5bba4bd70b','憎吏行','陳藻','宋','宋诗','song-poetry','','[]','人逢胥吏面，唾欲擣其胸。',120,'全唐诗/poet.song.169000.json','["人逢胥吏面，唾欲擣其胸。", "傷哉彼何罪，造化生蛇蟲。", "田宅世無有，妻孥腹屢空。", "人家詞訟起，踴躍時命通。", "天性本懷惡，煎熬仍怕窮。", "得錢即歡喜，道理那能公。", "州府珍寶饋，縣官筵席供。", "吏贓黥且死，州縣多寬容。", "三尺既虛設，民冤訴高穹。", "高穹不垂耳，官吏屋俱豐。"]'),
('c16c37a1-a6f6-4ce0-a056-614ee1285449','訟田行','陳藻','宋','宋诗','song-poetry','','[]','樂軒世俗文不工，場屋此生難遭逢。',372,'全唐诗/poet.song.169000.json','["樂軒世俗文不工，場屋此生難遭逢。", "百年餓死真可惜，人命只在田畝中。", "遠行直到西融州，客裝收拾來歸休。", "江灘象窟百無憂，却陷人心危險頭。", "海上曾琚本亭戶，日在公門騁詞訴。", "下鄉老嫗何大娘，小郎遺業孤女當。", "主婚老嫗貪聘資，將女嫁與曾琚兒。", "女將三十年及格，依法賣田何所疑。", "樂軒信己因信人，豈識兩家俱不仁。", "曾琚文約只要錢，錢被何偷反訟田。", "牙緋縣宰坐縣亭，官是堂除豈不精。", "老胥代判爲縱橫，知縣依書那得平。", "却監媒人宋五九，備錢還我錢何有。", "提點八州刑獄使，重念八州冤曲事。", "許人越訴榜通衢，有狀不禁攔軺車。", "軺車曉出平旦歸，千人百人周四圍。", "車中呼入使者笑，觀感人多涕沾衣。", "笑者笑何意，吾不聰明渠不至。", "感者泣何爲，赴愬容易殊曩時。", "文書山積難稽考，胥吏依前顔色好。", "樂軒辭說如直弦，外臺判下不改前。", "州府監錢何嫗還，吏人掌客生艱難。", "因循六十日，公事無了畢。", "胥徒去復來，索酒需財食。"]'),
('72e28c8a-b7ce-49ab-b6f9-60073415f5d4','阿凡初冠覓詩','陳藻','宋','宋诗','song-poetry','','[]','後人猶識前賢子，祇是迺翁文字行。',32,'全唐诗/poet.song.169000.json','["後人猶識前賢子，祇是迺翁文字行。", "爲報阿凡今既冠，莫教只託網山名。"]'),
('3281239b-65d2-44ab-98d9-6b89e2fa8c7b','愁夢','陳藻','宋','宋诗','song-poetry','','[]','天作閒愁催我老，夜長猶自怕天明。',32,'全唐诗/poet.song.169000.json','["天作閒愁催我老，夜長猶自怕天明。", "日中料想先成夢，白上髭鬚數十莖。"]'),
('499cdc8b-c192-4c76-a22a-f9d775946f1e','戲題宏仲飲亭酒肆','陳藻','宋','宋诗','song-poetry','','[]','老去雖貧有酒壚，秫田自種暫時沽。',32,'全唐诗/poet.song.169000.json','["老去雖貧有酒壚，秫田自種暫時沽。", "閨中不解爲慳婦，猶問劉郎燕客無。"]'),
('e124076f-c086-473b-a93c-789d16f58b8b','黄檗香爐峰','陳藻','宋','宋诗','song-poetry','','[]','黄檗寺前猶突兀，祖師塔外別安排。',32,'全唐诗/poet.song.169000.json','["黄檗寺前猶突兀，祖師塔外別安排。", "香爐好是中央小，無數峰巒拱揖來。"]'),
('b4cf355c-4985-486b-bddd-a2c25cdcd4cb','叔達及第書走筆答之','陳藻','宋','宋诗','song-poetry','','[]','君在臨安落第時，我從融水寄君詩。',128,'全唐诗/poet.song.169000.json','["君在臨安落第時，我從融水寄君詩。", "君歸莆陽爲薦首，我到漁溪餞君酒。", "龍飛唱第才俊多，健筆如君非甲科。", "終然學問有知己，姓名不記今卑矣。", "人靈世上如豺虎，我行厄運遭其侮。", "白頭膠膝變須臾，一面那知深肺腑。", "書報青山七月還，開書已覺開愁顔。", "何時七月聽君話，話我年來路轉囏。"]'),
('3872bf7d-eef3-49e6-8ed4-7f18d257a687','擬卜居','陳藻','宋','宋诗','song-poetry','','[]','向來爲客愛塘村，幾度天邊入夢魂。',32,'全唐诗/poet.song.169000.json','["向來爲客愛塘村，幾度天邊入夢魂。", "恰到塘村心已懶，不知何處立柴門。"]'),
('1e5bc2d0-f68a-4b5d-977c-9dc1ed957f39','冬日南谷讀書','陳藻','宋','宋诗','song-poetry','','[]','列岫開平野，修牆隠密林。',48,'全唐诗/poet.song.169000.json','["列岫開平野，修牆隠密林。", "暗泉聞雨響，寒日覺冬深。", "眼底孤村近，雲邊小樹侵。", "何須錢買屋，空寺足閑吟。"]'),
('580eba01-2854-42e3-be4b-52c3c8094d9a','夜行偶成','陳藻','宋','宋诗','song-poetry','','[]','脚踏橫塘外氏村，忽瞻北極動歸魂。',32,'全唐诗/poet.song.169000.json','["脚踏橫塘外氏村，忽瞻北極動歸魂。", "貧姑生理凋零盡，八十無兒住此門。"]'),
('da7b8e75-3ebe-4e0f-98df-bd36aaf54ef2','汝永寓大湖以歲歉還舍邂逅喜能爲具賦詩贈之','陳藻','宋','宋诗','song-poetry','','[]','不到蓬窗恰一年，空村作客遇饑還。',32,'全唐诗/poet.song.169000.json','["不到蓬窗恰一年，空村作客遇饑還。", "相逢喜有三餐色，況是烹魚送酒船。"]'),
('f37ee353-57e2-4f92-9c10-08ec34e04b69','次韻吳推官見贈經理達翁家事之什','陳藻','宋','宋诗','song-poetry','','[]','紅泉風俗如鄒魯，易合西華數載盟。',64,'全唐诗/poet.song.169000.json','["紅泉風俗如鄒魯，易合西華數載盟。", "莫把肝腸隨世變，常分儋石作人情。", "哦詩豈詫文章好，立教先須義利明。", "戲問苦廬余子畏，論交何重與何輕。"]'),
('9f18a68c-958b-4f4a-a1ab-0d0118ee977d','別舅氏','陳藻','宋','宋诗','song-poetry','','[]','表裏真容拜跪妨，老夫拱揖謾焚香。',64,'全唐诗/poet.song.169000.json','["表裏真容拜跪妨，老夫拱揖謾焚香。", "凋盡雙親一輩行，兩世能留獨渭陽。", "劣甥今年七十五，花甲戊辰先戊午。", "若非相見皆貧苦，多少壚邊好歌舞。"]'),
('c85b89e3-ecbd-4225-a111-1e579006f8ef','贈故鄉人','陳藻','宋','宋诗','song-poetry','','[]','我家已破出他鄉，如連如卓方阜昌。',64,'全唐诗/poet.song.169000.json','["我家已破出他鄉，如連如卓方阜昌。", "豈料囊金隨後散，一齊開鋪鬻文章。", "我今濱死祗如許，二友猶堪望軒翥。", "從頭借問向來誰，十室九人非舊主。"]'),
('46ec0b71-acf7-49e0-b1ea-dd62aeeca544','憶母','陳藻','宋','宋诗','song-poetry','','[]','蕭小八娘棄我去，我生方始十三年。',32,'全唐诗/poet.song.169000.json','["蕭小八娘棄我去，我生方始十三年。", "如今七十零單五，生死途分竟杳然。"]'),
('9df6793d-e114-460d-bd8c-6e169380c99b','客中夏夜即事','陳藻','宋','宋诗','song-poetry','','[]','上綴珠璣爲屋蓋，旁堆翡翠作屏風。',32,'全唐诗/poet.song.169000.json','["上綴珠璣爲屋蓋，旁堆翡翠作屏風。", "醉翁不見身貧賤，卧向凉飈清露中。"]'),
('7aa85a1a-4bba-46b3-81a4-16222b554dea','久爲塵事關懷因成一絕','陳藻','宋','宋诗','song-poetry','','[]','讀書得趣是神仙，未若神仙斷火烟。',32,'全唐诗/poet.song.169000.json','["讀書得趣是神仙，未若神仙斷火烟。", "解把老夫埋俗窟，多時不放上青天。"]'),
('06fc593e-d588-4448-a10e-28fb86606688','戲簡宏仲劉九丈','陳藻','宋','宋诗','song-poetry','','[]','明月無長好，晴空有晦時。',24,'全唐诗/poet.song.169000.json','["明月無長好，晴空有晦時。", "君家那與我，頭白似新知。"]'),
('8f813ed0-3031-4e40-8f86-bf9765b24040','丙子秋作','陳藻','宋','宋诗','song-poetry','','[]','今年時雨即時暘，用向田園每恰當。',32,'全唐诗/poet.song.169000.json','["今年時雨即時暘，用向田園每恰當。", "刈者不愁耕者喜，似曾真宰與商量。"]'),
('625b27bd-6504-4ed8-9104-15ab62dfe454','戲贈叔嘉','陳藻','宋','宋诗','song-poetry','','[]','七夕劉郎開小筵，細君重九病方痊。',64,'全唐诗/poet.song.169000.json','["七夕劉郎開小筵，細君重九病方痊。", "如何依舊煩纖手，伏枕呻吟到冬首。", "乃知貴骨真柔弱，老夫此語非諧謔。", "劉郎他日有公厨，節序無憂恣行樂。"]'),
('f79a3003-236a-4f43-8023-23a8e910062f','憫劉家竹','陳藻','宋','宋诗','song-poetry','','[]','陳生將五十，無地堪栽竹。',72,'全唐诗/poet.song.169000.json','["陳生將五十，無地堪栽竹。", "丈人門逕深，兩面千竿綠。", "營營不好事，終日眉峰蹙。", "二氣豈相宜，此君覺塵俗。", "琅玕訴失所，願作陶家菊。", "頼有徐卿兒，往往知忘肉。"]'),
('51ea31d3-a3d7-4787-9d91-73dd0f80598a','別蔡伯畛','陳藻','宋','宋诗','song-poetry','','[]','我本三山城下居，誰人共讀艾軒書。',64,'全唐诗/poet.song.169000.json','["我本三山城下居，誰人共讀艾軒書。", "固無田宅堪歸老，縱有文章適見疎。", "黄石出門多俊逸，白頭似子去鄉閭。", "六經正說終茫昧，不遣吾儕意氣舒。"]'),
('4d230a5e-9711-4d4c-b579-06cae3b83455','客中懷劉九','陳藻','宋','宋诗','song-poetry','','[]','丘嫂貧中出駡言，途窮非負昔時恩。',32,'全唐诗/poet.song.169000.json','["丘嫂貧中出駡言，途窮非負昔時恩。", "柴爐夜雨思君處，歸共柴壚笑語喧。"]'),
('e157109a-e69d-41bc-8d99-416a94452cab','贈蒙中','陳藻','宋','宋诗','song-poetry','','[]','田園尚少隠居難，場屋勞勞未得官。',32,'全唐诗/poet.song.169000.json','["田園尚少隠居難，場屋勞勞未得官。", "有酒羨君無一事，餘糧猶足散孤寒。"]'),
('b3693d82-4bc3-44d7-8b9a-8ce7a83d1d27','讀史偶作二首  其一','陳藻','宋','宋诗','song-poetry','','[]','千夫合作一賢人，合數賢人是聖神。',32,'全唐诗/poet.song.169000.json','["千夫合作一賢人，合數賢人是聖神。", "莫道眼前無孔子，一身散作萬千身。"]'),
('0918bfe1-2b15-48df-92cd-8573b5f9819c','讀史偶作二首  其二','陳藻','宋','宋诗','song-poetry','','[]','由來識後技無他，江左人材氣象豪。',32,'全唐诗/poet.song.169000.json','["由來識後技無他，江左人材氣象豪。", "道理明時身自俯，見聞溢處趾空高。"]'),
('e89f6890-b538-4197-a847-170dba20bb71','病眼寄子中','陳藻','宋','宋诗','song-poetry','','[]','連朝黑雨暫晴時，山抹浮雲似畫眉。',32,'全唐诗/poet.song.169000.json','["連朝黑雨暫晴時，山抹浮雲似畫眉。", "貪看須臾成底相，不堪病眼怕風吹。"]'),
('28cd4b5b-3e91-4634-9eac-ebed6368c5bd','絕交贈伯已二首  其一','陳藻','宋','宋诗','song-poetry','','[]','忙忙終日暫談玄，便聽閨房惡駡傳。',32,'全唐诗/poet.song.169000.json','["忙忙終日暫談玄，便聽閨房惡駡傳。", "郎壻已灰題柱志，親闈曾教斷機賢。"]'),
('7c39b41f-ec45-46f7-a7b3-c51cf2380659','絕交贈伯已二首  其二','陳藻','宋','宋诗','song-poetry','','[]','我讀人間饑死書，君歸市肆有錙銖。',32,'全唐诗/poet.song.169000.json','["我讀人間饑死書，君歸市肆有錙銖。", "未聞良婦嗔嘉客，分遣由來造化殊。"]'),
('55b18238-690f-4d4c-8aa4-35fef24d223c','獨宿贈伯已','陳藻','宋','宋诗','song-poetry','','[]','獨宿空齋夜雨流，對床無味不如休。',32,'全唐诗/poet.song.169000.json','["獨宿空齋夜雨流，對床無味不如休。", "論文似汝相逢少，又被塵埃鋪席囚。"]'),
('b3bcf06c-4b67-4635-a247-2c4f3e1efd74','值事有感懷漁溪丘德基','陳藻','宋','宋诗','song-poetry','','[]','紛紛場屋士，聞見是空虛。',48,'全唐诗/poet.song.169000.json','["紛紛場屋士，聞見是空虛。", "此老何曾學，高懷却有書。", "對人惟靜默，有飯即安居。", "說到榮華事，生平不計渠。"]'),
('f3abf197-e5f5-4f8c-9e4b-2695f080d99d','姚晉卿溪閣行','陳藻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南院觀溪心已清，縈紆更上閣中行。',160,'全唐诗/poet.song.169000.json','["南院觀溪心已清，縈紆更上閣中行。", "西窗車馬市橋橫，東窗遠山雲霧生。", "日斜沙石淺可數，半夜轟雷驅猛雨。", "農圃嘈嘈春水高，誰得身閒延客歌。", "醉後下階齊拍手，長株矮樹排花柳。", "主人更要雙眸寬，去年拄杖尋長安。", "一行一處狂呼去，日日芳園大如許。", "買地此多直幾金，千屏萬障爲牆堵。", "西湖覽畢歸興忙，川無大小人相羊。", "清風明月淛江有，酒廉魚賤輸吾鄉。"]'),
('f9a24b19-3939-4848-9bfe-bec458a64e2c','丘景運生孫叔南生子戲贈以詩二首  其一','陳藻','宋','宋诗','song-poetry','','[]','齒序逢君我在前，小兒學語舌初便。',32,'全唐诗/poet.song.169000.json','["齒序逢君我在前，小兒學語舌初便。", "如君未是生孫早，若比他人晚數年。"]'),
('51837db6-3785-45c6-9e63-4cb1de52c021','丘景運生孫叔南生子戲贈以詩二首  其二','陳藻','宋','宋诗','song-poetry','','[]','兩人鄉曲是同年，行坐相推日月先。',32,'全唐诗/poet.song.169000.json','["兩人鄉曲是同年，行坐相推日月先。", "莫道丘公孫是女，林郎初畫洗兒錢。"]'),
('39b3c690-6bb2-49da-9464-172a3ebbdff8','北風','陳藻','宋','宋诗','song-poetry','','[]','田園移主只丘墳，他邑浮家每斷魂。',32,'全唐诗/poet.song.169000.json','["田園移主只丘墳，他邑浮家每斷魂。", "又向隣州爲客久，北風終夜夢柴門。"]'),
('bd28af1d-c124-4166-b694-be2807ed0fcc','悼網山','陳藻','宋','宋诗','song-poetry','','[]','福清一半海爲田，創邑今垂五百年。',64,'全唐诗/poet.song.169000.json','["福清一半海爲田，創邑今垂五百年。", "傖蠻世革儒風起，西塘生在網山前。", "介夫凜凜松筠操，月魚識解文章到。", "黄檗休誇十二峰，烏窠白嶼空餐過。"]'),
('cc74890f-b0f2-46ed-a997-2f9e3a16d301','早梅開後寒日暗天各穿百孔於杖頭欲放一時之野眼戲題絕句跋其後','陳藻','宋','宋诗','song-poetry','','[]','夢中只是醒時魂，到老無他學著言。',32,'全唐诗/poet.song.169000.json','["夢中只是醒時魂，到老無他學著言。", "好句特然生夢裏，醒時却費斧斤痕。"]'),
('4edc7dce-2bc5-4e67-a6d7-8c79d850baa5','試黜寄余景仁','陳藻','宋','宋诗','song-poetry','','[]','六經不合窮稍深，入場下筆無知音。',64,'全唐诗/poet.song.169000.json','["六經不合窮稍深，入場下筆無知音。", "吐辭從實理從是，誰肯暮途生悔心。", "臨漳推官韙我筆，累舉悞疑當第一。", "夜光暗擲那有知，羣兒久處誰相識。"]'),
('7f41ebb4-3454-4a7c-9586-5310124eec33','冬日贈宏仲','陳藻','宋','宋诗','song-poetry','','[]','愛君方始卜鄰居，君又移家二里餘。',64,'全唐诗/poet.song.169000.json','["愛君方始卜鄰居，君又移家二里餘。", "日裏苦無時刻到，人情便覺往來疎。", "風霜今歲携盃幾，淮淛明年解纜初。", "兄嫂恩多因怨我，語言雖惡敢嗔渠。"]'),
('3a3c934c-ead4-4d0c-917b-c955be00b86c','題黄子正昜軒','陳藻','宋','宋诗','song-poetry','','[]','買屋移居已歷年，北偏破漏更新椽。',256,'全唐诗/poet.song.169000.json','["買屋移居已歷年，北偏破漏更新椽。", "忽於瓦下得昜字，鑄在小刀殊駭然。", "主人懽喜檢玉篇，昜也音揚飛也箋。", "儒生例作飛揚想，符瑞壯之心益堅。", "中間整頓安書案，此物携來呈我看。", "神扶頃刻聰明開，便解卜君門戶換。", "文形上下分兩刀，刀字成三意如何。", "昔人曾解三刀夢，果把一麾時命遭。", "正形五畫爲五馬，馬字依稀昜字寫。", "屋成一百六十秋，來歷無從詢鐵冶。", "漁溪市中多學者，舉業棄之如土苴。", "吟詩白日費工夫，勸君自此知趨舍。", "山水仙鄉出人物，課書雖少多簪紱。", "黄生雙眼自超奇，莫遜此刀持待兒。", "大書闊榜爲昜軒，我更分毫細討論。", "名場變易須容易，不到艱難過禹門。"]'),
('2fde1219-2c9b-472d-8cba-103988f2ff4b','和琴薰閣','陳藻','宋','宋诗','song-poetry','','[]','閣倚琴薰誦子虛，果然少壯入鄉書。',64,'全唐诗/poet.song.169000.json','["閣倚琴薰誦子虛，果然少壯入鄉書。", "未遊唐殿哦詩句，且把牙弦卧海隅。", "有據論文須博浩，無根話性合驅除。", "擢犀拔象塵埃裏，把出重看是捷途。"]'),
('1b816ac1-1f6f-41cb-abe8-0eaead9f88ec','賀仲雨斗門','陳藻','宋','宋诗','song-poetry','','[]','濯錦江邊唱絕强，孤青和者亦夔襄。',96,'全唐诗/poet.song.169000.json','["濯錦江邊唱絕强，孤青和者亦夔襄。", "歷年雖久地相遠，在寢豈止升渠堂。", "縱能帖石防頹岸，隨寓幽居供賞翫。", "何如是處斗門雄，莆壤萬農生贊歎。", "莊周笑我機械深，夏王見我須賞音。", "莫道白頭猶未遇，等勞一片活人心。"]'),
('6600bea7-c28b-4b88-812c-1936111a9d92','東林春晚作','陳藻','宋','宋诗','song-poetry','','[]','團欒四面山，我住一山裏。',192,'全唐诗/poet.song.169000.json','["團欒四面山，我住一山裏。", "相距能幾何，開方祗百里。", "日月出東西，星辰運終始。", "雲霞千萬狀，烟雨無窮美。", "誰云天體大，仰看全於此。", "窮儒治生計，富盛誰與擬。", "新晴麻麥秀，擁戴峰巒起。", "牡丹芍藥歇，春意濃未已。", "野花悉力開，白者真珠比。", "薔薇及寶相，爭鬭何綺靡。", "藩籬成障幕，村墟化城市。", "世上豈寂寥，俯仰昧斯旨。", "芙蕖開欲來，黄菊日可指。", "寒梅即艮卦，爲魁向年底。", "循環無了日，物物從頭理。", "康寧不相放，卧病爾爲爾。"]'),
('8fea1640-3046-4b7e-acb2-f5e8d760730b','平步樓','陳藻','宋','宋诗','song-poetry','','[]','主翁面貌不堪誇，却是書中意味華。',64,'全唐诗/poet.song.169000.json','["主翁面貌不堪誇，却是書中意味華。", "因地成樓平似陟，開林見樹直仍斜。", "竟日清幽來佛寺，有時問答覺人家。", "厭隨權勢貪情話，算殺肥雞愧滿車。"]'),
('b8be4a30-eb42-4fae-88aa-80f3ab25700f','劉騂子初冠勉以詩','陳藻','宋','宋诗','song-poetry','','[]','汝爺十五初裹頭，桂堂讀書從我遊。',96,'全唐诗/poet.song.169000.json','["汝爺十五初裹頭，桂堂讀書從我遊。", "汝今裹頭恰十五，兩載東林就規矩。", "我身只是前時命，汝家歲久無衰盛。", "族人快活羨汝爺，汝又勝爺好情性。", "瑩徹溫柔好性情，更須奮筆趨前程。", "苦思入神方得句，才如諸舅豈無甥。"]'),
('b6b9e357-4df4-4e4c-9143-3e3a854cd27d','叔嘉叔平既斬衰祝之以詩','陳藻','宋','宋诗','song-poetry','','[]','大兒年十四，三五不知八。',228,'全唐诗/poet.song.169000.json','["大兒年十四，三五不知八。", "源流於其母，造化保太察。", "小兒十歲周，松竹不知對。", "吾休置奴婢，天遣供井碓。", "我昔訓童多，虛受人家怨。", "愚智暗中分，何以償渠願。", "怪我自生兒，寒窗仍未睹。", "親朋責我苛，誨之非莽鹵。", "易教委虛談，過庭祗取笑。", "誰將蝴蜨飛，勒作秋蟬叫。", "迺舅久從游，村巫語又聽。", "身死欲葬埋，發掘安可憑。", "兩世太平山，此墓何人主。", "有房既分派，無息堪應舉。", "農商攀不及，矧乃君子儒。", "生前聊爾爾，沒後真卑污。", "他日主我喪，通經得兩郎。", "試之以巨創，整整到大祥。", "願汝且康健，送我歸山崗。"]'),
('33ff8178-f563-4046-9272-2b90c77d6214','貧病','陳藻','宋','宋诗','song-poetry','','[]','正圖奔走救寒饑，喘嗽那堪力已疲。',64,'全唐诗/poet.song.169000.json','["正圖奔走救寒饑，喘嗽那堪力已疲。", "意是無錢休買藥，情知有命不求醫。", "舊恩莫報空懷念，新識相逢淡更宜。", "多少貧交書畀我，觸來又得一篇詩。"]'),
('a1c9093e-b4ff-4eb6-afc1-605e4f56dc1e','李氏園','陳藻','宋','宋诗','song-poetry','','[]','開方數畝地，委曲多門牆。',120,'全唐诗/poet.song.169000.json','["開方數畝地，委曲多門牆。", "咫尺闤闠間，縈带谿山傍。", "入巷見顔子，簞瓢想淒涼。", "變化若夢中，忽成摩詰莊。", "主人華副實，好遊心不荒。", "引水灌花木，築牆收稻粱。", "六月無暑氣，池臺足徜徉。", "日斜留客浴，清浄如寶坊。", "迥迥過天象，艷艷流坤光。", "暫來吟未到，留歸作者囊。"]'),
('a152fc5b-fd8d-4d4c-bed9-9936ed5720ef','試黜題盧子俞所居','陳藻','宋','宋诗','song-poetry','','[]','門外冬青八九株，去去株間各丈餘。',128,'全唐诗/poet.song.169000.json','["門外冬青八九株，去去株間各丈餘。", "晚禾翦穗上囷儲，黄藁堆兼綠葉居。", "老夫晨出觀道腴，摧筇邐迤來東廬。", "世界在前君悟歟，饑寒火宅飽華胥。", "主人慰我下鄉書，謝之養生祗業儒。", "雖然鄰酒欠錢沽，粥飯可以供朝晡。", "四壁雖然一物無，半年聚稈爲薪芻。", "但愁賦稅吏追呼，鞭撻白丁省限踰。"]'),
('38ebb0e9-4e27-4e87-aef5-d631550a0fdb','歛石堂頭有老夫善排遣之語因答以詩','陳藻','宋','宋诗','song-poetry','','[]','本來無悶可消除，生死窮通一任渠。',32,'全唐诗/poet.song.169000.json','["本來無悶可消除，生死窮通一任渠。", "若到于今更排遣，讀書何處是工夫。"]'),
('1f8bcd37-fccf-492c-8058-d4ec7c23cf02','伯溫索詩賀令姊夫生朝','陳藻','宋','宋诗','song-poetry','','[]','一生開讀度殘年，糾者勞勞與辦錢。',128,'全唐诗/poet.song.169000.json','["一生開讀度殘年，糾者勞勞與辦錢。", "恰似叢林充化士，歷多世態得真禪。", "忽教衰老親題疏，也且低垂敢自賢。", "隨順却遭開眼白，屈伸誰識草經玄。", "官催租賦鞭笞急，家乏憔蘇色語煎。", "節序酒殽雖可廢，妻孥溝壑恐將填。", "不成底事空歸去，別問良媒解倒懸。", "樂內太深顔氏子，生朝索賀郭郎篇。"]'),
('92761fcd-4b0e-48b7-a981-136c6de7929a','謝丘伯已送酒芋','陳藻','宋','宋诗','song-poetry','','[]','二劉兄弟雖可語，其如斛面已尖量。',192,'全唐诗/poet.song.169000.json','["二劉兄弟雖可語，其如斛面已尖量。", "天差一婦各監係，跬步不容越隄防。", "羨餘置産晨夕忙，老夫押花亦歸疆。", "縉紳意態生堂堂，苞苴來往堪嗟傷。", "僕夫方遣邸音到，疾足追回他送將。", "跏趺禪伯坐高堂，棒喝驚人宗旨揚。", "東家小兒迪功郎，羞茶饋乳分名香。", "先生方寸古書藏，有時夜半開晶光。", "溫故知新滋味長，欲傳對面無承當。", "蹲鴟三十新酒芳，忽然餉我非世常。", "何以報之愧空囊，百尺竿頭與翺翔。", "男牽女挽細君狂，不放逍遥隨老莊。"]'),
('aa923927-56f3-4b06-a63e-11c1d46286c1','聽雨','陳藻','宋','宋诗','song-poetry','','[]','逋負關心糴穀償，麥苗準擬貼春糧。',32,'全唐诗/poet.song.169000.json','["逋負關心糴穀償，麥苗準擬貼春糧。", "連宵不寢聽微雨，錯喜簷花滴數行。"]'),
('c00b9569-e7e5-4cb4-9b8c-2b922021c2e4','元夕同社衆携燈上山謁神祠','陳藻','宋','宋诗','song-poetry','','[]','城中簫鼓閙鰲山，燈火千村別一般。',32,'全唐诗/poet.song.169000.json','["城中簫鼓閙鰲山，燈火千村別一般。", "今夕崔嵬行樂處，向時模倣仰頭看。"]'),
('18695cd1-d40b-4c19-92f6-f9d1656d1158','聞雷','陳藻','宋','宋诗','song-poetry','','[]','先春三日已聞雷，驅得長空一雨來。',32,'全唐诗/poet.song.169000.json','["先春三日已聞雷，驅得長空一雨來。", "莫問陰陽今失序，磽園且喜趁犁開。"]'),
('d11c6b82-7821-44e3-beba-4dccdeb27097','壽山種柑命名學圃','陳藻','宋','宋诗','song-poetry','','[]','數畝崎嶇带寺傍，水頹沙石古來荒。',64,'全唐诗/poet.song.169000.json','["數畝崎嶇带寺傍，水頹沙石古來荒。", "住山有道神通現，學圃成蹊鬼魅藏。", "每隔歲華留碩果，早從春事媚幽香。", "黄橙綠橘真堪詠，勝是長年引興長。"]'),
('33b63bca-d92d-4db1-8594-b3c0a9d2ea58','題林仲雨皦日庵','陳藻','宋','宋诗','song-poetry','','[]','詩仙庵未作，與我話庵名。',48,'全唐诗/poet.song.169000.json','["詩仙庵未作，與我話庵名。", "素髮來爲客，朱甍始落成。", "變風情性語，皦日死生盟。", "君老身猶健，雌埋一劍橫。"]'),
('f0213ca5-cd91-478c-9f16-74450ec508be','用余子畏韻其詩有警句云若知瓦礫真成道便覺珠璣不屬君','陳藻','宋','宋诗','song-poetry','','[]','少長城闉老一村，平生好語不曾聞。',64,'全唐诗/poet.song.169000.json','["少長城闉老一村，平生好語不曾聞。", "百年馬鬣空埋我，三載鼇頭更祝君。", "幸有鄰僧分隙地，豈無座主識雄文。", "須臾忍死携筇立，更看崢嶸足躡雲。"]'),
('f7890d52-3e9d-4376-9b48-079827348c36','聽吳畢聞講杜詩今夕行因效釋子偈體成一絕','陳藻','宋','宋诗','song-poetry','','[]','春秋皆貶事無褒，莊子思之意若何。',32,'全唐诗/poet.song.169000.json','["春秋皆貶事無褒，莊子思之意若何。", "下筆便爲齊物論，大家命酒且高歌。"]'),
('5b4a2d4a-ab5f-410d-8418-ab40a8851ae3','幽景','陳藻','宋','宋诗','song-poetry','','[]','山海吾鄉備，移供不厭餐。',24,'全唐诗/poet.song.169000.json','["山海吾鄉備，移供不厭餐。", "恰如行建劍，幽景享多般。"]'),
('628db399-6a7b-4351-95cf-e2bc27cdef50','次韵回叔經','陳藻','宋','宋诗','song-poetry','','[]','從來剽竊爲場屋，直是無繇識古書。',64,'全唐诗/poet.song.169000.json','["從來剽竊爲場屋，直是無繇識古書。", "屈指罕能官顯達，到頭剩得腹空虛。", "君今身計非謀祿，地有人耕免荷鋤。", "高適學詩年更晚，才名何患不相如。"]'),
('10230ae8-900b-47ef-ace7-6aaa61a06ece','喜雨','陳藻','宋','宋诗','song-poetry','','[]','年登猶藉米船通，去歲那堪一大凶。',64,'全唐诗/poet.song.169000.json','["年登猶藉米船通，去歲那堪一大凶。", "人死多因饑後疫，秧焦爭值北來風。", "晴空又似驕陽起，罄室誰支此患重。", "甘雨連朝雖未洽，蒔田漸喜澤邊農。"]'),
('64b2069d-b069-467f-8839-3ccacef15d6e','詠陳和伯母墳嘉禾芝草甘露之祥','陳藻','宋','宋诗','song-poetry','','[]','慕親五十歎姚虞，况是行年六十餘。',64,'全唐诗/poet.song.169000.json','["慕親五十歎姚虞，况是行年六十餘。", "方執母喪啼若孺，雖居禫制飯猶蔬。", "天存屋漏人純孝，曉到墳頭暮倚廬。", "芝草嘉禾甘露應，少爲嫠婦解生雛。"]'),
('1c253eca-9c0c-4e08-a220-a9bd12d54386','除夕','陳藻','宋','宋诗','song-poetry','','[]','歲晚民貧百物廉，無錢堪買亦何嫌。',32,'全唐诗/poet.song.169000.json','["歲晚民貧百物廉，無錢堪買亦何嫌。", "聊將送酒呼鄰客，淺飲三杯不用添。"]'),
('4a1609f3-22d5-4b48-859a-30f0e556e279','盧北山元夕','陳藻','宋','宋诗','song-poetry','','[]','社屋相忘鼓笛鳴，空村步月興堪乘。',32,'全唐诗/poet.song.169000.json','["社屋相忘鼓笛鳴，空村步月興堪乘。", "何須更要鰲山立，野燒天邊勝看燈。"]'),
('99296f56-818b-40f6-b344-14560e120b35','遇事有感','陳藻','宋','宋诗','song-poetry','','[]','命薄世仍貧，如何避苦辛。',48,'全唐诗/poet.song.169000.json','["命薄世仍貧，如何避苦辛。", "姓名聞有我，忠信話無人。", "哭死堪多舊，論交笑一新。", "聖經誰可愛，場屋散天真。"]'),
('79a67acd-a1b3-4ad0-97eb-476bc79ad4ce','橫江亭','陳藻','宋','宋诗','song-poetry','','[]','東注流求日本波，西吞金翅玉融河。',64,'全唐诗/poet.song.169000.json','["東注流求日本波，西吞金翅玉融河。", "好開亭館延三益，橫截江潮看萬艘。", "此是人烟生巨海，莫辭鮮食送新醪。", "網山勝處名賢迹，隔水相迎立兩坡。"]'),
('f1026e40-e717-4c88-a970-54bee5056908','剪春羅','陳藻','宋','宋诗','song-poetry','','[]','隨時宮女逐流波，尚有精魂在處多。',32,'全唐诗/poet.song.169000.json','["隨時宮女逐流波，尚有精魂在處多。", "待到百花零落盡，從頭子細剪春羅。"]'),
('57c2648d-2869-424b-b97c-fbeb573546a5','送郭定夫','陳藻','宋','宋诗','song-poetry','','[]','相看無可分，遠適無可餞。',96,'全唐诗/poet.song.169000.json','["相看無可分，遠適無可餞。", "但向主人家，杯酒時同燕。", "交緣何太淺，春風方識面。", "子行歸有期，我老魂將變。", "後會信難思，雖在殊州縣。", "史遷南北遊，值我鄉邦彥。", "話間及死生，亦足知深眷。", "石城伴梅福，共祝天和練。"]'),
('2feaea5c-6dca-4327-a7b6-5a55c55a4971','送張謙父往潭州','陳藻','宋','宋诗','song-poetry','','[]','八卦重來夢一周，人生更得幾年浮。',64,'全唐诗/poet.song.169000.json','["八卦重來夢一周，人生更得幾年浮。", "看君矍鑠猶堪展，似我龍鍾只合休。", "淮廣早供詞峽興，湖湘留與鬢霜遊。", "還鄉試問同庚客，剩有頭顱話舊否。"]'),
('01bd9358-17ec-4fb5-a99b-409d95fa65ac','書懷奉簡張謙父','陳藻','宋','宋诗','song-poetry','','[]','浮家官道傍，日夕逢佳客。',120,'全唐诗/poet.song.169000.json','["浮家官道傍，日夕逢佳客。", "無錢可用丹，有眼非開白。", "今春寧遠遁，往歲多慚色。", "一飯不能酬，饑來祗乞食。", "才華張八老，老昧幽居僻。", "邂逅出新醅，慇懃如舊識。", "燒笋美鮮嘗，買羊甘貴直。", "畦蔬遶舍生，園果亦堪摘。", "看君雖貧士，與我同庚袠。", "夫何造物偏，格我强其力。"]'),
('89653353-3131-4c60-900d-feeb730e47c2','贈余子畏','陳藻','宋','宋诗','song-poetry','','[]','相識紅泉舊日多，年年地上漸消磨。',64,'全唐诗/poet.song.169000.json','["相識紅泉舊日多，年年地上漸消磨。", "眼青好我今無幾，頭白逢君喜若何。", "縱道索居無伴侶，却能默悟自雄豪。", "細君掃去床書怒，笑答爲儒合詆訶。"]'),
('f0090b4e-ab5d-4fa9-9520-abd6ac7776f1','子畏惠詩用韻酬之','陳藻','宋','宋诗','song-poetry','','[]','老慵祗合在雞羣，變化那能慕海鵾。',64,'全唐诗/poet.song.169000.json','["老慵祗合在雞羣，變化那能慕海鵾。", "壯歲親朋多死別，窮途造化與生存。", "欲尋衣食愁無路，却被妻孥怨少恩。", "健筆期君今落第，相賙未得剩空論。"]'),
('9298f58b-70bf-49e6-8e69-987b5a469c06','送蔡伯畛往潮州四首  其一','陳藻','宋','宋诗','song-poetry','','[]','迎侍雖然勝左遷，戀鄉畢竟怕離筵。',32,'全唐诗/poet.song.169000.json','["迎侍雖然勝左遷，戀鄉畢竟怕離筵。", "讀書不合能譏佛，罰向潮州住幾年。"]'),
('5a87c88c-9efa-48a3-9f63-4a73b839cb75','送蔡伯畛往潮州四首  其二','陳藻','宋','宋诗','song-poetry','','[]','聽說漳南象窟間，如今行路不愁難。',32,'全唐诗/poet.song.169000.json','["聽說漳南象窟間，如今行路不愁難。", "黄茅青草無人處，多有軒亭好卸鞍。"]'),
('17b08a0b-3027-4661-ab93-f7ffcbfda856','送蔡伯畛往潮州四首  其三','陳藻','宋','宋诗','song-poetry','','[]','似我生男父合貧，腰斤嶺上解求薪。',32,'全唐诗/poet.song.169000.json','["似我生男父合貧，腰斤嶺上解求薪。", "君今有子爲官去，何憚携家踏路塵。"]'),
('eef6c454-efa3-4cce-8eb1-3eb5a24f08b0','送蔡伯畛往潮州四首  其四','陳藻','宋','宋诗','song-poetry','','[]','向來一夢兆孤青，還記伶俜過驛亭。',32,'全唐诗/poet.song.169000.json','["向來一夢兆孤青，還記伶俜過驛亭。", "今日此行非昨日，他時歸騎相掀騰。"]'),
('b5e285a6-a1ba-42f1-b240-14332cdb4456','問吳叔經病','陳藻','宋','宋诗','song-poetry','','[]','向來風月已傷多，誰料中身更被魔。',64,'全唐诗/poet.song.169000.json','["向來風月已傷多，誰料中身更被魔。", "萱草別非資灌溉，桐音何事不純和。", "人倫自古無娼妓，世態憑渠暫笑歌。", "若是此身能解脫，掃除藥餌病消磨。"]'),
('33aa6552-3f6d-4386-aba4-2b2c256d9150','贈高待聘','陳藻','宋','宋诗','song-poetry','','[]','待聘先生二十六，弟子滿堂脩幾束。',240,'全唐诗/poet.song.169000.json','["待聘先生二十六，弟子滿堂脩幾束。", "下床一麵月幾千，有客市廛錢別錄。", "爲兒不誦杞菊篇，舉筯欠魚須要肉。", "老夫弱冠奇一秋，飄零來問君平卜。", "先生稱我有雋才，滿縣青矜皆拭目。", "一日僅能赴三飯，折簡叩扉知幾幅。", "今夜酒移明夜醉，凌晨乞展黄昏速。", "四邊延我入師席，席則有餘身不足。", "高子行年已若干，更度四期心從欲。", "月錢祗直曉點心，薪蔬盡此携兒畜。", "抱書誰肯訪吾門，看君有是猶霑祿。", "井泉比舊百倍深，汲人綆短無麻續。", "時去技精分愈窮，時來淺學難逃福。", "販商射利偶贏餘，便詫巧謀能潤屋。", "莫待黄金當散時，舟車到處遭顛覆。"]'),
('26428779-fed0-43de-931b-a2b850595062','龍嶼偶作','陳藻','宋','宋诗','song-poetry','','[]','年少彎弓中鵠心，到頭衰暮也沉沉。',64,'全唐诗/poet.song.169000.json','["年少彎弓中鵠心，到頭衰暮也沉沉。", "有機悟道書篇嬾，無事關懷睡思深。", "跋扈笑非當日態，低回靜向此山吟。", "撥來自有洪纖韻，牙是天工我是琴。"]'),
('a8e4bb8a-b11a-406e-84c3-9d578f54c59c','夢故人','陳藻','宋','宋诗','song-poetry','','[]','死生休道隔幽明，夢裹相看話舊情。',32,'全唐诗/poet.song.169000.json','["死生休道隔幽明，夢裹相看話舊情。", "幻出他誰真面目，莫教總是自心成。"]'),
('18fa44ff-f189-4d7d-8ed1-9f3b1ded5018','黄景詠七十','陳藻','宋','宋诗','song-poetry','','[]','我纔弱冠出鄉閭，日漸回頭舊迹疎。',192,'全唐诗/poet.song.169000.json','["我纔弱冠出鄉閭，日漸回頭舊迹疎。", "惟有鄉閭才德士，記在心胸如記書。", "老來乍作龍門客，臭味訝君多似渠。", "講論前輩三數公，果然少壯皆羣居。", "因話隆興乾道事，恍惚此身棲故廬。", "迺知場屋非巨網，却放鯤鯨爲逸魚。", "不得浮名須得壽，人爵何如天爵有。", "談禪會意一二言，遣興成詩千百首。", "氣清形瘦力不羸，緩步登臨快如走。", "夕陽曉雞神愈健，端坐縱談誰解糾。", "今春七十休計年，此是神仙人識否。", "生平但看神仙手，何曾把錢弄升斗。"]'),
('e8a40422-edfd-4f23-ac6c-a98312ebe3f9','黄景詠夫婦七十','陳藻','宋','宋诗','song-poetry','','[]','身形清且瘦，乾坤一竿竹。',120,'全唐诗/poet.song.169000.json','["身形清且瘦，乾坤一竿竹。", "欺雪可千年，必壽先五福。", "易道古難全，陽九配陰六。", "先後期月間，唱隨來相逐。", "夫天君職閒，婦地臣勞服。", "觴詠恣優游，生理閨房熟。", "今春古稀會，元夜增和淑。", "二老出勸酬，笑談相往復。", "織女戲牛郎，輟耕歸辟穀。", "仙翁答王母，蟠桃真勝肉。"]'),
('01a992df-6dff-4d4d-a3b1-71fa12a3e59e','薌巒','陳藻','宋','宋诗','song-poetry','','[]','香山白樂天，香草荆屈平。',192,'全唐诗/poet.song.169000.json','["香山白樂天，香草荆屈平。", "釋氏定而慧，道家直且清。", "儒臣司燮理，至治薰神明。", "不然岩谷間，亦作蘭茝馨。", "郁郁若沉水，茫茫夷島生。", "人從韓壽徒，去就焉知輕。", "詎如賢達門，氣類全精誠。", "鮑肆不肯入，結交皆羣英。", "男以芳自持，女以烈主盟。", "時雖付衰歿，久亦騰褒旌。", "自古葬枯骨，阿誰埋令聲。", "所以薌巒上，遺芬始崢嶸。", "一字可爲謚，雙魂無愧情。", "寧馨把仙桂，已在月中行。", "迤邐銜雞舌，筆花對長檠。", "紫薇引當坐，紅藥歡相迎。"]'),
('85511861-9944-4939-b13f-db11bcdffc34','送郭定夫往江西二首  其一','陳藻','宋','宋诗','song-poetry','','[]','去年誤作送君詩，却又論文得幾時。',32,'全唐诗/poet.song.169000.json','["去年誤作送君詩，却又論文得幾時。", "今日溪邊成話別，榮歸早赴北堂期。"]'),
('f66fb1f7-9f28-4198-9d03-c616d9642ce6','送郭定夫往江西二首  其二','陳藻','宋','宋诗','song-poetry','','[]','石城少府自公餘，拄笏看山問老夫。',32,'全唐诗/poet.song.169000.json','["石城少府自公餘，拄笏看山問老夫。", "向道封胡羣從宅，馮生不到食魚無。"]'),
('145aa678-9f7d-4d50-bdbb-bff3b5b707ab','送黄欽之赴廣州鹽稅三首  其一','陳藻','宋','宋诗','song-poetry','','[]','地氣周遭逐處流，五羊漸已似中州。',32,'全唐诗/poet.song.169000.json','["地氣周遭逐處流，五羊漸已似中州。", "海風吹斷山無瘴，炎月何妨作宦遊。"]'),
('70399385-06ef-4f3d-96d1-67d547c18d82','送黄欽之赴廣州鹽稅三首  其二','陳藻','宋','宋诗','song-poetry','','[]','莫嫌征稅太喧卑，尺蠖將伸用屈爲。',32,'全唐诗/poet.song.169000.json','["莫嫌征稅太喧卑，尺蠖將伸用屈爲。", "好趁江西趨召命，此詩兼送入京時。"]'),
('6ca937df-e22b-4b16-96ac-8c383cb47df5','送黄欽之赴廣州鹽稅三首  其三','陳藻','宋','宋诗','song-poetry','','[]','一族名家叔度孫，同時入嶺五華軒。',32,'全唐诗/poet.song.169000.json','["一族名家叔度孫，同時入嶺五華軒。", "使臺帥閫終須到，官職高低且暫論。"]'),
('8fa7ac56-2994-4d2d-bf68-416871817293','謝丘子中惠詩','陳藻','宋','宋诗','song-poetry','','[]','高叟生來五十年，方知弄筆學詩篇。',32,'全唐诗/poet.song.169000.json','["高叟生來五十年，方知弄筆學詩篇。", "此翁甲子才奇一，吟詠看看到適邊。"]'),
('519d8221-589f-4ec1-894c-a67110081f80','寄黄景詠','陳藻','宋','宋诗','song-poetry','','[]','仙翁早歲學吾鄉，我到衰年客仞牆。',64,'全唐诗/poet.song.169000.json','["仙翁早歲學吾鄉，我到衰年客仞牆。", "柳下和風今有惠，江西詩派又傳黄。", "幽居衆仰仁山靜，默坐身回佛日光。", "人世大都如夢覺，雖然如夢話難忘。"]'),
('69b02bef-4bf2-4529-b7ca-f192ec182cc0','暮秋閏月平步樓口占','陳藻','宋','宋诗','song-poetry','','[]','恰已論心四十秋，朱顔化作素絲頭。',64,'全唐诗/poet.song.169000.json','["恰已論心四十秋，朱顔化作素絲頭。", "種田有穫須知足，應物無貪亦寡尤。", "浮世欲回殘夢未，男兒休管讀書否。", "任他門戶隨時變，尊酒相逢且勸酬。"]'),
('524c012c-7e57-4a24-ae2f-c99f2679c721','西軒罷齋暫別先後進諸友','陳藻','宋','宋诗','song-poetry','','[]','菜羹脫粟布襴衫，酒肉隨時亦飽酣。',64,'全唐诗/poet.song.169000.json','["菜羹脫粟布襴衫，酒肉隨時亦飽酣。", "生理傍人那得見，泉源在我久彌甘。", "此身可是陶成器，來學須教青出藍。", "若要參禪垂一問，也勝削髮禮瞿曇。"]'),
('f653aa54-fc75-46ce-83db-15b96b24317c','顔伯溫生日席上口占','陳藻','宋','宋诗','song-poetry','','[]','今日開筵賀始生，來年今日辦西行。',32,'全唐诗/poet.song.169000.json','["今日開筵賀始生，來年今日辦西行。", "後年壁挂登科記，今日人看指姓名。"]'),
('b1990429-1b48-4c4c-b613-7bde774420c4','送穀准羊肩賀伯溫','陳藻','宋','宋诗','song-poetry','','[]','曲江宴罷注官旋，親舊肥家有酒舡。',32,'全唐诗/poet.song.169000.json','["曲江宴罷注官旋，親舊肥家有酒舡。", "我老學農雖未遂，穀分一石准羊肩。"]'),
('f1b5dadc-a7d8-4649-8791-10f89cf61178','西宮中夜聞紡聲','陳藻','宋','宋诗','song-poetry','','[]','半夜俄聞踏紡車，鄰人如此解勤家。',32,'全唐诗/poet.song.169000.json','["半夜俄聞踏紡車，鄰人如此解勤家。", "東奔西走方來憇，驚覺真知何處邪。"]'),
('d1bfab1b-ff57-4e46-9a54-41fb18d14d01','別林肅翁','陳藻','宋','宋诗','song-poetry','','[]','滿懷裝貨出門前，多寡相酬應世緣。',64,'全唐诗/poet.song.169000.json','["滿懷裝貨出門前，多寡相酬應世緣。", "取友無他惟會理，逢僧祇此是談禪。", "樂生箇裏真慚愧，用向稠中足裹纏。", "便謝化工分付足，莫言行李去蕭然。"]'),
('45d37ad6-e660-4cde-8119-f8cafcf9dd12','讀東坡玉糝詩因成一絕續去年芋莖羹後寄丘林陳三友','陳藻','宋','宋诗','song-poetry','','[]','味有酥陀出自天，芋成玉糝却同然。',32,'全唐诗/poet.song.169000.json','["味有酥陀出自天，芋成玉糝却同然。", "此羹若使東坡見，尤怪枯莖化得偏。"]'),
('71c9de88-5992-4467-a28e-f943f3c7bdb5','六月望夜紀飲','陳藻','宋','宋诗','song-poetry','','[]','年老聊依年少遊，月圓庭上似中秋。',32,'全唐诗/poet.song.169000.json','["年老聊依年少遊，月圓庭上似中秋。", "舉杯問月爭多少，一度猶行甲子周。"]'),
('394e5306-2f5d-4220-be85-0a9272439058','贈許秀才','陳藻','宋','宋诗','song-poetry','','[]','祖工儷句集刊行，業販儒書乃父能。',32,'全唐诗/poet.song.169000.json','["祖工儷句集刊行，業販儒書乃父能。", "莫恥向人傭作字，世禆文教後須興。"]'),
('f6b19bb0-c066-4d92-b1a7-190895ffe0d4','寄楊南仲','陳藻','宋','宋诗','song-poetry','','[]','君思家世質，云此閨閭華。',72,'全唐诗/poet.song.169000.json','["君思家世質，云此閨閭華。", "我知財貨裏，自出人驕奢。", "先翁非勤儉，安能美生涯。", "兒郎不鼓舞，造化無萌芽。", "從今君已悟，拈骰入諠譁。", "結棚粧俚戲，達旦聽淫哇。"]'),
('924adf50-ac51-47f2-a968-6f43ef0ee4b9','書子誨所寄詩後','陳藻','宋','宋诗','song-poetry','','[]','摇膝支頤體漸康，入門已作白家香。',32,'全唐诗/poet.song.169000.json','["摇膝支頤體漸康，入門已作白家香。", "從今休傍官人俗，但向林泉呼二郎。"]'),
('f4ff7851-a9e5-4e22-8167-85b927eb882e','詠子誨門外荷花','陳藻','宋','宋诗','song-poetry','','[]','門外芙蓉未肯花，西風彌月露多華。',32,'全唐诗/poet.song.169000.json','["門外芙蓉未肯花，西風彌月露多華。", "我來爲客如相約，細沼同時十一葩。"]'),
('1086daa7-9c77-494b-8d26-0a9a9e2e836d','朱叔清小樓謁名并詩','陳藻','宋','宋诗','song-poetry','','[]','望舒雖是月，借作此樓名。',48,'全唐诗/poet.song.169000.json','["望舒雖是月，借作此樓名。", "收爾萬家地，歸吾雙眼明。", "規模成巧小，景物散縱橫。", "人若無高見，虛空柱謾擎。"]'),
('e726bc93-d455-449e-8cc6-61ce0d1d45f7','叔清留飲座上感懷','陳藻','宋','宋诗','song-poetry','','[]','十夜不相見，一見又如初。',48,'全唐诗/poet.song.169000.json','["十夜不相見，一見又如初。", "兄弟無人在，交朋却我餘。", "矢弧皆後挂，銘旐競先書。", "有酒堪留客，悲懷且掃除。"]'),
('e4469cc4-71d9-4dde-bb9b-25819f3bd212','歲晚朱叔清樓上談詩話佛飲酒聽琴作','陳藻','宋','宋诗','song-poetry','','[]','歲晚家何處，因循未得歸。',48,'全唐诗/poet.song.169000.json','["歲晚家何處，因循未得歸。", "本無愁可遣，寧有佛堪依。", "翁子談佳句，郎君撫妙徽。", "剔燈聊共醉，明日又分飛。"]'),
('5e3cc33c-4fde-4f43-8dff-db12e19fdd8d','謝余子京驤惠詩  其一','陳藻','宋','宋诗','song-poetry','','[]','晝同學歷夜觀星，壯日情親忽老成。',32,'全唐诗/poet.song.169000.json','["晝同學歷夜觀星，壯日情親忽老成。", "莫恨異鄉相見少，一來人物一番更。"]'),
('f8c81b30-af96-42ec-a113-80a4210751a2','謝余子京驤惠詩  其二','陳藻','宋','宋诗','song-poetry','','[]','遠來無物示拳拳，到老生涯尚闕然。',32,'全唐诗/poet.song.169000.json','["遠來無物示拳拳，到老生涯尚闕然。", "坐久但貪情話好，又勤雞黍費囊錢。"]'),
('77b5170f-0784-4a69-87d9-9f89aa412528','題吳景恬寫三傳正後','陳藻','宋','宋诗','song-poetry','','[]','乃翁催我傳春秋，及我書成已合眸。',32,'全唐诗/poet.song.169000.json','["乃翁催我傳春秋，及我書成已合眸。", "有子傳家何可憾，夜深燈火問東周。"]'),
('950a4369-2746-44ab-8c22-905b19c89099','謝王爾瞻爾中惠詩','陳藻','宋','宋诗','song-poetry','','[]','兄弟初年事網山，髭鬚未出正童顔。',32,'全唐诗/poet.song.169000.json','["兄弟初年事網山，髭鬚未出正童顔。", "我方盛壯今羸老，多謝新詩敘舊懽。"]'),
('3c5fbbc0-c363-4ccb-a1e7-cadbf52263b1','久不到黄石故人相見多喜余紅顔吳世執友喻之霜柿謂其熟而將墜也','陳藻','宋','宋诗','song-poetry','','[]','年將四十客莆陽，丱角相看笑語長。',32,'全唐诗/poet.song.169000.json','["年將四十客莆陽，丱角相看笑語長。", "今日生男行冠禮，老如霜柿又逢場。"]'),
('5c0d4bde-4119-40e6-8597-5838e5d7055c','謝余薦鴞聽易惠詩一首','陳藻','宋','宋诗','song-poetry','','[]','向得追隨父祖間，此來重結子孫懽。',64,'全唐诗/poet.song.169000.json','["向得追隨父祖間，此來重結子孫懽。", "自嗟三世須臾見，不有餘生會遇難。", "詩社已收風月美，舉場祇用粃糠殘。", "百錢聊買時文看，容易如君直換官。"]'),
('18951fba-da62-4996-ad1d-d00fd7b9e1cd','和林君作起叔梅詩韻','陳藻','宋','宋诗','song-poetry','','[]','林逋沒後幾星霜，苦要吟梅弄爝光。',64,'全唐诗/poet.song.169000.json','["林逋沒後幾星霜，苦要吟梅弄爝光。", "兩處湖光看共色，一家詩句嗅同香。", "花開再約談玄白，駑老那能逐乘黄。", "又恐來冬隨計吏，仙霞不管似羊腸。"]'),
('07ec218b-f63c-428c-a5ac-1290e9075b70','劉躔父生男','陳藻','宋','宋诗','song-poetry','','[]','生來長誦老夫詩，那可無詩慶浴兒。',32,'全唐诗/poet.song.169000.json','["生來長誦老夫詩，那可無詩慶浴兒。", "得巽曾吟吟是讖，果然先偶次從奇。"]'),
('e14f6504-73f0-4802-8087-3fb15db05378','賀叔嘉生日','陳藻','宋','宋诗','song-poetry','','[]','一子累輕婚事畢，如何學易已皤然。',32,'全唐诗/poet.song.169000.json','["一子累輕婚事畢，如何學易已皤然。", "天無快活除君壽，任待皤然也百年。"]'),
('e14a434a-87dc-4dd5-a75e-f1004fc335f8','賀劉直之值改官  其一','陳藻','宋','宋诗','song-poetry','','[]','公車五剡得京官，俗態營求有百端。',32,'全唐诗/poet.song.169000.json','["公車五剡得京官，俗態營求有百端。", "但看樂昌劉令尹，了無一語汗人顔。"]'),
('5c0ec16a-ff18-4176-9783-755150187c78','賀劉直之值改官  其二','陳藻','宋','宋诗','song-poetry','','[]','里人歡喜看榮歸，兩僕籃輿自有輝。',32,'全唐诗/poet.song.169000.json','["里人歡喜看榮歸，兩僕籃輿自有輝。", "勝在宦途無事業，但將裘馬詫輕肥。"]'),
('35a67dae-b649-42e5-954b-d3138351638e','賀劉直之值改官  其三','陳藻','宋','宋诗','song-poetry','','[]','少年場屋有程文，但見高才迥出羣。',32,'全唐诗/poet.song.169000.json','["少年場屋有程文，但見高才迥出羣。", "今日江邊看道骨，世人涵養罕如君。"]'),
('b4ff16be-7a58-40ae-ac41-1c19707ad5b1','賀劉直之值改官  其四','陳藻','宋','宋诗','song-poetry','','[]','日者紛紛步五星，諸儒言命亦相承。',32,'全唐诗/poet.song.169000.json','["日者紛紛步五星，諸儒言命亦相承。", "大人雙眼如明月，照出毫釐不肯憑。"]'),
('5b3a7052-1476-4dfa-b42e-978c71d80d5b','賀丘煥翁南歸','陳藻','宋','宋诗','song-poetry','','[]','三十年前八桂歸，西江舡上每吟詩。',64,'全唐诗/poet.song.169000.json','["三十年前八桂歸，西江舡上每吟詩。", "迺翁收拾傳尤切，令子經從是果非。", "渡海却休賢季路，論文想勝謁羅池。", "此行況有如臯雉，藥裹拋來自畫眉。"]'),
('a8cf0e5d-dc79-4056-ab85-7dd87f039a03','劉公父新理花畦約賞菊因成樂軒行','陳藻','宋','宋诗','song-poetry','','[]','舊屋早易主，新椽辦無錢。',192,'全唐诗/poet.song.169000.json','["舊屋早易主，新椽辦無錢。", "帡幪託親友，蹉跎經歲年。", "碎累入安宅，隻身出隨緣。", "引腹挂蛛網，移簷餌羽鮮。", "所愧歷游賞，不勞携饌筵。", "美名吾敢僣，茂實衆推先。", "但名長樂郡，誰擬地行仙。", "玉融未遍眼，銀髮久垂肩。", "何況縣十二，欲周里數千。", "軒齋或寄寓，宿食輒留連。", "公父白日暇，後園清興牽。", "種花成趣易，席草覺情宣。", "犬雞交巷陌，風月自林泉。", "匼匝山圍野，晴明霞散天。", "紅萸把雖過，黄菊采猶憐。", "詠我昔文賦，泛渠今酒舡。"]'),
('ca0db123-cc59-49c6-a5c9-e59235b605c3','清暉行','陳藻','宋','宋诗','song-poetry','','[]','主翁不解飲，安事園池遊。',108,'全唐诗/poet.song.169000.json','["主翁不解飲，安事園池遊。", "從知蓮社侶，所樂在清修。", "我憶少壯日，未多禪悅優。", "獨醒對佳景，愁紋上眉頭。", "四方觀唱禮，文辭旨趣幽。", "我膝固不屈，彌陀暗相投。", "葉吹光亂轉，花覆實泉流。", "此外無國土，靜中反身求。", "湛然真賞妙，誰肯尋糟丘。"]'),
('093ac2ca-9449-48e7-8388-02972ef0afaf','宿清暉','陳藻','宋','宋诗','song-poetry','','[]','禪家自古分人境，心地明時境始明。',64,'全唐诗/poet.song.169000.json','["禪家自古分人境，心地明時境始明。", "榕樾交陰牆內外，卉花散采路縱橫。", "築臺勾引江山入，鑿沼因緣萍藕清。", "好是炎天亭上宿，便爲凈土國中生。"]'),
('2e555214-cb02-434b-944c-7bfd39a9ab61','經鉏','陳藻','宋','宋诗','song-poetry','','[]','兩間陋屋牓經鉏，經是心明鉏是蔬。',64,'全唐诗/poet.song.169000.json','["兩間陋屋牓經鉏，經是心明鉏是蔬。", "種果始初花可翫，遶牆藤蔓實堪儲。", "若能棲止身爲鳳，何必奔馳食要魚。", "人見此間無五畝，誰知藝圃本寬舒。"]'),
('1dae4825-05dd-449c-a765-fe4ec4d95dac','過盧子俞','陳藻','宋','宋诗','song-poetry','','[]','番番留我殺雞多，老齒如今不奈何。',32,'全唐诗/poet.song.169000.json','["番番留我殺雞多，老齒如今不奈何。", "本是年凶甘隔闊，論情非爲酒來過。"]'),
('6357622b-278f-4955-85e2-1e1ca3a7e464','賀王嘉玉生日','陳藻','宋','宋诗','song-poetry','','[]','九袠初開二，鄉閭敬老成。',48,'全唐诗/poet.song.169000.json','["九袠初開二，鄉閭敬老成。", "今朝壽者出，明日聖人生。", "孫重勞昏嫁，奴猶課耨耕。", "乾坤無暫息，翁嫗合營營。"]'),
('a4544ad4-a854-447e-b024-a156e4ea17fb','次韻林君則惠詩','陳藻','宋','宋诗','song-poetry','','[]','湖水當門四面山，旁羅書史坐中間。',64,'全唐诗/poet.song.169000.json','["湖水當門四面山，旁羅書史坐中間。", "他人共我何曾有，造物於君本不慳。", "況是早教緣累少，便知晚與歲時閒。", "餘糧摸得鮮魚煮，大勝簞瓢陋巷顔。"]'),
('8b20cafc-c949-4ccf-93a5-2c1caee70e6a','感舊','陳藻','宋','宋诗','song-poetry','','[]','憶到渠來憶到渠，滿懷無限不刊書。',32,'全唐诗/poet.song.169000.json','["憶到渠來憶到渠，滿懷無限不刊書。", "獨行總是同行處，剩得長年剩得吁。"]'),
('6bab1ec7-3d60-4308-82a9-1763c6ebdd51','鄭汝則七十','陳藻','宋','宋诗','song-poetry','','[]','少壯同時事網山，幾人別後鬢能斑。',32,'全唐诗/poet.song.169000.json','["少壯同時事網山，幾人別後鬢能斑。", "古稀慙愧今餘四，君已平頭一醉歡。"]'),
('111aa001-563d-4932-b161-ef95eb9a6ca9','贈陳伯融夫婦','陳藻','宋','宋诗','song-poetry','','[]','才子治春秋，推尋命氏由。',48,'全唐诗/poet.song.169000.json','["才子治春秋，推尋命氏由。", "果然佳偶遂，夫豈俗人猶。", "話自文章出，身從勤儉修。", "老夫歡喜見，舊與兩家遊。"]'),
('f39a51c4-db17-4dbf-a1d3-7df7a1500efc','辛巳大歉','陳藻','宋','宋诗','song-poetry','','[]','村村無米歲何堪，我到家家有酒酣。',32,'全唐诗/poet.song.169000.json','["村村無米歲何堪，我到家家有酒酣。", "自昔略經三兩度，似今未見大生慚。"]'),
('4e053477-e087-40c0-8024-05a2298a0936','辛巳歲暮宴陸甥子由家','陳藻','宋','宋诗','song-poetry','','[]','吾妹嫁時狼狽甚，幸皆存活得年深。',64,'全唐诗/poet.song.169000.json','["吾妹嫁時狼狽甚，幸皆存活得年深。", "有男買屋棲遲喜，見舅開樽爛熳斟。", "歲值凶荒多餓死，我慚溫飽更酣吟。", "還鄉日少生難保，敢覬今番一話心。"]'),
('0b484ca2-d2c3-4dec-87d7-2267974df230','辛巳歲晚上墳','陳藻','宋','宋诗','song-poetry','','[]','偶然空手出州城，薄有田園住福清。',64,'全唐诗/poet.song.169000.json','["偶然空手出州城，薄有田園住福清。", "晚得次男陪筆硯，秋隨舉子省墳塋。", "過淮不擬成僧去，挂紙誰能接跡行。", "多少隴頭無祭祀，此來猶喜剩餘生。"]'),
('4b766045-24f4-4306-95c2-d2e320acb38d','嘆問塘東一二新舊','陳藻','宋','宋诗','song-poetry','','[]','數畝荒田不解耕，老年場屋又無成。',32,'全唐诗/poet.song.169000.json','["數畝荒田不解耕，老年場屋又無成。", "更堪風雨飄摇甚，告放渠儂與養生。"]'),
('90f86253-366b-4856-8d12-35e7b5e9883f','閲世','陳藻','宋','宋诗','song-poetry','','[]','道理初從紙上求，因而處世得優游。',32,'全唐诗/poet.song.169000.json','["道理初從紙上求，因而處世得優游。", "于今但閲人間世，自有文章筆下流。"]'),
('0acbd93d-109e-46c8-b952-11f3b99f7089','辛巳秋後訪盧子俞作','陳藻','宋','宋诗','song-poetry','','[]','本是吾鄉少富藏，五年亢旱太難當。',64,'全唐诗/poet.song.169000.json','["本是吾鄉少富藏，五年亢旱太難當。", "麥苗俱盡村如洗，蔬芋全無市亦荒。", "笑我擬爲饑莩去，訪君那得酒肴嘗。", "更生一見真歡喜，忍聽他人尚絕糧。"]'),
('a993d442-a3a3-4669-8886-8830688df95c','食粥絕句贈盧震夫','陳藻','宋','宋诗','song-poetry','','[]','古甆大椀今無有，特地凶年洗出來。',32,'全唐诗/poet.song.169000.json','["古甆大椀今無有，特地凶年洗出來。", "滿著十分牛乳粥，客思喫盡鬼神猜。"]'),
('b1dc18db-d64d-4cd4-8f13-4bddda2ce33c','戒買墓石人','陳藻','宋','宋诗','song-poetry','','[]','盜拆鄰墳築己墳，價廉石大且輸君。',32,'全唐诗/poet.song.169000.json','["盜拆鄰墳築己墳，價廉石大且輸君。", "莫教孫子無如我，自拆年時也易聞。"]'),
('db1e9fc9-078e-406c-97f4-780215293457','楞伽經','陳藻','宋','宋诗','song-poetry','','[]','若向他經義已詳，此難成句也何妨。',32,'全唐诗/poet.song.169000.json','["若向他經義已詳，此難成句也何妨。", "昔人誤點經文會，更不回頭狥故常。"]'),
('50e57ba0-f72d-4067-98ce-f76fcfe8bac6','過桃枝嶺','陳藻','宋','宋诗','song-poetry','','[]','兒童嬉戲向比鄰，長見桃枝出郭人。',32,'全唐诗/poet.song.169000.json','["兒童嬉戲向比鄰，長見桃枝出郭人。", "七十五翁方過嶺，回頭舊事總成塵。"]'),
('74056375-ee41-452c-a1b5-6188866b3631','九峰過重陽  其一','陳藻','宋','宋诗','song-poetry','','[]','算來七十五重陽，無酒今朝對菊黄。',32,'全唐诗/poet.song.169000.json','["算來七十五重陽，無酒今朝對菊黄。", "記得蘇杭船上坐，一番醒眼詠詩章。"]'),
('8cb832d9-6c7d-445f-8cc7-83e0908551e8','九峰過重陽  其二','陳藻','宋','宋诗','song-poetry','','[]','登高却是今最高，九峰寺上誦莊騷。',32,'全唐诗/poet.song.169000.json','["登高却是今最高，九峰寺上誦莊騷。", "茶話恰宜湯餠素，滿身風癢怕村醪。"]'),
('1a2bfd14-53d3-459a-9238-f88bf7f14953','謝鄭如之送酒初十日','陳藻','宋','宋诗','song-poetry','','[]','俗緣不許伴僧齋，錯喜重陽避酒杯。',32,'全唐诗/poet.song.169000.json','["俗緣不許伴僧齋，錯喜重陽避酒杯。", "誰擬衰翁對衰菊，黄昏猶有白衣來。"]'),
('f45cf0ba-0d6c-46a9-9d71-bacd8b8becc1','謝九峰升坐相留','陳藻','宋','宋诗','song-poetry','','[]','重陽七日月當圓，高坐禪師祝萬年。',32,'全唐诗/poet.song.169000.json','["重陽七日月當圓，高坐禪師祝萬年。", "夢裏五更聞齒錄，凡夫有罪是貪眠。"]'),
('0b39632d-c4b3-4ddc-bacc-572c83a0fe4d','贈九峰老','陳藻','宋','宋诗','song-poetry','','[]','佛土仙家本一般，松菴海上住三山。',32,'全唐诗/poet.song.169000.json','["佛土仙家本一般，松菴海上住三山。", "三三演出奇峰九，生氣元來萃此間。"]'),
('b71b4fad-6683-45e7-843a-dfcd6e16ca81','九峰僧房看山','陳藻','宋','宋诗','song-poetry','','[]','寺前寺後木彎環，殿裏莊嚴佛一般。',32,'全唐诗/poet.song.169000.json','["寺前寺後木彎環，殿裏莊嚴佛一般。", "衲子開窗還禮拜，生株何用巧彫殘。"]'),
('c317793b-5b75-456c-9cab-4fff2f20535f','九峰看菊','陳藻','宋','宋诗','song-poetry','','[]','平生尋菊未曾遭，直上成叢一丈高。',32,'全唐诗/poet.song.169000.json','["平生尋菊未曾遭，直上成叢一丈高。", "幾處禪房驚老眼，滿堂佛像自森羅。"]'),
('020951c4-20f9-4b41-866d-0dcc82943462','送陳智叔舍人赴召','陳藻','宋','宋诗','song-poetry','','[]','紫袍入手閏兩周，黄紙除書作郡侯。',176,'全唐诗/poet.song.169000.json','["紫袍入手閏兩周，黄紙除書作郡侯。", "後薪莫訝還居上，巨魚直是能吞舟。", "蕭何乃知天下信，魯人祇道東家丘。", "到了公評難嫉忌，遠皆敬服近何尤。", "器識高明官令顯，羞作軟媚隨波流。", "膽略肯因權勢屈，事機果中日前籌。", "鴻飛似退正仙翼，不蓍不龜心有眸。", "兵形敵計何英識，胍絡豈從經外紬。", "友于根自惟孝發，論語尚書政所由。", "君於骨髓已先得，字是皮毛剝便投。", "强收老淚且分袂，情共斯文苑囿留。"]'),
('b6f987c5-675e-4bc0-998e-e26cc71ce7b0','吾鄉有李明府其伯子襟懷夐然世表某早知敬慕長誦諸人今老矣輒韻之以貽其子孫云','陳藻','宋','宋诗','song-poetry','','[]','廟食於莆李長者，變海爲田散郊野。',176,'全唐诗/poet.song.169000.json','["廟食於莆李長者，變海爲田散郊野。", "福宜孫子百千年，家甲三山總文雁。", "西城一位京朝郎，官雖未顯善聲揚。", "伯曰孝純遵義方，潘安容貌心蒙莊。", "幼小摳趨父執時，挂口何曾聞是非。", "到了交遊如一日，肯學世情隨盛衰。", "我頭半白言稍傳，晚出要教識前賢。", "睽遠莫能修世契，擬將下筆無由緣。", "喜今有便歸鄉多，吾姪春中偏飲和。", "老去舊懷因稱敘，吉人與就幸如何。", "滿眼各爲君父子，誰憂平地起風波。"]'),
('38c4a8a5-2e2c-46a6-84a3-d4190db4c105','歲除僧寺看寫疏作','陳藻','宋','宋诗','song-poetry','','[]','元正祈禱萬千般，縱道聰明聽也難。',32,'全唐诗/poet.song.169000.json','["元正祈禱萬千般，縱道聰明聽也難。", "料得鬼神應喜我，不曾投疏一相干。"]'),
('8afc14a0-0681-412d-bd85-95cce073e5af','首正有感二首  其一','陳藻','宋','宋诗','song-poetry','','[]','憶昔吾鄉入首正，衩衣街斷小書生。',32,'全唐诗/poet.song.169000.json','["憶昔吾鄉入首正，衩衣街斷小書生。", "紫衫來去今無幾，恰似當年冠带行。"]'),
('839c0831-2ba0-4c30-b2ad-a0058495983e','首正有感二首  其二','陳藻','宋','宋诗','song-poetry','','[]','聽說從前我未生，知書不許衩衣行。',32,'全唐诗/poet.song.169000.json','["聽說從前我未生，知書不許衩衣行。", "平時街上齊冠带，況是人間歲節更。"]'),
('cf77b0fa-4858-4f38-8306-865f12bf8d66','口占寄林子六','陳藻','宋','宋诗','song-poetry','','[]','日月相催不放遲，寄詩又是去年時。',32,'全唐诗/poet.song.169000.json','["日月相催不放遲，寄詩又是去年時。", "近來未省開懷否，還似從前尚皺眉。"]'),
('aa9baf5e-6fc2-4d15-ae2f-c12a0acc8299','寓故里大中寺值朱起蔡同宿數夜','陳藻','宋','宋诗','song-poetry','','[]','壯遊初到鄭公鄉，與子吟哦古佛旁。',32,'全唐诗/poet.song.169000.json','["壯遊初到鄭公鄉，與子吟哦古佛旁。", "老去同時人死盡，那知來此話僧房。"]'),
('4b9b46a6-7685-411d-9869-75944c2365c3','上東山墳寄敬之弟','陳藻','宋','宋诗','song-poetry','','[]','東山零落古三丘，力薄那能抑得周。',32,'全唐诗/poet.song.169000.json','["東山零落古三丘，力薄那能抑得周。", "頼有阿連霑寸祿，我慚到老一來休。"]'),
('7754c2a7-0ef9-42dc-a247-5e3892eed5c3','癸未生朝躔父公父以酒殽而華其陋賦一絕','陳藻','宋','宋诗','song-poetry','','[]','家貧何敢話生朝，多謝開尊慰寂寥。',32,'全唐诗/poet.song.169000.json','["家貧何敢話生朝，多謝開尊慰寂寥。", "要跡一盃辭不受，便需拙句作瓊瑶。"]'),
('0bdc45a7-24da-47e0-b1fa-ce71f41ac49d','中秋','陳藻','宋','宋诗','song-poetry','','[]','詩書讀罷問耕牛，待得時來死便休。',32,'全唐诗/poet.song.169000.json','["詩書讀罷問耕牛，待得時來死便休。", "一带空村無潤屋，聊因社肉作中秋。"]'),
('e9bc6d36-2811-414a-99c4-f0fad128ed69','次韻源仲八丈日理之作','陳藻','宋','宋诗','song-poetry','','[]','眼中皆道境，牆內是君家。',24,'全唐诗/poet.song.169000.json','["眼中皆道境，牆內是君家。", "樂處元無盡，吾生任有涯。"]'),
('642ead32-9ccb-4ca1-a4bb-a0865b5411dd','賀四五姑七十','陳藻','宋','宋诗','song-poetry','','[]','壯歲貧而旅，無家可語歸。',48,'全唐诗/poet.song.169000.json','["壯歲貧而旅，無家可語歸。", "見多延酒饌，躬爲補裳衣。", "頭白諸親忝，心丹百事違。", "何堪持報德，但喜母年希。"]'),
('bb815701-6668-4777-862c-c365e013a57e','艾軒老先生文集刊傳上以揄揚其問學下則得佛家以法布施之意前後數君子有是志而不果今日薄西山幸一見此喜成古風三篇以賀後來之有作者且述下悰云  其一','陳藻','宋','宋诗','song-poetry','','[]','老艾先生歿，駸駸四紀年。',132,'全唐诗/poet.song.169000.json','["老艾先生歿，駸駸四紀年。", "衣冠常嘆惜，文字合刊傳。", "東巒乃猶子，遺藁掇拾全。", "網山雖上足，無刀堪雕鎸。", "從遊今殆盡，錄藏多散捐。", "裔孫韙君應，發憤起收編。", "甲集且流布，俸微艱得錢。", "晚春題壁去，名姓輝藍田。", "製錦增廩給，乙丙尋踵前。", "搜羅必盈十，但祝君高遷。", "我老不可待，權輿已欣然。"]'),
('7173d54b-b12b-4834-8147-346f06ce33f6','艾軒老先生文集刊傳上以揄揚其問學下則得佛家以法布施之意前後數君子有是志而不果今日薄西山幸一見此喜成古風三篇以賀後來之有作者且述下悰云  其二','陳藻','宋','宋诗','song-poetry','','[]','夫子刪詩去，流年近二千。',84,'全唐诗/poet.song.169000.json','["夫子刪詩去，流年近二千。", "何人悟芣苢，此老獨遺筌。", "活鯉收入袖，化龍騎上僊。", "傍看休發問，無語堪相傳。", "假令託忠恕，投塊答僧禪。", "依前提出後，未誰知的然。", "給還上手契，各認落江田。"]'),
('9fb0344f-f88f-4197-8e63-c66c8c08c9d6','艾軒老先生文集刊傳上以揄揚其問學下則得佛家以法布施之意前後數君子有是志而不果今日薄西山幸一見此喜成古風三篇以賀後來之有作者且述下悰云  其三','陳藻','宋','宋诗','song-poetry','','[]','蚤歲過玉融，悟逢陳叔盥。',96,'全唐诗/poet.song.169000.json','["蚤歲過玉融，悟逢陳叔盥。", "曾待艾翁來，國風話長短。", "忽聽誦采蘋，玉川茶八椀。", "因入網山門，多舍莆陽館。", "今喜文集行，源流心事滿。", "頭顱七十六，見此抑何緩。", "百爲信有待，立志如君罕。", "良晤向三山，彙緣非偶款。"]'),
('b342bd1a-c507-41f4-bbed-d50a7f1072fd','別林黄中帥湖南','陳藻','宋','宋诗','song-poetry','','[]','清秋緩轡馬如雲，論定忠邪黑白分。',64,'全唐诗/poet.song.169000.json','["清秋緩轡馬如雲，論定忠邪黑白分。", "湘水傳呼新刺史，霸陵改觀舊將軍。", "平生孤節人難到，自此一番名愈聞。", "定有詔書催入覲，不勞下擔楚江濆。"]'),
('eb43fc7e-6ca8-49c4-b5c2-9be1f02cf085','漱石  其一','黄犖','宋','宋诗','song-poetry','','[]','撐空嶙峋一石古，呼水來作飛泉鳴。',32,'全唐诗/poet.song.169000.json','["撐空嶙峋一石古，呼水來作飛泉鳴。", "摩挲徙倚坐彌久，便欲老此巖之扃。"]'),
('75131e06-e851-484b-8933-1ffd4dff9ecd','漱石  其二','黄犖','宋','宋诗','song-poetry','','[]','天然雲骨老巉巖，疑是飛來住此間。',32,'全唐诗/poet.song.169000.json','["天然雲骨老巉巖，疑是飛來住此間。", "獨坐小窗聽夜雨，夢魂應不到康山。"]'),
('675bbcbd-683a-45de-800a-58909d6b9afd','臨終歌','鄒夢遇','宋','宋诗','song-poetry','','[]','嘉木扶疏兮，鳥鳴關關。',33,'全唐诗/poet.song.169000.json','["嘉木扶疏兮，鳥鳴關關。", "暑風舒徐兮，庭中閒閒。", "起視天宇兮，浩乎虛澄。"]'),
('5c5705fd-f782-427e-8967-11593b78d534','臨終詩','王楙','宋','宋诗','song-poetry','','[]','平生不學口頭禪，脚踏實地性虛天。',32,'全唐诗/poet.song.169000.json','["平生不學口頭禪，脚踏實地性虛天。", "臨歸不用求纏裹，趁著帆風便上船。"]'),
('e2e8552b-912f-4445-8719-c3ff4a06b107','題釣臺','舒杲','宋','宋诗','song-poetry','','[]','會心林木已成懽，登覽還知天地寬。',32,'全唐诗/poet.song.169000.json','["會心林木已成懽，登覽還知天地寬。", "莫訝釣臺有真贋，一潭秋月照人寒。"]'),
('fba4e256-4146-4e54-9e98-31620d313777','與孫自修祝和甫讀宛陵山谷詩','程永奇','宋','宋诗','song-poetry','','[]','孫君出宛陵，梅詩獨不喜。',156,'全唐诗/poet.song.169000.json','["孫君出宛陵，梅詩獨不喜。", "祝黄世通家，於此更訾毀。", "暇日扣我門，相與求正始。", "敢述過庭聞，用告二三子。", "節拍貴詳緩，言語戒浮靡。", "無因內金盤，遂厭古罍洗。", "無惑變徵聲，雅樂成逆耳。", "譬如學書人，牽率宗二米。", "一觀繇羲帖，棄走却千里。", "九方相神駿，肯與驪黄齒。", "紛紛稗官說，而昧洙泗理。", "世事難具陳，豈必在文士。", "不鼓無成虧，吾欲師昭氏。"]'),
('e52e5396-ac9e-4204-9c9a-560e5ef7a86b','聞考亭先師之訃時黨禁方嚴','程永奇','宋','宋诗','song-poetry','','[]','忽聞摧岱岳，吾黨更何依。',48,'全唐诗/poet.song.169000.json','["忽聞摧岱岳，吾黨更何依。", "歛枕看炊黍，登樓送落暉。", "祥麟傷史筆，山鳥怪儒衣。", "此道終難絕，他年有是非。"]'),
('b0191503-d81b-4c50-9b4e-e3f11cf16420','題耕隠卷','程永奇','宋','宋诗','song-poetry','','[]','山下巢雲夢亦清，隴頭耕雨綠蓑輕。',32,'全唐诗/poet.song.169000.json','["山下巢雲夢亦清，隴頭耕雨綠蓑輕。", "時人共指龐居士，爲借農書一到城。"]'),
('3824140f-d64d-4fcb-b8d0-5e31e1fb292a','屯溪訪故人','程永奇','宋','宋诗','song-poetry','','[]','主人溪上宅，烏几屢曾憑。',48,'全唐诗/poet.song.169000.json','["主人溪上宅，烏几屢曾憑。", "山直西南向，田分上下層。", "池鮮烹錦鯉，塘果致青菱。", "此去重陽近，遥岑共一登。"]'),
('08aa98e2-60a8-461f-abac-604969dba0e3','頌古五首  其一','釋如琰','宋','宋诗','song-poetry','','[]','示疾毗耶方丈，文殊亦難近傍。',28,'全唐诗/poet.song.169000.json','["示疾毗耶方丈，文殊亦難近傍。", "看來無藥可醫，只是忌口爲上。"]'),
('b2c42bd2-1e38-4019-86f0-29bcdbfec0ae','頌古五首  其二','釋如琰','宋','宋诗','song-poetry','','[]','問處分明答處端，還同雙劍倚天寒。',32,'全唐诗/poet.song.169000.json','["問處分明答處端，還同雙劍倚天寒。", "一從樓閣門開後，滿面慚惶無處安。"]'),
('53f47d32-9042-4be7-9967-75f30526aedc','頌古五首  其三','釋如琰','宋','宋诗','song-poetry','','[]','蹉過跨門一機，昧却見成公案。',28,'全唐诗/poet.song.169000.json','["蹉過跨門一機，昧却見成公案。", "子湖指處太親，直須急著眼看。"]'),
('ee956133-5776-4e8f-937c-40eb6d9f137d','頌古五首  其四','釋如琰','宋','宋诗','song-poetry','','[]','夾嶠當年錯用心，貪他香餌被他擒。',32,'全唐诗/poet.song.169000.json','["夾嶠當年錯用心，貪他香餌被他擒。", "點頭三下無言說，水闊山遥恨轉深。"]'),
('52095c70-f84a-4549-9ed8-d796c925b045','頌古五首  其五','釋如琰','宋','宋诗','song-poetry','','[]','趙州老漢熱心腸，一盞粗茶驗當行。',32,'全唐诗/poet.song.169000.json','["趙州老漢熱心腸，一盞粗茶驗當行。", "回首路傍橋斷處，白蘋紅蓼映斜陽。"]'),
('fba003a9-2458-4976-95eb-66e04ab3b7d7','句  其一','余子畏','宋','宋诗','song-poetry','','[]','我合焚香夜深坐，等君頭白柳州來。',16,'全唐诗/poet.song.169000.json','["我合焚香夜深坐，等君頭白柳州來。"]'),
('06e72296-f9a4-4127-9555-3040725fe951','句  其二','余子畏','宋','宋诗','song-poetry','','[]','若知瓦礫真成道，便覺珠璣不屬君。',16,'全唐诗/poet.song.169000.json','["若知瓦礫真成道，便覺珠璣不屬君。"]'),
('f0633ba8-12e7-4d89-ae48-676994ad54dd','句  其三','余子畏','宋','宋诗','song-poetry','','[]','世多畏路嗟予怯，天有危機奈子何。',16,'全唐诗/poet.song.169000.json','["世多畏路嗟予怯，天有危機奈子何。"]'),
('549cf4d7-afcc-4ffb-aa19-06c0f101ec1d','新歲連雨不止因寄公濟兼簡賢令强公','釋契嵩','宋','宋诗','song-poetry','','[]','寒郊纔喜歲華新，景物陰陰又一旬。',64,'全唐诗/poet.song.17000.json','["寒郊纔喜歲華新，景物陰陰又一旬。", "雲带天低垂壓野，雨藏春晝暗迷人。", "寧愁燈火妨明月，却嘆詩家惜令辰。", "陶令而今卧江國，倚樓吟望更誰親。"]'),
('95dc6ec2-dad2-4a89-b218-5a71e656933d','又次韻奉寄强令','釋契嵩','宋','宋诗','song-poetry','','[]','冉冉流年年曆新，仲春春日未盈旬。',64,'全唐诗/poet.song.17000.json','["冉冉流年年曆新，仲春春日未盈旬。", "何爲萬里青雲士，來問雙峰白髮人。", "詩思雅驚含老格，風神清爽惜芳辰。", "況聞傲令陶元亮，蠟屐須來與我親。"]'),
('28698168-d68f-4dfc-89ae-0994e4fe74e4','錢湖草堂次仲靈韻','釋惟晤','宋','宋诗','song-poetry','','[]','雪滿西山春未歸，泉聲凍咽鳥聲稀。',64,'全唐诗/poet.song.17000.json','["雪滿西山春未歸，泉聲凍咽鳥聲稀。", "靜觀眼境人間渺，驅逐詩魔天外飛。", "一飽每將松作飯，大寒重換紙爲衣。", "我憐詩是君家事，更約論心極細微。"]'),
('2b4b2af6-6b82-4c13-b74a-67ea05a1f8cc','將訪永安東山禪師先寄','釋惟晤','宋','宋诗','song-poetry','','[]','庵在千株松桂下，更無塵事到夫君。',64,'全唐诗/poet.song.17000.json','["庵在千株松桂下，更無塵事到夫君。", "高蹤罕過呼猿澗，靜思唯看抱石雲。", "日暮坐間禽影集，雪晴岸畔路形分。", "揚雄約我須投宿，月裏禪餘怯論文。"]'),
('7fe71dfa-4cbc-484f-880b-97ed5930bf5f','次韻奉和','釋惟晤','宋','宋诗','song-poetry','','[]','道安獨繼襄陽踵，詩好慵窺霅晝評。',64,'全唐诗/poet.song.17000.json','["道安獨繼襄陽踵，詩好慵窺霅晝評。", "竹屋數間經幾載，草衣三事傲平生。", "縱陪林下收孤迹，難學人間走大名。", "燈火已殘譚未倦，曉風斜雨打窗聲。"]'),
('6a586894-6220-4288-afcb-d5953532d2c3','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','白雲蒼海一重重，傍舍遥聞隔塢鐘。',64,'全唐诗/poet.song.17000.json','["白雲蒼海一重重，傍舍遥聞隔塢鐘。", "月上更無人語鬧，雪深空認虎行蹤。", "詩書共喜燈前論，茗果翻疑夢裏逢。", "脫屣高譚無限樂，熅鑪寒擁日高舂。"]'),
('44d4ac0d-b8df-42da-a0f9-62fbf49bf2b6','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','雨洗羣山秀色分，一笻雙屐到松門。',64,'全唐诗/poet.song.17000.json','["雨洗羣山秀色分，一笻雙屐到松門。", "天邊雲散爭歸洞，島外樵還各占村。", "久著青袍心已厭，相看白首事休論。", "請君細問黄梅老，當信禪河別有源。"]'),
('426ee42b-fa43-4332-b949-120cae34c950','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','戰退睡魔重酌茗，再披文卷眩生花。',64,'全唐诗/poet.song.17000.json','["戰退睡魔重酌茗，再披文卷眩生花。", "喜逢長夜身雖健，勉和新詩興未佳。", "風細猿聲清似梵，月明杉影密如麻。", "臘寒燈炷飛蛾滅，何必殷勤護薄紗。"]'),
('6142b484-262e-4045-bc81-bc18970ff320','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','曉過翻經臺下寺，與君同謁祖師堂。',64,'全唐诗/poet.song.17000.json','["曉過翻經臺下寺，與君同謁祖師堂。", "庭前紫桂葉頻脫，石上紅梅花正香。", "出洞陰雲分遠影，挂松寒日漏清光。", "謝公勸飯須無讓，不許非時薦茗湯。"]'),
('7c1321bb-628a-4ba0-ab58-63f6650f8e90','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','撥雲過得南隴去，流水激濺一澗長。',64,'全唐诗/poet.song.17000.json','["撥雲過得南隴去，流水激濺一澗長。", "盤石誰堆補缺岸，老松自倒成危梁。", "沙禽呼雌頻叫噪，山藥吐色常芬芳。", "臘去春歸山愈好，喜君共無塵事忙。"]'),
('85ff1683-4e92-4402-9d4b-86820e587852','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','天寒雨細日將暮，泥滑誰禁策馬還。',64,'全唐诗/poet.song.17000.json','["天寒雨細日將暮，泥滑誰禁策馬還。", "砂穴吐泉鳴決決，竹叢歸鳥語關關。", "聊睎謝客須穿屐，莫羨支公獨買山。", "方外論交情未淺，願陪投老白雲閒。"]'),
('ecdb18cd-a6bb-4b68-9c62-96a95ae8a97b','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','平昔詩禪友契深，更來人外事幽尋。',64,'全唐诗/poet.song.17000.json','["平昔詩禪友契深，更來人外事幽尋。", "雨餘澗壑流寒響，歲晏檉杉老翠陰。", "袒跣不妨陶令醉，風流多效洛生吟。", "山翁解榻延清賞，未放前賢勝竹林。"]'),
('39753ca3-759e-4391-80fa-42f5bc73acb7','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','燈火青熒雲塢寺，清猿叫斷有餘音。',64,'全唐诗/poet.song.17000.json','["燈火青熒雲塢寺，清猿叫斷有餘音。", "檻梅雪白春風近，山雨盆傾澗水深。", "背世跡憐高鳥跡，結交心契老松心。", "酬君秀句無新語，徒攪詩腸徹曙吟。"]'),
('124df8e5-3126-4792-9206-113751eb3c1f','同','釋惟晤','宋','宋诗','song-poetry','','[]','澗泉吾所好，山舍寂無喧。',48,'全唐诗/poet.song.17000.json','["澗泉吾所好，山舍寂無喧。", "春脈生雲底，夜聲來枕前。", "風休不動竹，月上未嗁猿。", "石上鳴逾急，泠然清夢魂。"]'),
('eea4dcad-c035-4dee-8cb7-cc28e2ff8309','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','掃携綠野村邊去，累日青山曠世機。',64,'全唐诗/poet.song.17000.json','["掃携綠野村邊去，累日青山曠世機。", "惜向永安蘭若別，還經靈隱渡頭歸。", "雲峰積雪迷樵徑，石罅新泉濺客衣。", "詩會未由陪帝戚，心隨雲鳥入城飛。"]'),
('9d62a443-ff93-475d-9d12-dbdd92259b2d','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','興高未肯輟清詩，捨轎重扶櫛栗枝。',64,'全唐诗/poet.song.17000.json','["興高未肯輟清詩，捨轎重扶櫛栗枝。", "松柏青肥春雨洗，煙雲輕健澗風吹。", "樵歸後塢連聲唱，鹿過前溪失隊悲。", "莫道還家甘寂默，陶潜自有五男兒。"]'),
('4f45e182-0c7e-487a-8ef9-ba8a1d2390bb','出山至中塗寄永安禪師','釋惟晤','宋','宋诗','song-poetry','','[]','松行未盡却回頭，寒雨霶沱已漸收。',64,'全唐诗/poet.song.17000.json','["松行未盡却回頭，寒雨霶沱已漸收。", "望海閣邊雲繚繞，行春橋下水奔流。", "山庵驟別高譚遠，城寺將歸滿面羞。", "須效著書同護法，悠悠人事漫拘囚。"]'),
('9270a9d3-966d-4927-b69b-2f8fb3ea0dc8','次韻和酬','釋惟晤','宋','宋诗','song-poetry','','[]','今日追懷昨日游，二君乘興似奔流。',64,'全唐诗/poet.song.17000.json','["今日追懷昨日游，二君乘興似奔流。", "遠尋幽壑行拖屐，累到深雲卧枕邱。", "崖竹蕭疏晴影亂，塢梅零落晚香收。", "會須重訪藤州老，更約高才沈隱侯。"]'),
('ee6e0f9f-07cc-49e0-87ad-3887b4c07966','次韻奉和','釋惟晤','宋','宋诗','song-poetry','','[]','白髮東山老，青林西塢歸。',48,'全唐诗/poet.song.17000.json','["白髮東山老，青林西塢歸。", "聽猿時駐錫，厲水自褰衣。", "高論才難敵，孤蹤行亦稀。", "慚君寄樵采，佳句出巖扉。"]'),
('7b8f6bcb-7e27-4c0a-befc-2458a728d603','次韻奉酬','釋惟晤','宋','宋诗','song-poetry','','[]','杜門誰復念吾曹，老畏春寒擁毳袍。',64,'全唐诗/poet.song.17000.json','["杜門誰復念吾曹，老畏春寒擁毳袍。", "懶慢從來徒自笑，唱酬今更怯君高。", "曾無道譽喧喧播，厭把肝脾苦苦勞。", "佳句忽來催野句，譬將凡果偪仙桃。"]'),
('8f7fa2a3-d7a7-4583-96cd-e1be4df84334','次韻奉酬仲靈歲暮還西塢見寄','釋{巩/言}元','宋','宋诗','song-poetry','','[]','野步溪流靜，源深興未歸。',48,'全唐诗/poet.song.17000.json','["野步溪流靜，源深興未歸。", "晚禽棲雪竹，殘霰灑禪衣。", "放意天涯遠，狂吟人跡稀。", "詩成寄我侶，清氣動禪扉。"]'),
('4c268597-4925-46eb-bd39-382eec5defcc','顔跖','歐陽修','宋','宋诗','song-poetry','','[]','顔回飲瓢水，陋巷卧曲肱。',156,'全唐诗/poet.song.17000.json','["顔回飲瓢水，陋巷卧曲肱。", "盜跖厭人肝，九州恣橫行。", "回仁而短命，跖壽死免兵。", "愚夫仰天呼，禍福豈足憑。", "跖身一腐鼠，死朽化無形。", "萬世尚遭戮，筆誅甚刀刑。", "思其生所得，豺犬飽臭腥。", "顔子聖人徒，生知自誠明。", "惟其生之樂，豈減跖所榮。", "死也至今在，光輝如日星。", "譬如埋金玉，不耗精與英。", "生死得失間，較量誰重輕。", "善惡理如此，毋尤天不平。"]'),
('54ac4a3d-bd8c-430a-bc5b-53ad38e0337d','猛虎','歐陽修','宋','宋诗','song-poetry','','[]','猛虎白日行，心閑貌揚揚。',180,'全唐诗/poet.song.17000.json','["猛虎白日行，心閑貌揚揚。", "當路擇人肉，羆豬不形相。", "頭垂尾不掉，百獸自然降。", "暗禍發所忽，有機埋路傍。", "徐行自踏之，機翻矢穿腸。", "怒吼震林丘，瓦落兒墮床。", "已死不敢近，目睛射餘光。", "虎勇恃其外，爪牙利鉤鋩。", "人形雖羸弱，智巧乃中藏。", "恃外可摧折，藏中難測量。", "英心多決烈，自信不猜防。", "老狐足姦計，安居穴垣牆。", "窮冬聽冰渡，思慮豈不長。", "引身入扱中，將死猶跳踉。", "狐姦固堪笑，虎猛誠可傷。"]'),
('8b67b633-41b6-4c32-84e9-d7ebb4bd8d6e','仙草','歐陽修','宋','宋诗','song-poetry','','[]','世說有仙草，得之能隱身。',96,'全唐诗/poet.song.17000.json','["世說有仙草，得之能隱身。", "仙書已怪妄，此事況無文。", "嗟爾得從誰，不辨僞與真。", "持行入都市，自謂術通神。", "白日攫黄金，磊落揀奇珍。", "旁人掩口笑，縱汝暫懽忻。", "汝方矜所得，謂世盡盲昏。", "非人不見汝，乃汝不見人。"]'),
('b2f57775-bd4a-4e01-8df6-183932194e62','遊龍門分題十五首 上山','歐陽修','宋','宋诗','song-poetry','','[]','躡蹻上高山，探險慕幽賞。',36,'全唐诗/poet.song.17000.json','["躡蹻上高山，探險慕幽賞。", "初驚澗芳早，忽望巖扉敞。", "林窮路已迷，但逐樵歌響。"]'),
('14849909-3227-4ade-989b-dd80626ba737','遊龍門分題十五首 下山','歐陽修','宋','宋诗','song-poetry','','[]','行歌翠微裏，共下山前路。',36,'全唐诗/poet.song.17000.json','["行歌翠微裏，共下山前路。", "千峯返照外，一鳥投巖去。", "渡口晚無人，繫舸芳洲樹。"]'),
('e002af23-4731-475b-9b4b-d73e4fee4ecd','遊龍門分題十五首 石樓','歐陽修','宋','宋诗','song-poetry','','[]','高灘復下灘，風急刺舟難。',36,'全唐诗/poet.song.17000.json','["高灘復下灘，風急刺舟難。", "不及樓中客，徘徊川上山。", "夕陽洲渚遠，唯見白鷗翻。"]'),
('dd4cf06a-7130-4b4b-af0f-a403738fdfff','遊龍門分題十五首 上方閣','歐陽修','宋','宋诗','song-poetry','','[]','聞鍾渡寒水，共步尋雲嶂。',36,'全唐诗/poet.song.17000.json','["聞鍾渡寒水，共步尋雲嶂。", "還隨孤鳥下，却望層林上。", "清梵遠猶聞，日暮空山響。"]'),
('193dc18c-df14-4932-9d14-340a5da8f9af','遊龍門分題十五首 伊川泛舟','歐陽修','宋','宋诗','song-poetry','','[]','春谿漸生溜，演漾迴舟小。',24,'全唐诗/poet.song.17000.json','["春谿漸生溜，演漾迴舟小。", "沙禽獨避人，飛去青林杪。"]'),
('c06fdf2d-6615-49f5-8fae-505c7949072d','遊龍門分題十五首 宿廣化寺','歐陽修','宋','宋诗','song-poetry','','[]','橫槎渡深澗，披露採香薇。',36,'全唐诗/poet.song.17000.json','["橫槎渡深澗，披露採香薇。", "樵歌雜梵響，共向松林歸。", "日落寒山慘，浮雲隨客衣。"]'),
('2c40e08a-559c-4ee2-ad66-8bdfd80c5bda','遊龍門分題十五首 自菩提步月歸廣化寺','歐陽修','宋','宋诗','song-poetry','','["\u6708\u4eae", "\u5c71\u6c34"]','春巖瀑泉響，夜久山已寂。',24,'全唐诗/poet.song.17000.json','["春巖瀑泉響，夜久山已寂。", "明月浄松林，千峯同一色。"]'),
('f3589fea-2387-4077-af92-22e45b340294','遊龍門分題十五首 八節灘','歐陽修','宋','宋诗','song-poetry','','[]','亂石瀉溪流，跳波濺如雪。',36,'全唐诗/poet.song.17000.json','["亂石瀉溪流，跳波濺如雪。", "往來川上人，朝暮愁灘闊。", "更待浮雲散，孤舟弄明月。"]'),
('3cc26305-dadd-4eaf-bcb6-21ba9d5438a8','遊龍門分題十五首 白傅墳','歐陽修','宋','宋诗','song-poetry','','[]','芳荃奠蘭酌，共弔松林裏。',24,'全唐诗/poet.song.17000.json','["芳荃奠蘭酌，共弔松林裏。", "溪口望山椒，但見浮雲起。"]'),
('4a554e05-1dcc-4b06-bef1-0d25b52caf5d','遊龍門分題十五首 晚登菩提上方','歐陽修','宋','宋诗','song-poetry','','[]','野色混晴嵐，蒼茫辨煙樹。',24,'全唐诗/poet.song.17000.json','["野色混晴嵐，蒼茫辨煙樹。", "行人下山道，猶向都門去。"]'),
('e7c6c89f-3c42-4433-a0d1-f38a455c0a6c','遊龍門分題十五首 山槎','歐陽修','宋','宋诗','song-poetry','','[]','古木卧山腰，危根老盤石。',36,'全唐诗/poet.song.17000.json','["古木卧山腰，危根老盤石。", "山中苦霜霰，歲久無春色。", "不如巖下桂，開花獨留客。"]'),
('089ea672-2298-4043-9f7a-aeac86b5121a','遊龍門分題十五首 石笋','歐陽修','宋','宋诗','song-poetry','','[]','巨石何亭亭，孤生此巖側。',36,'全唐诗/poet.song.17000.json','["巨石何亭亭，孤生此巖側。", "白雲與翠霧，誰見琅玕色。", "惟應山鳥飛，百轉時來息。"]'),
('7afbea11-47e7-4636-8beb-23e960097d2a','遊龍門分題十五首 鴛鴦','歐陽修','宋','宋诗','song-poetry','','[]','畫舷鳴兩槳，日暮芒洲路。',36,'全唐诗/poet.song.17000.json','["畫舷鳴兩槳，日暮芒洲路。", "泛泛風波鳥，雙雙弄紋羽。", "愛之欲移舟，漸近還飛去。"]'),
('3d61666a-da00-455f-af47-90e4fe85ce60','遊龍門分題十五首 魚罾','歐陽修','宋','宋诗','song-poetry','','[]','春水弄春沙，蕩漾流不極。',36,'全唐诗/poet.song.17000.json','["春水弄春沙，蕩漾流不極。", "笭箵苦難滿，終日沙頭客。", "向暮卷空罾，棹歌菱浦北。"]'),
('47a8d8fb-8682-4bd5-9ea3-3782edb55758','遊龍門分題十五首 魚鷹','歐陽修','宋','宋诗','song-poetry','','[]','日色弄晴川，時時錦鱗躍。',36,'全唐诗/poet.song.17000.json','["日色弄晴川，時時錦鱗躍。", "輕飛若下韝，豈畏風灘惡。", "人歸晚渚靜，獨傍漁舟落。"]'),
('9b9ca9f9-4ef0-4141-9413-13a87bff6791','伊川獨遊','歐陽修','宋','宋诗','song-poetry','','[]','東郊漸微綠，驅馬忻獨往。',48,'全唐诗/poet.song.17000.json','["東郊漸微綠，驅馬忻獨往。", "梅繁野渡晴，泉落春山響。", "身閑愛物外，趣遠諧心賞。", "歸路逐樵歌，落日寒川上。"]'),
('cb097f3e-c1f1-45a8-ab11-9baf98723554','三遊洞','歐陽修','宋','宋诗','song-poetry','','[]','漾檝泝清川，捨舟緣翠嶺。',152,'全唐诗/poet.song.17000.json','["漾檝泝清川，捨舟緣翠嶺。", "探奇冒層嶮，因以窮人境。", "弄舟終日愛雲山，徒見青蒼杳靄間。", "誰知一室煙霞裏，乳竇雲腴凝石髓。", "蒼崖一徑橫查渡，翠壁千尋當戶起。", "昔人心賞爲誰留，人去山阿跡更幽。", "青蘿綠桂何岑寂，山鳥嘐嘐不驚客。", "松鳴澗底自生風，月出林間來照席。", "仙境難尋復易迷，山回路轉向人知。", "惟應洞口春花落，流出巖前百丈谿。"]'),
('aaff113e-155a-4bf3-a572-c97bce2290c1','下牢溪','歐陽修','宋','宋诗','song-poetry','','[]','隔谷聞溪聲，尋溪度橫嶺。',48,'全唐诗/poet.song.17000.json','["隔谷聞溪聲，尋溪度橫嶺。", "清流涵白石，靜見千峯影。", "巖花無時歇，翠栢鬰何整。", "安能戀潺湲，俯仰弄雲景。"]'),
('74c615e9-a7f9-467e-a8fe-99a4e0ea7486','蝦蟆碚','歐陽修','宋','宋诗','song-poetry','','[]','石溜吐陰崖，泉聲滿空谷。',48,'全唐诗/poet.song.17000.json','["石溜吐陰崖，泉聲滿空谷。", "能邀弄泉客，繫舸留巖腹。", "陰精分月窟，水味標茶錄。", "共約試春芽，槍旗幾時綠。"]'),
('50adecaa-0a77-49fe-bd91-8dacfd3fa369','黄牛峽祠','歐陽修','宋','宋诗','song-poetry','','[]','大川雖有神，淫祀亦其俗。',136,'全唐诗/poet.song.17000.json','["大川雖有神，淫祀亦其俗。", "石馬繫祠門，山鵶噪叢木。", "潭潭村鼓隔溪聞，楚巫歌舞送迎神。", "畫船百丈山前路，上灘下峽長來去。", "江水東流不暫停，黄牛千古長如故。", "峽山侵天起青嶂，崖崩路絕無由上。", "黄牛不下江頭飲，行人惟向舟中望。", "朝朝暮暮見黄牛，徒使行人過此愁。", "山高更遠望猶見，不是黄牛滯客舟。"]'),
('60406864-eedf-42b9-ab1e-f9b463f67cd1','千葉紅梨花','歐陽修','宋','宋诗','song-poetry','','[]','紅梨千葉愛者誰，白髮郎官心好奇。',160,'全唐诗/poet.song.17000.json','["紅梨千葉愛者誰，白髮郎官心好奇。", "徘徊繞樹不忍折，一日千匝看無時。", "夷陵寂寞千山裏，地遠氣偏時節異。", "愁煙苦霧少芳菲，野卉蠻花鬭紅紫。", "可憐此樹生此處，高枝絕艷無人顧。", "春風吹落復吹開，山鳥飛來自飛去。", "根盤樹老幾經春，真賞今纔遇使君。", "風輕絳雪罇前舞，日暖繁香露下聞。", "從來奇物產天涯，安得移根植帝家。", "猶勝張騫爲漢使，辛勤西域徙榴花。"]'),
('ef824511-c0f5-43cc-b5c3-3a494d88d445','金雞五言十四韻','歐陽修','宋','宋诗','song-poetry','','[]','蠻荆鮮人秀，厥美爲物怪。',168,'全唐诗/poet.song.17000.json','["蠻荆鮮人秀，厥美爲物怪。", "禽鳥得之多，山雞稟其粹。", "眾綵爛成文，真色不可繪。", "仙衣霓紛披，女錦花綷縩。", "輝華日光亂，眩轉目晴憊。", "高田啄秋粟，下澗飲寒瀨。", "清唳或相呼，舞影還自愛。", "豈知文章累，遂使網羅掛。", "及禍誠有媒，求友反遭賣。", "有身乃吾患，斷尾亦前戒。", "不羣世所驚，甚美眾之害。", "稻粱雖云厚，樊縶豈爲泰。", "山林歸無期，羽翮日已鎩。", "用晦有前言，書之可爲誡。"]'),
('79e3f803-fc82-4e69-99da-fc087f005e7e','和丁寶臣遊甘洋寺','歐陽修','宋','宋诗','song-poetry','','[]','江上孤峯蔽綠蘿，縣樓終日對嵯峩。',160,'全唐诗/poet.song.17000.json','["江上孤峯蔽綠蘿，縣樓終日對嵯峩。", "叢林已廢姜祠在，事迹難尋楚語訛。", "空餘一派寒巖側，澄碧泓渟涵玉色。", "野僧豈解惜清泉，蠻俗那知爲勝迹。", "西陵老令好尋幽，時共登臨向此遊。", "欹危一逕穿林樾，盤石蒼苔留客歇。", "山深雲日變陰晴，澗栢巖松度歲青。", "谷裏花開知地暖，林間鳥語作春聲。", "依依渡口夕陽時，却望層巒在翠微。", "城頭暮鼓休催客，更待橫江弄月歸。"]'),
('feddb1c8-50fc-40c6-bd4c-d703214bfe62','送京西提點刑獄張駕部','歐陽修','宋','宋诗','song-poetry','','[]','太華之松千歲肯，嘗聞其下多茯苓。',176,'全唐诗/poet.song.17000.json','["太華之松千歲肯，嘗聞其下多茯苓。", "地靈山秀草木異，往往變化爲人形。", "神仙不欲世人採，覆以雲氣常冥冥。", "臺郎何年得真訣，服餌既久毛骨清。", "汝陽昔見今十載，丹顔益少方瞳明。", "郡齋政成罇俎樂，高談日接無俗情。", "詔書忽下襃美績，使車朝出行屬城。", "職清事簡稱雅意，蠹書古篋晨裝輕。", "洛陽花色笑春日，錦衣晝歸閭里驚。", "自云就欲謝官去，烏紗白髮西臺卿。", "他年我亦老嵩少，願乞仙粒分餘馨。"]'),
('1056e7d2-2c79-45d3-a34e-279fca00a1ff','贈杜默','歐陽修','宋','宋诗','song-poetry','','[]','南山有鳴鳳，其音和且清。',240,'全唐诗/poet.song.17000.json','["南山有鳴鳳，其音和且清。", "鳴於有道國，出則天下平。", "杜默東土秀，能吟鳳凰聲。", "作詩幾百篇，長歌仍短行。", "携之入京邑，欲使眾耳驚。", "來時上師堂，再拜辭先生。", "先生頷首遣，教以勿驕矜。", "贈之三豪篇，而我濫一名。", "杜子來訪我，欲求相和鳴。", "顧我文字卑，未足當豪英。", "豈如子之辭，鏗鍠間鏞笙。", "淫哇俗所樂，百鳥徒嚶嚶。", "杜子卷舌去，歸衫翩以輕。", "京東聚羣盜，河北點新兵。", "饑荒與愁苦，道路日以盈。", "子盍引其吭，發聲通下情。", "上聞天子聰，次使宰相聽。", "何必九包禽，始能瑞堯庭。", "子詩何時作，我耳入已傾。", "願以白玉琴，寫之朱絲繩。"]'),
('ed57920b-e3ac-42f9-bece-5c5cea451048','送呂夏卿','歐陽修','宋','宋诗','song-poetry','','[]','始吾尚幼學弄筆，羣兒爭誦公初文。',192,'全唐诗/poet.song.17000.json','["始吾尚幼學弄筆，羣兒爭誦公初文。", "嗟我今年已白髮，公初相見猶埃塵。", "傳家尚喜有二子，始知靈珠出淮濱。", "去年束書來上國，欲以文字驚眾人。", "駑駘羣馬斂足避，天衢讓路先騏驎。", "尚書禮部奏高第，斂衣襆硯趨嚴宸。", "曈曈春日轉黄傘，藹藹賦筆摛青雲。", "我時寓直殿廬外，眾中迎子笑以忻。", "明朝失意落人後，我爲沮氣羞出門。", "得官高要幾千里，猶幸海遠無惡氛。", "英英帝圃多鸞凰，上下羽翼何繽紛。", "期子當呼丹山鳳，爲瑞相與來及羣。"]'),
('38b53868-8f4a-4181-9ecc-85eca67465b4','憶山示聖俞','歐陽修','宋','宋诗','song-poetry','','[]','吾思夷陵山，山亂不可究。',288,'全唐诗/poet.song.17000.json','["吾思夷陵山，山亂不可究。", "東城一堠餘，高下漸岡阜。", "羣峯迤邐接，四顧無前後。", "憶嘗祗吏役，鉅細悉經覯。", "是時秋卉紅，嶺谷堆纈繡。", "林枯松鱗皴，山老石脊瘦。", "斷徑履頹崖，孤泉聽清溜。", "深行得平川，古俗見耕耨。", "澗荒驚麏奔，日出飛雉雊。", "盤石屢欹眠，綠巖堪解綬。", "幽尋歎獨往，清興思誰侑。", "其西乃三峽，嶮怪愈奇富。", "江如自天傾，岸立兩崖鬭。", "黔巫望西屬，越嶺通南奏。", "時時縣樓對，雲霧昏白晝。", "荒煙下牢戍，百仞寒溪漱。", "蝦蟆噴水簾，甘液勝飲酎。", "亦嘗到黄牛，泊舟聽猿狖。", "巉巉起絕壁，蒼翠非刻鏤。", "陰巖下攢叢，岫穴忽空透。", "遥岑聳孤出，可愛欣欲就。", "惟思得君詩，古健寫奇秀。", "今來會京師，車馬逐塵瞀。", "頹冠名白髮，舉酒無蒨袖。"]'),
('c1b6fe3a-964c-4c38-9534-8be4ebcbb3db','送唐生','歐陽修','宋','宋诗','song-poetry','','[]','京師英豪域，車馬日紛紛。',132,'全唐诗/poet.song.17000.json','["京師英豪域，車馬日紛紛。", "唐生萬里客，一影隨一身。", "出無車與馬，但踏車馬塵。", "日食不自飽，讀書依主人。", "夜夜客枕夢，北風吹孤雲。", "翩然動歸思，旦夕來叩門。", "終年少人識，逆旅惟我親。", "來學媿道矒，贈歸慚橐貧。", "勉之期不止，多穫由力耘。", "指家大嶺北，重湖浩無垠。", "飛鴈不可到，書來安得頻。"]'),
('3981b563-7325-4066-8243-656c1d8fc092','送任處士歸太原','歐陽修','宋','宋诗','song-poetry','','[]','一虜動邊陲，用兵三十萬。',192,'全唐诗/poet.song.17000.json','["一虜動邊陲，用兵三十萬。", "天威豈不嚴，賊首猶未獻。", "自古王者師，有征而不戰。", "勝敗繫人謀，得失由廟算。", "是以天子明，咨詢務周徧。", "直欲採奇謀，不爲人品限。", "公車百千輩，下不遺僕賤。", "況於儒學者，延納宜無間。", "如何任生來，三月不得見。", "方茲急士時，論擇豈宜慢。", "任生居太原，白首勤著撰。", "閉戶不求聞，忽來誰所薦。", "人堅固當用，舉繆不加譴。", "賞罰兩無文，是非奚以辨。", "遂令拂衣歸，安使來者勸。", "嗟吾筆與舌，非職不敢諫。"]'),
('36b5ac45-569a-4505-9ab6-2278eb808fc8','聖俞會飲','歐陽修','宋','宋诗','song-poetry','','[]','傾壺豈徒彊君飲，解带且欲留君談。',192,'全唐诗/poet.song.17000.json','["傾壺豈徒彊君飲，解带且欲留君談。", "洛陽舊友一時散，十年會合無二三。", "京師旱久塵土熱，忽值晚雨凉纖纖。", "滑公井泉釀最美，赤泥印酒新開緘。", "更吟君句勝啖炙，杏花妍媚春酣酣。", "吾交豪俊天下選，誰得眾美如君兼。", "詩工鑱刻露天骨，將論縱橫輕玉鈐。", "遺編最愛孫武說，往往曹杜遭夷芟。", "關西幕府不能辟，隴山敗將死可慚。", "嗟余身賤不敢薦，四十白髮猶青衫。", "吳興太守詩亦好，往奏玉琯和英咸。", "盃行到手莫辭醉，明日舉棹天東南。"]'),
('4dbfa3e2-9a91-4deb-b7a1-aa4c7e751cb3','送胡學士知湖州','歐陽修','宋','宋诗','song-poetry','','[]','武平天下才，四才滯鉛槧。',96,'全唐诗/poet.song.17000.json','["武平天下才，四才滯鉛槧。", "忽乘使君舟，歸榜不可纜。", "都門春漸動，柳色綠將暗。", "掛帆千里風，水闊江灧灧。", "吳興水精宮，樓閣在寒鑑。", "橘柚秋苞繁，烏程春甕釅。", "清談越客醉，屢舞吳娘豔。", "寄詩毋憚頻，以慰離居念。"]'),
('8a737974-a2ca-4b0f-bf2d-d593c86d424b','哭曼卿','歐陽修','宋','宋诗','song-poetry','','[]','嗟我識君晚，君時猶壯夫。',264,'全唐诗/poet.song.17000.json','["嗟我識君晚，君時猶壯夫。", "信哉天下奇，落落不可拘。", "軒昂懼驚俗，自隱酒之徒。", "一飲不計斗，傾河竭崑墟。", "作詩幾百篇，錦組聯瓊琚。", "時時出險語，意外研精麤。", "窮奇變雲煙，搜怪蟠蛟魚。", "詩成多自寫，筆法顔與虞。", "旋棄不復惜，所存今幾餘。", "往往落人間，藏之比明珠。", "又好題屋壁，虹蜺隨卷舒。", "遺蹤處處在，餘墨潤不枯。", "朐山頃歲出，我亦斥江湖。", "乖離四五載，人事忽焉殊。", "歸來見京師，心老貌已癯。", "但驚何其衰，豈意今也無。", "才高不少下，闊若與世踈。", "驊騮當少時，其志萬里塗。", "一旦老伏櫪，猶思主山芻。", "天兵宿西北，狂兒尚稽誅。", "而令壯士死，痛惜無賢愚。", "歸魂渦上田，露草荒春蕪。"]'),
('1f49f3f5-d847-48b8-8180-3f26a3add9d7','送曇穎歸廬山','歐陽修','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','吾聞廬山久，欲往世欲拘。',204,'全唐诗/poet.song.17000.json','["吾聞廬山久，欲往世欲拘。", "昔歲貶夷陵，扁舟下江湖。", "八月到湓口，停帆望香爐。", "香爐雲霧間，杳靄疑有無。", "忽值秋日明，彩翠浮空虛。", "信哉奇且秀，不與灊霍俱。", "偶病不時往，中流但踟躕。", "今思尚髣髴，恨不傳畫圖。", "曇穎十年舊，風塵客京都。", "一旦不辭訣，飄然卷衣裾。", "山林往不返，古亦有吾儒。", "西北苦兵戰，江南仍旱枯。", "新秦又攻寇，京陜募兵夫。", "聖君念蒼生，賢相思良謨。", "嗟我無一說，朝紳拖舒舒。", "未能膏鼎鑊，又不老菰蒲。", "羨子識所止，雙林歸結廬。"]'),
('77f3c742-5d0a-4019-b305-d047fc356999','送孔秀才遊河北','歐陽修','宋','宋诗','song-poetry','','[]','吾始未識子，但聞楊公賢。',60,'全唐诗/poet.song.17000.json','["吾始未識子，但聞楊公賢。", "及子來叩門，手持贈子篇。", "賢愚視所與，不待交子言。", "子文諧律呂，子行潔琅玕。", "行矣慎所遊，惡草能敗蘭。"]'),
('04e1156a-2622-4595-8b94-1292bb01f00a','送黎生下第還蜀','歐陽修','宋','宋诗','song-poetry','','[]','黍離不復雅，孔子修春秋。',144,'全唐诗/poet.song.17000.json','["黍離不復雅，孔子修春秋。", "扶王貶吳楚，大法加諸侯。", "妄儒泥於魯，甚者云黜周。", "大旨既已矣，安能討源流。", "遂令學者迷，異說相交鉤。", "黎生西南秀，挾策來東遊。", "有司不見採，春霜滑歸輈。", "自云喜三傳，力欲探微幽。", "凡學患不彊，苟至將焉庾。", "聖言簡且直，慎勿迂其求。", "經通道自明，下筆如戈矛。", "一改不足衄，後功掩前羞。"]'),
('4b30084a-df98-4c76-a7ff-8188b4125483','送楊闢秀才','歐陽修','宋','宋诗','song-poetry','','[]','吾奇曾生者，始得之太學。',228,'全唐诗/poet.song.17000.json','["吾奇曾生者，始得之太學。", "初謂獨軒然，百鳥而一鶚。", "既又得楊生，羣獸出麟角。", "乃知天下才，所識慚未博。", "楊生初誰師，仁義而禮樂。", "天姿樸且茂，美不待追琢。", "始來讀其文，如渴飲醴酪。", "既坐即之談，稍稍吐鋒鍔。", "非唯富春秋，固已厚天爵。", "有司選羣材，繩墨困量度。", "胡爲謹毫分，而使遺磊落。", "至寶異常珍，夜光驚把握。", "駭者棄諸塗，竊拾充吾橐。", "其於獲二生，厥價玉一瑴。", "嗟吾雖得之，氣力獨何弱。", "帝閽啟巖巖，欲獻前復却。", "遽令扁舟下，飄若吹霜籜。", "世好競辛鹹，古味殊淡泊。", "否泰理有時，惟窮見其確。"]'),
('1e8b652a-8eb4-45ab-b408-7ff261bde31c','送孔生再遊河北','歐陽修','宋','宋诗','song-poetry','','[]','志士惜白日，高車無停輪。',132,'全唐诗/poet.song.17000.json','["志士惜白日，高車無停輪。", "孔生東魯儒，年少勇且仁。", "大軸獻理匭，長裾弊街塵。", "門無黄金聘，家有白髮親。", "寒風八九月，北渡大河津。", "玉塞積精甲，金戈輝秋雲。", "孔生力數斗，其智兼千人。", "短褐不自暖，高談吐陽春。", "北州多賢侯，待士誰最勤。", "一見贈雙璧，再見延上賓。", "丈夫患不遇，豈患長賤貧。"]'),
('a86f3135-4f99-4849-b7c0-321c84196af2','送慧勤歸餘杭','歐陽修','宋','宋诗','song-poetry','','[]','越欲僭宮室，傾貲事雕牆。',264,'全唐诗/poet.song.17000.json','["越欲僭宮室，傾貲事雕牆。", "佛屋尤其侈，耽耽擬侯王。", "文彩瑩丹漆，四壁金焜煌。", "上懸百寶蓋，宴坐以方牀。", "胡爲棄不居，棲身客京坊。", "辛勤營一室，有類燕巢梁。", "南方精飲食，菌笋鄙羔羊。", "飯以玉粒粳，調之甘露漿。", "一饌費千金，百品羅成行。", "晨興未飯僧，日昃不敢嘗。", "乃茲隨北客，枯粟充饑腸。", "東南地秀絕，山水澄清光。", "餘杭幾萬家，日夕焚清香。", "煙霏四面起，雲霧雜芬芳。", "豈如車馬塵，鬢髮染成霜。", "三者孰苦樂，子奚勤四方。", "乃云慕仁義，奔走不自遑。", "始知仁義力，可以治膏肓。", "有志誠可樂，及時宜自彊。", "人情重懷土，飛鳥思故鄉。", "夜枕聞北鴈，歸心逐南檣。", "歸兮能來否，送子以短章。"]'),
('1eb48d59-5762-4335-9a51-88e38635ffd5','讀張李二生文贈石先生','歐陽修','宋','宋诗','song-poetry','','[]','先生二十年東魯，能使魯人皆好學。',240,'全唐诗/poet.song.17000.json','["先生二十年東魯，能使魯人皆好學。", "其間張續與李常，剖琢珉石得天璞。", "大圭雖不假雕瑑，但未磨礲出圭角。", "二生因是天下寶，豈與先生私褚橐。", "先生示我何矜誇，手携文編謂新作。", "得之數日未暇讀，意欲百事先屏却。", "夜歸獨坐南窗下，寒燭青熒如熠爚。", "病眸昏澀乍開緘，燦若月星明錯落。", "辭嚴意正質非俚，古味雖淡醇不薄。", "千年佛老賊中國，禍福依憑羣黨惡。", "拔根掘窟期必盡，有勇無前力何犖。", "乃知二子果可用，非獨詞堅由志確。", "朝廷清明天子聖，陽德彙進羣陰剝。", "大烹養賢有列鼎，豈久師門共藜藿。", "予慚職諫未能薦，有酒且慰先生酌。"]'),
('80083e91-b402-4e26-aacc-ccaac9b8d64b','絳守居園池','歐陽修','宋','宋诗','song-poetry','','[]','嘗聞紹述絳守居，偶來覽登周四隅。',192,'全唐诗/poet.song.17000.json','["嘗聞紹述絳守居，偶來覽登周四隅。", "異哉樊子怪可吁，心欲獨出無古初。", "窮荒搜幽入有無，一語詰曲百盤紆。", "孰云已出不剽襲，句斷欲學盤庚書。", "荒煙古水蔚遺墟，我來嗟祗得其餘。", "栢槐端莊偉丈夫，蒼顔鬰鬰老不枯。", "靚容新麗一何姝，清池翠蓋擁紅蕖。", "胡鬅虎搏豈足道，記錄細碎何區區。", "虙氏八卦畫河圖，禹湯臯虺暨唐虞。", "豈不古奧萬世模，嫉世姣巧習卑汙。", "以奇矯薄駭羣愚，用此猶得追韓徒。", "我思其人爲躊躇，作詩聊謔爲坐娛。"]'),
('460d6ff3-bd3a-4e8b-8473-fab89e9d4a1c','晉祠','歐陽修','宋','宋诗','song-poetry','','[]','古城南出十里間，鳴渠夾路何潺潺。',192,'全唐诗/poet.song.17000.json','["古城南出十里間，鳴渠夾路何潺潺。", "行人望祠下馬謁，退即祠下窺水源。", "地靈草木得餘潤，鬰鬰古栢含蒼煙。", "并兒自古事豪俠，戰爭五代幾百年。", "天開地闢真主出，猶須再駕方凱旋。", "頑民盡遷高壘削，秋草自綠埋空垣。", "并人昔遊晉水上，清鏡照耀涵朱顔。", "晉水今入并州裏，稻花漠漠澆平田。", "廢興髣髴無舊老，氣象寂寞餘山川。", "惟存祖宗聖功業，干戈象舞被管絃。", "我來覽登爲歎息，暫照白髮臨清泉。", "鳥啼人去廟門闔，還有山月來娟娟。"]'),
('8f180a6e-f75e-4243-946d-8df3d2b2791b','登絳州富公嵩巫亭示同行者','歐陽修','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','羣峯擁軒檻，竹樹陰漠漠。',252,'全唐诗/poet.song.17000.json','["羣峯擁軒檻，竹樹陰漠漠。", "公胡苦思山，規構自心作。", "惟予愛山者，初仕即京洛。", "嵩峯三十六，終日對高閣。", "陰晴無朝暮，紫氣常浮泊。", "雄然九州中，氣象壓寥廓。", "亦嘗步其巔，培塿視四岳。", "其後竄荆蠻，始識峽山惡。", "長江瀉天來，巨石忽開拓。", "始疑茫昧初，渾沌死鎸鑿。", "神功夜催就，萬仞成一削。", "尤奇十二峯，隱見入冥邈。", "人蹤斷攀緣，異物定所託。", "顧瞻但徘徊，想像逢綽約。", "嵩山近可愛，泉石吾已諾。", "終其以幽人，白首老雲壑。", "荆巫惜遐荒，詭怪杳難貌。", "至今清夜思，魂夢輒飛愕。", "偶來玩茲亭，塵眼刮昏膜。", "況逢秋雨霽，濃翠新染濯。", "峯端上明月，且可留幽酌。"]'),
('c904692d-e2cb-41c0-907a-55a52dce4cff','水谷夜行寄子美聖俞','歐陽修','宋','宋诗','song-poetry','','[]','寒雞號荒林，山壁月倒掛。',288,'全唐诗/poet.song.17000.json','["寒雞號荒林，山壁月倒掛。", "披衣起視夜，攬轡念行邁。", "我來夏云初，素節今已屆。", "高河瀉長空，勢落九州外。", "微風動涼襟，曉氣清餘睡。", "緬懷京師友，文酒邈高會。", "其問蘇與梅，二字可畏愛。", "篇章富縱橫，聲價相磨蓋。", "子美氣尤雄，萬竅號一噫。", "有時肆顛狂，醉墨灑霶霈。", "譬如千里馬，已發不可殺。", "盈前盡珠璣，一一難柬汰。", "梅翁事清切，石齒漱寒瀨。", "作詩三十年，視我猶後輩。", "文詞愈清新，心意雖老大。", "譬如妖韶女，老自有餘態。", "近詩尤古硬，咀嚼苦難嘬。", "初如食橄欖，真味久愈在。", "蘇豪以氣轢，舉世徒驚駭。", "梅窮獨我知，古貨今難賣。", "二子雙鳳凰，百鳥之嘉瑞。", "雲煙一翱翔，羽翮一摧鎩。", "安得相從遊，終日鳴噦噦。", "問胡苦思之，對酒把新蟹。"]'),
('2cb31e1a-5972-41bb-bae0-02a2f7e301ac','病中代書奉寄聖俞二十五兄','歐陽修','宋','宋诗','song-poetry','','[]','憶君去年來自越，值我傳車催去闕。',336,'全唐诗/poet.song.17000.json','["憶君去年來自越，值我傳車催去闕。", "是時新秋蟹正肥，恨不一醉與君別。", "今年得疾因酒作，一春不飲氣彌劣。", "饑腸未慣飽甘脆，九蟲寸白爭爲孽。", "一飽猶能致身患，寵祿豈無神所罰。", "乃知賦予分有涯，適分自然無夭閼。", "昔在洛陽年少時，春思每先花亂發。", "萌芽不待楊柳動，探春馬蹄常踏雪。", "到今年纔三十九，怕見新花羞白髮。", "顔侵塞下風霜色，病過鎮陽桃李月。", "兵閑事簡居可樂，心意自衰非屑屑。", "日長天暖惟欲睡，睡美尤厭春鳩聒。", "北潭去城無百步，淥水冰銷魚撥剌。", "經時曾未著脚到，好景但聽遊人說。", "官榮雖厚世味薄，始信衣纓乃羈紲。", "故人有幾獨思君，安得見君憂暫豁。", "公厨酒美遠莫致，念君貰飲衣屢脫。", "郭生書來猶未到，想見新詩甚饑渴。", "少年事事今已去，惟有愛詩心未歇。", "君閑可能爲我作，莫辭自書藤紙滑。", "少低筆力容我和，無使難追韻高絕。"]'),
('eef20d36-6157-4006-98f0-c5e4c190a012','鎮陽殘杏','歐陽修','宋','宋诗','song-poetry','','[]','鎮陽二月春苦寒，東風力弱冰雪頑。',144,'全唐诗/poet.song.17000.json','["鎮陽二月春苦寒，東風力弱冰雪頑。", "北潭跬步病不到，何暇騎馬尋郊原。", "鵰丘新晴暖已動，砌下流水來潺潺。", "但聞簷間鳥語變，不覺桃杏開已闌。", "人生一世浪自苦，盛衰桃杏開落間。", "西亭昨日偶獨到，猶有一樹當南軒。", "殘芳爛漫看更好，皓若春雪團枝繁。", "無風已恐自零落，長條可愛不可攀。", "猶堪携酒醉其下，誰肯伴我頹巾冠。"]'),
('897c6751-683e-4c35-b92e-315303535dfe','班班林間鳩寄內','歐陽修','宋','宋诗','song-poetry','','[]','班班林間鳩，穀穀命其匹。',288,'全唐诗/poet.song.17000.json','["班班林間鳩，穀穀命其匹。", "迨天之未雨，與汝勿相失。", "春原洗新霽，綠葉暗朝日。", "鳴聲相呼和，應答如吹律。", "深棲柔桑暖，下啄高田實。", "人皆笑汝拙，無巢以家室。", "易安由寡求，吾羨拙之佚。", "吾雖有室家，出處曾不一。", "荆蠻昔竄逐，奔走若鞭抶。", "山川瘴霧深，江海波濤䫻。", "跬步子所同，淪棄甘共沒。", "投身去人眼，已廢誰復嫉。", "山花與野草，我醉子鳴瑟。", "但知貧賤安，不覺歲月忽。", "還朝今幾年，官祿霑兒姪。", "身榮責愈重，器小憂常溢。", "今年來鎮陽，留滯見春物。", "北潭新漲淥，魚鳥相聱䎲。", "我意不在春，所憂空自咄。", "一官誠易了，報國何時畢。", "高堂母老矣，衰髮不滿櫛。", "昨日寄書言，新陽發舊疾。", "藥食子雖勤，豈若我在膝。", "又云子亦病，蓬首不加髴。"]'),
('d6b5cd7b-50e2-4d2b-86ef-9b4c1c1a1eb5','暮春門有感','歐陽修','宋','宋诗','song-poetry','','[]','幽憂無以銷，春日靜愈長。',120,'全唐诗/poet.song.17000.json','["幽憂無以銷，春日靜愈長。", "薰風入花骨，花枝午低昂。", "往來採花蜂，清蜜未滿房。", "春事已爛漫，落英漸飄揚。", "蛺蝶無所爲，飛飛助其忙。", "啼鳥亦屢變，新音巧調篁。", "遊絲最無事，百尺拖晴光。", "天工施造化，萬物感春陽。", "我獨不知春，久病卧空堂。", "時節去莫挽，浩歌自成傷。"]'),
('41f6795e-5d0d-44f3-92dc-1320b07b0b48','洛陽牡丹圖','歐陽修','宋','宋诗','song-poetry','','[]','洛陽地脈花最宜，牡丹尤爲天下奇。',320,'全唐诗/poet.song.17000.json','["洛陽地脈花最宜，牡丹尤爲天下奇。", "我昔所記數十種，於今十年半忘之。", "開圖若見故人面，其間數種昔未窺。", "客言近歲花特異，往往變出呈新枝。", "洛人驚誇立名字，買種不復論家貲。", "比新較舊難優劣，爭先擅價各一時。", "當時絕品可數者，魏紅窈窕姚黄妃。", "壽安細葉開尚少，朱砂玉版人未知。", "傳聞千葉昔未有，只從左紫名初馳。", "四十年間花百變，最後最好潛溪緋。", "今花雖新我未識，未信與舊誰妍媸。", "當時所見已云絕，豈有更好此可疑。", "古稱天下無正色，但恐世好隨時移。", "鞓紅鶴翎豈不美，斂色如避新來姬。", "何況遠說蘇與賀，有類異世誇嬙施。", "造化無情宜一槩，偏此著意何其私。", "又疑人心愈巧僞，天欲鬭巧窮精微。", "不然元化朴散久，豈特近歲尤澆漓。", "爭新鬭麗若不已，更後百載知何爲。", "但應新花日愈好，惟有我老年年衰。"]'),
('fa3d3d71-fa73-4d6b-9319-2404e52bb316','鎮陽讀書','歐陽修','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','春深夜苦短，燈冷焰不長。',288,'全唐诗/poet.song.17000.json','["春深夜苦短，燈冷焰不長。", "塵蠹文字細，病眸澁無光。", "坐久百骸倦，中遭羣慮戕。", "尋前顧後失，得一念十忘。", "乃知學在少，老大不可彊。", "廢書誰與語，歎息自悲傷。", "因憶石夫子，徂徠有茅堂。", "前年來京師，講學居上庠。", "青衫綴朝士，面有數畝桑。", "不耐羣兒嗤，束書歸故鄉。", "却尋茅堂在，高卧泰山傍。", "聖經日陳前，弟子羅兩廂。", "大論叱佛老，高聲誦虞唐。", "賓朋足棗栗，兒女飽糟糠。", "雖云待官闕，便欲解朝裳。", "有似蠶作繭，縮身思自藏。", "嗟我一何愚，貪得不自量。", "平生事筆硯，自可娛文章。", "開口攬時事，論議爭煌煌。", "退之嘗有云，名聲暫羶香。", "誤蒙天子知，侍從列班行。", "官榮日已寵，事業闇不彰。", "器小以任大，躋顛理之常。", "聖君雖不誅，在汝豈自遑。"]'),
('560797c2-7287-49d1-beb4-9ba77055c720','留題鎮陽潭園','歐陽修','宋','宋诗','song-poetry','','[]','官雖鎮陽居，身是鎮陽客。',192,'全唐诗/poet.song.17000.json','["官雖鎮陽居，身是鎮陽客。", "北園潭上花，安問誰所植。", "春風無先後，爛漫爭紅白。", "一花聊一醉，盡醉猶須百。", "而我病不飲，對花空歎息。", "朝來不能歸，暮看不忍摘。", "謂言花縱落，滿地猶可席。", "不來纔幾時，人事已非昔。", "芳枝結青杏，翠葉新奕奕。", "落絮風卷盡，春歸不留迹。", "空餘綠潭水，尚带餘春色。", "疑春竟何之，意謂追可得。", "東西遶潭行，峰鳥已寂寂。", "惘然無所依，歸駕不停軛。", "寓興誠可樂，留情豈非惑。", "至今清夜夢，猶遶北潭北。"]'),
('be1f9f95-2c13-499b-94ce-299a5e88eb97','讀蟠桃詩寄子美','歐陽修','宋','宋诗','song-poetry','','[]','韓孟於文詞，兩雄力相當。',288,'全唐诗/poet.song.17000.json','["韓孟於文詞，兩雄力相當。", "篇章綴談笑，雷電擊幽荒。", "眾鳥誰敢和，鳴鳳呼其凰。", "孟窮苦纍纍，韓富浩穰穰。", "窮者啄其精，富者爛文章。", "發生一爲宮，揫斂一爲商。", "二律雖不同，合奏乃鏘鏘。", "天之產奇怪，希世不可常。", "寂寥二百年，至寶埋無光。", "郊死不爲島，聖俞發其藏。", "患世愈不出，孤吟夜號霜。", "霜寒入毛骨，清響哀愈長。", "玉山禾難熟，終歲苦饑腸。", "我不能飽之，更欲不自量。", "引吭和其音，力盡猶勉彊。", "誠知非所敵，但欲繼前芳。", "近者蟠桃詩，有傳來北方。", "發我衰病思，藹如得春陽。", "忻然便欲和，洗硯坐中堂。", "墨筆不能下，怳怳若有亡。", "老雞嘴爪硬，不易犯其場。", "不戰先自却，雖奔未甘降。", "更欲呼子美，子美隔濤江。", "其人雖憔悴，其志獨軒昂。"]'),
('ccdc6e92-5f84-4c40-aa5d-76ca135ed111','初伏日招王幾道小飲','歐陽修','宋','宋诗','song-poetry','','[]','北園數畝官牆下，嗟我官居如傳舍。',176,'全唐诗/poet.song.17000.json','["北園數畝官牆下，嗟我官居如傳舍。", "滹沱北渡馬踏冰，西山病歸花已謝。", "落英不見空繞樹，細草初長猶可藉。", "空園一鎖不復窺，不覺芳蹊繁早夏。", "隔牆時時聞好鳥，如得嘉客聽清話。", "今朝試去繞園尋，綠李橫枝礙行馬。", "蒲萄憶見初引蔓，翠葉陰陰還滿架。", "紅榴最晚子已繁，猶有殘花藏葉罅。", "人生有酒復何求，官事無了須偷暇。", "古云伏日當早歸，況今著令許休假。", "能來解带相就飲，爲子掃月開風榭。"]'),
('8ff966c5-0cc7-44b4-a134-f2f6131383b6','白髮喪女師作','歐陽修','宋','宋诗','song-poetry','','[]','吾年未四十，三斷哭子腸。',72,'全唐诗/poet.song.17000.json','["吾年未四十，三斷哭子腸。", "一割痛莫忍，屢痛誰能當。", "割腸痛連心，心碎骨亦傷。", "出我心骨血，灑爲清淚行。", "淚多血已竭，毛膚冷無光。", "自然鬚與鬢，未老先蒼蒼。"]'),
('e5dad0a7-4462-441f-867d-66d01e191c56','永陽大雪','歐陽修','宋','宋诗','song-poetry','','[]','清流關前一尺雪，鳥飛不度人行絕。',112,'全唐诗/poet.song.17000.json','["清流關前一尺雪，鳥飛不度人行絕。", "冰連谿谷麋鹿死，風勁野田桑柘折。", "江淮卑濕殊北地，歲不苦寒常疫癘。", "老農自言身七十，曾見此雪纔三四。", "新陽漸動愛日輝，微和習習東風吹。", "一尺雪，幾尺泥，泥深麥苗春始肥。", "老農爾豈知帝力，聽我歌此豐年詩。"]'),
('60a53119-d1b0-4482-a1a2-6bb99b29c85f','送章生東歸','歐陽修','宋','宋诗','song-poetry','','[]','窮山荒僻人罕顧，子以一身千里來。',96,'全唐诗/poet.song.17000.json','["窮山荒僻人罕顧，子以一身千里來。", "問子之勤何所欲，自慚報子無瓊瑰。", "非徒多難學久廢，世事漸懶由心衰。", "吳興先生富道德，侁侁弟子皆賢材。", "鄉閭禮讓已成俗，餘風漸被來江淮。", "子年方少力可勉，往與夫子爲顔回。"]'),
('4df76783-2270-4f09-bfa5-803aad1cb86e','啼鳥','歐陽修','宋','宋诗','song-poetry','','[]','窮山候至陽氣生，百物如與時節爭。',288,'全唐诗/poet.song.17000.json','["窮山候至陽氣生，百物如與時節爭。", "官居荒涼草樹密，撩亂紅紫開繁英。", "花深葉暗耀朝日，日暖眾鳥皆嚶鳴。", "鳥言我豈解爾意，綿蠻但愛聲可聽。", "南窗星多春正美，百舌未曉催天明。", "黄鸝顔色已可愛，舌端啞咤如嬌嬰。", "竹林靜啼青竹笋，深處不見惟聞聲。", "陂田遶郭白水滿，戴勝穀穀催春耕。", "誰謂鳴鳩拙無用，雄雌各自知陰晴。", "雨聲蕭蕭泥滑滑，草深苔綠無人行。", "獨有花上提葫蘆，勸我沽酒花前傾。", "其餘百種各嘲哳，異鄉殊俗難知名。", "我遭讒口身落此，每聞巧舌宜可憎。", "春到山城苦寂寞，把盞常恨無娉婷。", "花開鳥語輒自醉，醉與花鳥爲交朋。", "花能嫣然顧我笑，鳥勸我飲非無情。", "身閑酒美惜光景，惟恐鳥散花飄零。", "可笑靈均楚澤畔，離騷憔悴愁獨醒。"]'),
('3158f623-4df9-4536-a662-1fd684ec954d','遊瑯琊山','歐陽修','宋','宋诗','song-poetry','','[]','南山一尺雪，雪盡山蒼然。',96,'全唐诗/poet.song.17000.json','["南山一尺雪，雪盡山蒼然。", "澗谷深自暖，梅花應已繁。", "使君厭騎從，車馬留山前。", "行歌招野叟，共步青林間。", "長松得高蔭，盤石堪醉眠。", "止樂聽山鳥，携琴寫幽泉。", "愛之欲忘返，但苦世俗牽。", "歸時始覺遠，明月高峯巔。"]'),
('1a6b4fd2-d65f-42cc-9178-b58ed1c03b15','讀徂徠集','歐陽修','宋','宋诗','song-poetry','','[]','徂徠魯東山，石子居山阿。',288,'全唐诗/poet.song.17000.json','["徂徠魯東山，石子居山阿。", "魯人之所瞻，子與山嵯峩。", "今子其死矣，東山復誰過。", "精魄已埋沒，文章豈能磨。", "壽命雖不長，所得固已多。", "舊藁偶自錄，滄溟之一蠡。", "其餘誰付與，散失存幾何。", "存之警後世，古鑑照妖魔。", "子生誠多難，憂患靡不罹。", "宦學三十年，六經老研摩。", "問胡所專心，仁義丘與軻。", "揚雄韓愈氏，此外豈知他。", "尤勇攻佛老，奮筆如揮戈。", "不量敵眾寡，膽大身幺麽。", "往年遭母喪，泣血走岷峨。", "垢面跣雙足，鋤犁事田坡。", "至今鄉里化，孝悌勤蠶禾。", "昨者來太學，青衫踏朝靴。", "陳詩頌聖德，厥聲續猗那。", "羔鴈聘黄晞，晞驚走鄰家。", "施爲可怪駭，世俗安委蛇。", "謗口由此起，口之若飛梭。", "上賴天子明，不挂網者羅。", "憶在太學年，大雪如翻波。"]'),
('227a23c2-310d-46c2-b2af-0d27aa4e7265','大熱二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','四時成萬物，寒暑迭鈞陶。',84,'全唐诗/poet.song.17000.json','["四時成萬物，寒暑迭鈞陶。", "壯陽當用事，大夏蒸炎歊。", "造化本無情，怨咨徒爾勞。", "身微天地闊，四顧無由逃。", "九門閶闔開，萬仞崑崙高。", "積雪寒凜凜，清風吹寥寥。", "嗟我雖欲往，而身無羽毛。"]'),
('78471caf-0d16-4d32-9995-68d4a075dbf1','大熱二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','陽暉爍四野，萬里纖雲收。',60,'全唐诗/poet.song.17000.json','["陽暉爍四野，萬里纖雲收。", "羲和困路遠，正午當空留。", "枝條不動影，草木皆含愁。", "深林虎不嘯，卧喘如吳牛。", "蜩蟬一何微，嗟爾徒啾啾。"]'),
('6b8868bf-efed-4bc3-b02a-b4aecd77640d','幽谷泉','歐陽修','宋','宋诗','song-poetry','','[]','踏石弄泉流，尋源入幽谷。',84,'全唐诗/poet.song.17000.json','["踏石弄泉流，尋源入幽谷。", "泉傍野人家，四面深篁竹。", "溉稻滿春疇，鳴渠遶茅屋。", "生長飲泉甘，蔭泉栽美木。", "潺湲無春冬，日夜響山曲。", "自言今白首，未慣逢朱轂。", "顧我應可怪，每來聽不足。"]'),
('00f8fef4-e6ae-4049-a154-f379ee0372bd','百子坑賽龍','歐陽修','宋','宋诗','song-poetry','','[]','嗟龍之智誰可拘，出入變化何須臾。',128,'全唐诗/poet.song.17000.json','["嗟龍之智誰可拘，出入變化何須臾。", "壇平樹古潭水黑，沉沉影響疑有無。", "四山雲霧忽晝合，瞥起直上拏空虛。", "龜魚带去半空落，雷輷電走先後驅。", "傾崖倒漳聊一戲，頃刻萬物皆涵濡。", "青天却掃萬里靜，但見綠野如雲敷。", "明朝老農拜潭側，鼓聲坎坎鳴山隅。", "野巫醉飽廟門闔，狼藉烏鳥爭殘餘。"]'),
('34f9628e-78fb-48dc-b18d-e85a616d790f','贈蚊','歐陽修','宋','宋诗','song-poetry','','[]','擾擾萬類殊，可憎非一族。',288,'全唐诗/poet.song.17000.json','["擾擾萬類殊，可憎非一族。", "甚哉蚊之微，豈足汙簡牘。", "乾坤量廣大，善惡皆含育。", "荒茫三五前，民物交相黷。", "禹鼎象神姦，蛟龍遠潛伏。", "周公驅猛獸，人始居川陸。", "爾來千百年，天地得清肅。", "大患已云除，細微遺不錄。", "蠅蝱蚤虱蟣，蜂蝎蚖蛇蝮。", "惟爾於其間，有形纔一粟。", "雖微無柰眾，惟小難防毒。", "嘗聞高郵間，猛虎死凌辱。", "哀哉露筋女，萬古讎不復。", "水鄉自宜爾，可怪窮邊俗。", "晨飱下帷幬，盛暑泥駒犢。", "我來守窮山，地氣尤卑溽。", "官閑懶所便，惟睡宜偏足。", "難堪爾類多，枕席厭緣撲。", "燻簷苦煙埃，燎壁疲照燭。", "荒城繁草樹，旱氣飛炎熇。", "羲和驅日車，當午不轉轂。", "清風得夕涼，如赦脫囚梏。", "掃庭露青天，坐月蔭嘉木。", "汝寧無他時，忍此見迫促。"]'),
('7a1f6f08-fdf3-4820-bfbe-145300761787','重讀徂徠集','歐陽修','宋','宋诗','song-poetry','','[]','我欲哭石子，夜開徂徠編。',288,'全唐诗/poet.song.17000.json','["我欲哭石子，夜開徂徠編。", "開編未及讀，涕泗已漣漣。", "勉盡三四章，收淚輒忻懽。", "切切善惡戒，丁寧仁義言。", "如聞子談論，疑子立我前。", "乃知長在世，誰謂已沉泉。", "昔也人事乖，相從常苦艱。", "今而每思子，開卷子在顔。", "我欲貴子文，刻以金玉聯。", "金可爍而銷，玉可碎非堅。", "不若書以紙，六經皆紙傳。", "但當書百本，傳百以爲千。", "或落於四夷，或藏在深山。", "待彼謗燄熄，放此光芒懸。", "人生一世中，長短無百年。", "無窮在其後，萬世在其先。", "得長多幾何，得短未足憐。", "惟彼不可朽，名聲文行然。", "讒誣不須辨，亦止百年間。", "百年後來者，憎愛不相緣。", "公議然後出，自然見媸妍。", "孔孟困一生，毀逐遭百端。", "後世苟不公，至今無聖賢。", "所以忠義士，恃此死不難。"]'),
('05c9ea4c-dda6-4cb2-83dc-a41586d88e6b','汝癭答仲儀','歐陽修','宋','宋诗','song-poetry','','[]','君嗟汝癭多，誰謂汝土惡。',288,'全唐诗/poet.song.17000.json','["君嗟汝癭多，誰謂汝土惡。", "汝癭雖云苦，汝民居自樂。", "鄉閭同飲食，男女相媒妁。", "習俗不爲嫌，譏嘲豈知怍。", "汝山西南險，平地猶磽确。", "汝樹生擁腫，根株浸溪壑。", "山川固已然，風氣宜其濁。", "接境化襄鄧，餘風被伊雒。", "思予昔曾遊，所見可驚愕。", "喔喔聞語笑，纍纍滿城郭。", "傴婦懸甕盎，嬌嬰包卵鷇。", "無由辨肩頸，有類龜縮殼。", "噫人稟最靈，反不如鳧鶴。", "駢枝雖形累，小小固可略。", "癰瘍暫畜聚，決潰終當涸。", "贅疣附支體，幸或不爲虐。", "未若此巍然，所生非所託。", "咽喉繫性命，鍼石難砭削。", "農皇古神聖，爲世名百藥。", "豈不有方書，頑然莫銷鑠。", "溫湯汝靈泉，亦不能湔瀹。", "君官雖謫居，政可瘳民瘼。", "奈何不哀憐，而反恣訶謔。", "文辭騁新工，醜怪極名貌。"]'),
('fb41da82-ef32-486e-a6b7-82c3637f7382','滄浪亭','歐陽修','宋','宋诗','song-poetry','','[]','子美寄我滄浪吟，邀我共作滄浪篇。',288,'全唐诗/poet.song.17000.json','["子美寄我滄浪吟，邀我共作滄浪篇。", "滄浪有景不可到，使我東望心悠然。", "荒灣野水氣象古，高林翠阜相回環。", "新篁抽笋添夏影，老枿亂發爭春妍。", "水禽閑暇事高格，山鳥日夕相啾喧。", "不知此地幾興廢，仰視喬木皆蒼煙。", "堪嗟人迹到不遠，雖有來路曾無緣。", "窮奇極怪誰似子，搜索幽隱探神仙。", "初尋一逕入蒙密，豁目異境無窮邊。", "風高月白最宜夜，一片瑩浄鋪瓊田。", "清光不辨水與月，但見空碧涵漪漣。", "清風明月本無價，可惜祗賣四萬錢。", "又疑此境天乞與，壯士憔悴天應憐。", "鴟夷古亦有獨往，江湖波濤渺翻天。", "崎嶇世路欲脫去，反以身試蛟龍淵。", "豈如扁舟任飄兀，紅蕖淥浪摇醉眠。", "丈夫身在豈長棄，新詩美酒聊窮年。", "雖然不許俗客到，莫惜佳句人間傳。"]'),
('50e24658-8e2f-4c97-910d-e5453c8f3015','寶劍','歐陽修','宋','宋诗','song-poetry','','[]','寶劍匣中藏，暗室夜常明。',120,'全唐诗/poet.song.17000.json','["寶劍匣中藏，暗室夜常明。", "欲知天將雨，錚爾劔有聲。", "神龍本一物，氣類感則鳴。", "常恐躍匣去，有時暫開𨩮。", "煌煌七星文，照曜三尺冰。", "此劔在人間，百妖夜收形。", "姦兇與佞媚，膽破骨亦驚。", "試以向星月，飛光射攙槍。", "藏之武庫中，可息天下兵。", "柰何狂胡兒，尚改邀金繒。"]'),
('ec418ac0-dc20-411b-9645-df4ecdaaacfe','秋晚凝翠亭','歐陽修','宋','宋诗','song-poetry','','[]','黄葉落空城，青山遶官廨。',96,'全唐诗/poet.song.17000.json','["黄葉落空城，青山遶官廨。", "風雲凄已高，歲月驚何邁。", "陂田寒未收，野水淺生派。", "晴林紫榴坼，霜日紅梨曬。", "蕭踈喜竹勁，寂寞傷蘭敗。", "叢菊如有情，幽芳慰孤介。", "嘉客日可携，寒醅美新醡。", "登臨無厭頻，冰雪行即屆。"]'),
('f968862d-24c3-4f6b-91c6-1c569b41a5fa','菱溪大石','歐陽修','宋','宋诗','song-poetry','','[]','新霜夜落秋水淺，有石露出寒溪垠。',368,'全唐诗/poet.song.17000.json','["新霜夜落秋水淺，有石露出寒溪垠。", "苔昏土蝕禽鳥啄，出沒溪水秋復春。", "溪邊老翁生長見，疑我來視何殷勤。", "愛之遠徙向幽谷，曳以三犢載兩輪。", "行穿城中罷市看，但驚可怪誰復珍。", "荒煙野草埋沒久，洗以石竇清泠泉。", "朱欄綠竹相掩映，選致佳處當南軒。", "南軒旁列千萬峯，曾未有些奇嶙峋。", "乃知異物世所少，萬金爭買傳幾人。", "山河面戰變陵谷，何爲落彼荒溪濆。", "山經地誌不可究，遂令異說爭紛紜。", "皆云女堝初鍛鍊，融結一氣凝精純。", "仰視蒼蒼補其缺，染此紺碧瑩且溫。", "或疑古者燧人氏，鉆以出火爲炮燔。", "苟非神聖親手迹，不爾孔竅誰雕剜。", "又云漢使把漢節，西北萬里窮崑崙。", "行經于闐得寶玉，流入中國隨河源。", "沙磨水激自穿穴，所以鎸鑿無瑕痕。", "嗟予有口莫能辯，歎息但以兩手捫。", "盧仝韓愈不在世，彈壓百怪無雄文。", "爭奇鬭異各取勝，遂至荒誕無根原。", "天高地厚靡不有，醜好萬狀奚足論。", "惟當掃雪席其側，日與嘉客陳清罇。"]'),
('96f462d4-c2cb-4c5e-809e-fb8d459c9d3c','送姜秀才遊蘇州','歐陽修','宋','宋诗','song-poetry','','[]','憶從太學諸生列，我尚弱齡君秀發。',64,'全唐诗/poet.song.17000.json','["憶從太學諸生列，我尚弱齡君秀發。", "同時並薦幾存亡，一夢十年如倏忽。", "壯心君未減青春，多難我今先白髮。", "山花撩亂鳥綿蠻，更盡一罇明日別。"]'),
('6c27253c-2cfe-4478-bc5d-60ccb5b806ca','送孫秀才','歐陽修','宋','宋诗','song-poetry','','[]','高門煌煌赫如赭，勢利聲名爭借假。',80,'全唐诗/poet.song.17000.json','["高門煌煌赫如赭，勢利聲名爭借假。", "嗟哉子獨不顧之，訪我千山一羸馬。", "明珠渡水覆舟失，曾我璣貝猶滿把。", "遲遲顧我不欲去，問我無窮慚報寡。", "時之所棄子獨嚮，無乃與世異取捨。"]'),
('e14ab486-1607-44fe-bc1a-66449fc487cd','新霜二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','天雲慘慘秋陰薄，卧聽北風鳴屋角。',112,'全唐诗/poet.song.17000.json','["天雲慘慘秋陰薄，卧聽北風鳴屋角。", "平明驚鳥四散飛，一夜新霜羣木落。", "南山鬰鬰舊可愛，千仞巉巖如刻削。", "林枯山瘦失顔色，我意豈能無寂寞。", "衰顔得酒猶彊發，可醉豈須嫌酒濁。", "泉傍菊花方爛漫，短日寒輝相照灼。", "無情木石尚須老，有酒人生何不樂。"]'),
('a1faa0f7-0f0b-4c8b-b1e3-c792bc30a9d1','新霜二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','荒城草樹多陰暗，日夕霜雲意濃淡。',128,'全唐诗/poet.song.17000.json','["荒城草樹多陰暗，日夕霜雲意濃淡。", "長淮漸落見洲渚，野潦初清收瀲濪。", "蘭枯蕙死誰復弔，殘菊籬根爭豔豔。", "青松守節見臨危，正色凜凜不可犯。", "芭蕉芰荷不足數，狼藉徒能污池檻。", "時行收斂歲將窮，冰雪嚴凝從此漸。", "咿呦兒女感時節，愛惜朱顔屢窺鑑。", "惟有壯士獨悲歌，拂拭塵埃磨古劔。"]'),
('d1541f4d-ae79-4d37-8814-a0209584556a','豐樂亭小飲','歐陽修','宋','宋诗','song-poetry','','[]','造化無情不擇物，春色亦到深山中。',80,'全唐诗/poet.song.17000.json','["造化無情不擇物，春色亦到深山中。", "山桃溪杏少意思，自趁時節開春風。", "看花遊女不知醜，古粧野態爭花紅。", "人生行樂在勉彊，有酒莫負琉璃鍾。", "主人勿笑花與女，嗟爾自是花前翁。"]'),
('0d8c5745-4a00-4d97-912e-78740cc60740','四月九日幽谷見緋桃盛開','歐陽修','宋','宋诗','song-poetry','','[]','經年種花滿幽谷，花開不暇把一巵。',144,'全唐诗/poet.song.17000.json','["經年種花滿幽谷，花開不暇把一巵。", "人生此事尚難必，況欲功名書鼎彝。", "深紅淺紫看雖好，顔色不柰東風吹。", "緋桃一樹獨後發，意若待我留芳菲。", "清香嫩蕊含不吐，日日怪我來何遲。", "無情草木不解語，向我有意偏依依。", "羣芳落盡始爛漫，榮枯不與眾豔隨。", "念花意厚何以報，唯有醉倒花東西。", "盛開比落猶數日，清罇尚可三四携。"]'),
('aa22d5e9-08c3-4881-a37c-d1487ad5a792','秋懷二首寄聖俞  其一','歐陽修','宋','宋诗','song-poetry','','[]','孤管叫秋月，清砧韻霜風。',72,'全唐诗/poet.song.17000.json','["孤管叫秋月，清砧韻霜風。", "天涯遠夢歸，驚斷山千重。", "羣物動已息，百憂感從中。", "日月矢雙流，四時環無窮。", "隆陰夷老物，摧折壯士胸。", "壯士亦何爲，素絲悲青銅。"]'),
('9a3613e5-d1cc-4650-80b5-d561ed01e214','秋懷二首寄聖俞  其二','歐陽修','宋','宋诗','song-poetry','','[]','羣木落空原，南山高巃嵸。',84,'全唐诗/poet.song.17000.json','["羣木落空原，南山高巃嵸。", "巉巖想詩老，瘦骨寒愈聳。", "詩老類秋蟲，吟秋聲百種。", "披霜掇孤英，泣古弔荒冢。", "琅玕叩金石，清響聽生悚。", "何由幸見之，使我滌煩冗。", "飛鳥下東南，音書無日捧。"]'),
('cfc4e1ff-e98a-4406-84a2-f7f3f65da1af','希真堂東手種菊花十月始開','歐陽修','宋','宋诗','song-poetry','','[]','當春種花唯恐遲，我獨種菊君勿誚。',176,'全唐诗/poet.song.17000.json','["當春種花唯恐遲，我獨種菊君勿誚。", "春枝滿園爛張錦，風雨須臾落顛倒。", "看多易厭情不專，鬭紫誇紅隨俗好。", "豁然高秋天地肅，百物衰零誰暇弔。", "君看金蕊正芬敷，曉日浮霜相照耀。", "煌煌正色秀可餐，藹藹清香寒愈峭。", "高人避喧守幽獨，淑女靜容修窈窕。", "方當摇落看轉佳，慰我寂寥何以報。", "時携一罇相就飲，如得貧交論久要。", "我從多難壯心衰，迹與世人殊靜躁。", "種花勿種兒女花，老大安能逐年少。"]'),
('43c42b02-0d44-4fb1-8d44-3881e721a304','拒霜花','歐陽修','宋','宋诗','song-poetry','','[]','芳菲能幾時，顔色如自愛。',60,'全唐诗/poet.song.17000.json','["芳菲能幾時，顔色如自愛。", "鮮鮮弄霜曉，裊裊含風態。", "蕙蘭殞秋香，桃李媚春醉。", "時節雖不同，盛衰終一致。", "莫笑黄菊花，籬根守憔悴。"]'),
('6fbced32-3415-467d-ad46-4258f2604183','懷嵩樓晚飲示徐無黨無逸','歐陽修','宋','宋诗','song-poetry','','[]','滁山不通車，滁水不載舟。',287,'全唐诗/poet.song.17000.json','["滁山不通車，滁水不載舟。", "舟車路所窮，嗟誰肯來遊。", "念非吾在此，二子來何求。", "不見忽三年，見之忘百憂。", "問其別後學，初若繭緒抽。", "縱橫漸組織，文章爛然浮。", "引伸無窮極，卒斂以軻丘。", "少進日如此，老退誠可羞。", "弊邑亦何有，青山遶城樓。", "泠泠谷中泉，吐溜彼山幽。", "石醜駭溪怪，天奇瞰龍湫。", "子初如可樂，久乃歎以愀。", "云此譬圖畫，暫看已宜收。", "荒涼草樹間，暮館城南陬。", "破屋仰見星，窗風冷如鎪。", "歸心中夜起，輾轉卧不周。", "我爲辦酒肴，羅列蛤與蛑。", "酒酣微探之，仰笑不頷頭。", "曰予非此儂，又不負譴尤。", "自非世不容，安事此爲囚。", "幸以主人故，崎嶇幾摧輈。", "一來勤已多，而況久留。", "我語頓遭屈，顔慚汗交流。", "川塗冰已壯，霰雪行將稠。"]'),
('9e6b6f20-936c-40bc-ab0e-0cc78c9e4ee9','瑯琊山六題 歸雲洞','歐陽修','宋','宋诗','song-poetry','','[]','洞門常自起煙霞，洞穴傍穿透谿谷。',32,'全唐诗/poet.song.17000.json','["洞門常自起煙霞，洞穴傍穿透谿谷。", "朝看石上片雲陰，夜半山前春雨足。"]'),
('a4dca87a-786f-46f9-93dd-d4cde1779960','瑯琊山六題 瑯琊谿','歐陽修','宋','宋诗','song-poetry','','[]','空山雪消谿水漲，遊客渡谿橫古槎。',32,'全唐诗/poet.song.17000.json','["空山雪消谿水漲，遊客渡谿橫古槎。", "不知谿源來遠近，但見流出山中花。"]'),
('93f791ed-7663-4a12-9f9b-eff8cea48764','瑯琊山六題 石屏路','歐陽修','宋','宋诗','song-poetry','','[]','石屏自倚浮雲外，石路久無人跡行。',32,'全唐诗/poet.song.17000.json','["石屏自倚浮雲外，石路久無人跡行。", "我來携酒醉其下，卧看千峯秋月明。"]'),
('13c6777c-3828-45f3-8297-c8114af8090a','瑯琊山六題 班春亭','歐陽修','宋','宋诗','song-poetry','','[]','信馬尋春踏雪泥，醉中山水弄清輝。',32,'全唐诗/poet.song.17000.json','["信馬尋春踏雪泥，醉中山水弄清輝。", "野僧不用相迎送，乘興閑來興盡歸。"]'),
('023fcd6e-b61e-4164-9155-89907303c0b3','瑯琊山六題 庶子泉','歐陽修','宋','宋诗','song-poetry','','[]','庶子遺蹤留此地，寒巖徙倚弄飛泉。',32,'全唐诗/poet.song.17000.json','["庶子遺蹤留此地，寒巖徙倚弄飛泉。", "古人不見心可見，一片清光長皎然。"]'),
('b2daceb6-64a1-407b-be69-cb0a1950a53a','瑯琊山六題 惠覺方丈','歐陽修','宋','宋诗','song-poetry','','[]','青松行盡到山門，亂峰深處開方丈。',32,'全唐诗/poet.song.17000.json','["青松行盡到山門，亂峰深處開方丈。", "已能宴坐老山中，何用聲名傳海上。"]'),
('edb233f9-8955-40e1-a3fe-40145914b7e7','贈無爲軍李道士二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','無爲道士三尺琴，中有萬古無窮音。',66,'全唐诗/poet.song.17000.json','["無爲道士三尺琴，中有萬古無窮音。", "音如石上瀉流水，瀉之不竭由源深。", "彈雖在指聲在意，聽不以耳而以心。", "心意既得形骸忘，不覺天地白日愁雲陰。"]'),
('a9dd03a2-244c-4b87-b42c-eca3f731c0c1','贈無爲軍李道士二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','李師琴紋如卧蛇，一彈使我三咨嗟。',172,'全唐诗/poet.song.17000.json','["李師琴紋如卧蛇，一彈使我三咨嗟。", "五音商羽主肅殺，颯颯坐上風吹沙。", "忽然黄鍾回暖律，當冬草木皆萌芽。", "郡齋日午公事退，荒涼樹石相交加。", "李師一彈鳳凰聲，空山百鳥停嘔啞。", "我怪李師年七十，面目明秀光如霞。", "問胡以然笑語我，慎勿辛苦求丹砂。", "惟當養其根，自然燁其華。", "又云理身如理琴，正聲不可干以邪。", "我聽其言未云足，野鶴何事還思家。", "抱琴揖我出門去，獵獵歸袖風中斜。"]'),
('c4834acb-6ef1-4578-9fab-d18936d96fb9','拜赦','歐陽修','宋','宋诗','song-poetry','','[]','拜赦古州南，山火明烈烈。',60,'全唐诗/poet.song.17000.json','["拜赦古州南，山火明烈烈。", "州人共喧喧，兩丱扶白髮。", "丁寧天語深，曠蕩皇恩闊。", "乃知天地施，幽遠無間別。", "欣欣草木意，喜氣消殘雪。"]'),
('705afb5a-e36b-428b-8085-ef663b418d27','彈琴效賈島體','歐陽修','宋','宋诗','song-poetry','','[]','古人不可見，古人琴可彈。',132,'全唐诗/poet.song.17000.json','["古人不可見，古人琴可彈。", "彈爲古曲聲，如與古人言。", "琴聲雖可聽，琴意誰能論。", "橫琴置牀頭，當午曝背眠。", "夢見一丈夫，嚴嚴古衣冠。", "登牀取之坐，調作南風絃。", "一奏風雨來，再鼓變雲煙。", "鳥獸盡嚶鳴，草木亦滋蕃。", "乃知太古時，未遠可追還。", "方彼夢中樂，心知口難傳。", "既覺失其人，起坐涕汍瀾。"]'),
('83e665b6-32f5-42e1-b5ee-a88eaff30c3b','酬學詩僧惟晤','歐陽修','宋','宋诗','song-poetry','','[]','詩三百五篇，作者非一人。',203,'全唐诗/poet.song.17000.json','["詩三百五篇，作者非一人。", "羈臣與棄妾，桑濮乃淫奔。", "其言苟可取，庬雜不全純。", "子雖爲佛徒，未易廢其言。", "其言在合理，但懼學不臻。", "子佛與吾儒，異轍難同輪。", "子何獨吾慕，自忘夷其身。", "苟能知所歸，固有路自新。", "誘進或可至，拒之誠不仁。", "維詩於文章，太山一浮塵。", "又如古衣裳，組織爛成文。", "拾其裁剪餘，未識衮服尊。", "嗟子學雖，徒自苦骸筋。", "勤勤袖卷軸，一歲三及門。", "惟求一言榮，歸以耀其倫。", "與夫榮其膚，不若啟其源。", "韓子亦嘗謂，收斂加冠巾。"]'),
('4761defe-eec6-48d6-941a-6b49f086c91a','別後奉寄俞二十五兄','歐陽修','宋','宋诗','song-poetry','','[]','長河秋雨多，夜插寒潮入。',288,'全唐诗/poet.song.17000.json','["長河秋雨多，夜插寒潮入。", "歲暮孤舟遲，客心飛鳥急。", "君老忘卑窮，文字或綴緝。", "余生苦難阨，世險蹈已習。", "離合二十年，乖睽多聚集。", "常時飲酒別，今別輒飲泣。", "君曰吾老矣，不覺兩袖濕。", "我年雖少君，白髮已揖揖。", "憶初京北門，送我馬暫立。", "自茲遭檻穽，一落誰引汲。", "顛危偶脫死，藏竄甘自縶。", "但令身尚在，果得手重執。", "聞來喜迎前，貌改驚乍揖。", "別離纔幾時，舊學廢百十。", "殘章與斷藁，草草各收拾。", "空窗語青燈，夜雨聽霵霵。", "明朝解舟南，歸翼縱莫戢。", "還期明月飲，幸此中秋及。", "酒酣弄篇章，四坐困供給。", "歡言正喧譁，別意忽於邑。", "日暮北亭上，濁醪聊共挹。", "輕橈動翩翩，晚水明熠熠。", "行心去雖迫，訣語出猶澁。", "歸來錄君詩，卷軸多𧥄𧥄。"]'),
('a56673d0-0ea3-43d3-8fe7-b370005deb24','紫石屏歌','歐陽修','宋','宋诗','song-poetry','','[]','月從海底來，行上天東南。',326,'全唐诗/poet.song.17000.json','["月從海底來，行上天東南。", "正當天中時，下照千丈潭。", "潭心無風月不動，倒影射入紫石巖。", "月光水潔石瑩浄，感此陰魄來中潛。", "自從月入此石中，天有兩曜分爲三。", "清光萬古不磨滅，天地至寶難藏緘。", "天公呼雷公，夜持巨斧隳嶄巖。", "墮此一片落千仞，皎然寒鏡在玉匳。", "蝦蟇白兔走天上，空留桂影猶杉杉。", "景山得之惜不得，贈我意與千金兼。", "自云每到月滿時，石在暗室光出簷。", "大哉天地間，萬怪難悉談。", "嗟予不度量，每事思窮探。", "欲將兩耳目所及，而與造化爭毫纖。", "煌煌三辰行，日月尤尊嚴。", "若令下與物爲比，擾擾萬類將誰瞻。", "不然此石竟何物，有口欲說嗟如鉗。", "吾奇蘇子胸，羅列萬象中包含。", "不惟胸寬膽亦大，屢出言語驚愚凡。", "自吾得此石，未見蘇子心懷慚。", "不經老匠先指决，有手誰改施鎸鑱。", "呼工畫石持寄似，幸子留意其無謙。"]'),
('10b5adeb-22a8-40fe-9f2b-e736a3197d6b','聚星堂前紫薇花','歐陽修','宋','宋诗','song-poetry','','[]','亭亭紫薇花，向我如有意。',84,'全唐诗/poet.song.17000.json','["亭亭紫薇花，向我如有意。", "高煙晚溟濛，清露晨點綴。", "豈無陽春月，所得時節異。", "靜女不爭寵，幽姿如自喜。", "將期誰顧眄，獨伴我憔悴。", "而我不彊飲，繁英行亦墜。", "相看兩寂寞，孤詠聊自慰。"]'),
('d633b69d-1410-4dba-99bb-da10cdf215cb','獲麟贈姚闢先輩','歐陽修','宋','宋诗','song-poetry','','[]','世已無孔子，獲麟意誰知。',288,'全唐诗/poet.song.17000.json','["世已無孔子，獲麟意誰知。", "我嘗爲之說，聞者未免非。", "而子獨曰然，有如塤應篪。", "惟麟不爲瑞，其意乃可推。", "春秋二百年，文約義甚夷。", "一從聖人沒，學者自爲師。", "崢嶸眾家說，平地生嶮巇。", "相沿益迂怪，各鬭出新奇。", "爾來千餘歲，舉世不知迷。", "焯哉聖人經，照耀萬世疑。", "自從蒙眾說，日月遭蔽虧。", "常患無氣力，掃除浮雲披。", "還其自然光，萬物皆見之。", "子昔已好古，此經手常持。", "超然出眾見，不爲俗牽卑。", "近又脫賦格，飛黄擺銜羈。", "聖門開大道，夷路肆騰嬉。", "便可勦眾說，旁通塞多歧。", "正途趨簡易，慎勿事嶇崎。", "著述須待老，積勤宜少時。", "苟思垂後世，大禹尚胼胝。", "顧我今老矣，兩瞳蝕昏眵。", "大書難久視，心在力已衰。", "因思少自棄，今縱悔可追。"]'),
('9962afe8-2e24-499e-8b41-5eb210979449','喜雨','歐陽修','宋','宋诗','song-poetry','','[]','大雨雖霶霈，隔轍分晴陰。',120,'全唐诗/poet.song.17000.json','["大雨雖霶霈，隔轍分晴陰。", "小雨散浸淫，爲潤廣且深。", "浸淫苟不止，利澤何窮已。", "無言雨大小，小雨農尤喜。", "宿麥已登實，新禾未抽秧。", "及時一日雨，終歲飽豐穰。", "夜響流霢霂，晨暉霽蒼涼。", "川原浄如洗，草木自先光。", "童稚喜瓜芋，耕夫望陂塘。", "誰云田家苦，此樂殊未央。"]'),
('5e706199-e973-4ad6-9bf3-5ba7e54386b5','飛蓋橋翫月','歐陽修','宋','宋诗','song-poetry','','[]','天形積輕清，水德本虛靜。',120,'全唐诗/poet.song.17000.json','["天形積輕清，水德本虛靜。", "雲收風波止，始見天水性。", "澄光與粹容，上下相涵映。", "乃於其兩間，皎皎掛寒鏡。", "餘暉所照耀，萬物皆鮮瑩。", "矧夫人之靈，豈不醒視聽。", "而我於此時，翛然發孤詠。", "紛昏忻洗滌，俯仰姿涵泳。", "人心曠而閑，月色高愈迥。", "惟恐清夜闌，時時瞻斗柄。"]'),
('4e74a8d5-d6c6-4e51-aafa-880bb38bde43','竹間亭','歐陽修','宋','宋诗','song-poetry','','[]','啾啾竹間鳥，日夕相嚶鳴。',144,'全唐诗/poet.song.17000.json','["啾啾竹間鳥，日夕相嚶鳴。", "悠悠水中魚，出入藻與萍。", "水竹魚鳥家，伊誰作斯亭。", "翁來無車馬，非與彈弋并。", "潛者入深淵，飛者散縱橫。", "奈何翁屢來，浪使飛走驚。", "忘爾榮與利，脫爾冠與纓。", "還來尋魚鳥，傍此水竹行。", "鳥語弄蒼翠，魚遊翫清澄。", "而翁仍何爲，獨醉還自醒。", "三者各自適，要歸亦同情。", "翁乎知此樂，無厭日來登。"]'),
('adae1c34-b66b-48f7-8353-c851f128262f','簽呂公著見贈','歐陽修','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晉人歌蟋蟀，孔子錄於詩。',276,'全唐诗/poet.song.17000.json','["晉人歌蟋蟀，孔子錄於詩。", "因知聖賢心，豈不惜良時。", "行樂不及早，朱顔忽焉衰。", "馳光如騕褭，一去不可追。", "今也不彊飲，後雖悔奚爲。", "三年謫永陽，陷穽不知危。", "種樹滿幽谷，疏泉瀉清池。", "新陽染山木，撩亂發枯枝。", "無人歌青春，自釂白玉巵。", "今者荷寬宥，乞州從爾宜。", "西湖舊已聞，既見又過之。", "菡萏間紅綠，鴛鴦浮渺瀰。", "四時花與竹，罇俎動可隨。", "況與賢者同，薰然襲蘭芝。", "醁醅寒且醥，清唱婉而遲。", "四坐各已醉，臨觴獨何疑。", "昔人逢麴車，流涎尚垂頤。", "況此盃中趣，久得樂無涯。", "多憂衰病早，心在良可噫。", "譬若卧櫪馬，聞鼙尚鳴悲。", "春膏已動脈，百卉漸葳蕤。", "丹砂得新方，舊疾庶可治。", "尚可執鞭弭，周旋以忘疲。"]'),
('de4940be-eaad-44ca-acde-4d15cff8aa8d','送滎陽魏主簿','歐陽修','宋','宋诗','song-poetry','','[]','卓犖東都子，姓名聞十年。',264,'全唐诗/poet.song.17000.json','["卓犖東都子，姓名聞十年。", "窮冬雪塞空，千里至我門。", "子足未及閾，我衣驚倒顛。", "僕童相視疑，寮吏或不然。", "俛首鵠鶴啄，進趨鳧鴈聯。", "青衫靴兩脚，言色倩以溫。", "於公門豈少，乃獨得公懽。", "受知固不易，知士誠尤難。", "我思屈童吏，俗辯難以言。", "觴豆及嘉節，高堂列羣賢。", "文章看落筆，論議馳後先。", "破石出至寶，决高瀉長川。", "光暉相磨晻，浩渺肆波瀾。", "寮吏媿我歎，僕童恪生顔。", "我顧寮吏嘻，士豈以此觀。", "此聊爲戲耳，以驚僕童昏。", "士欲見其守，視其居賤貧。", "欲知其所趨，試以義利干。", "我始識其面，已窺其肺肝。", "禮有來必往，木瓜報琅玕。", "十年思見之，一日捨我還。", "何用慰離居，贈子以短篇。"]'),
('fdc3876d-074e-480e-a820-59e63695560d','青松贈林子','歐陽修','宋','宋诗','song-poetry','','[]','青松生而直，繩墨易爲功。',60,'全唐诗/poet.song.17000.json','["青松生而直，繩墨易爲功。", "良玉有天質，少加磨與礲。", "子誠懷美材，但未遭良工。", "養育既堅好，英華充厥中。", "於誰以成之，孟韓荀暨雄。"]'),
('fd941535-226a-4b8a-a55e-9ad645aaea36','人日聚星堂燕集探韻得豐字','歐陽修','宋','宋诗','song-poetry','','[]','汙池以其下，眾流之所鍾。',144,'全唐诗/poet.song.17000.json','["汙池以其下，眾流之所鍾。", "尺水無長瀾，蛟龍豈其容。", "顧予誠鄙薄，羣俊枉高蹤。", "得一不爲少，雖多肯辭豐。", "譬如登圓壇，羅列璧與琮。", "又若饗鈞天，左右間笙鏞。", "文章爛照耀，應和相撞舂。", "而予處其間，眩晁不知從。", "退之亦嘗云，青蒿倚長松。", "新陽發羣枯，生意漸豐茸。", "暮雪浩方積，醁醅寒更濃。", "毋言輕此樂，此樂難屢逢。"]'),
('f0aa2322-a5ac-49e3-bc1e-c9b57248772b','橄欖','歐陽修','宋','宋诗','song-poetry','','[]','五行居四時，維火盛南訛。',132,'全唐诗/poet.song.17000.json','["五行居四時，維火盛南訛。", "炎焦陵木氣，橄欖得之多。", "酸苦不相入，初爭久方和。", "霜苞入中州，萬里來江波。", "幸登君子席，得與眾果羅。", "中州眾果佳，珠圓玉光瑳。", "媿茲微陋質，以遠不見訶。", "餳飴兒女甜，遺味久則那。", "良藥不甘口，厥功見沉痾。", "忠言初厭之，事至悔若何。", "世已無採詩，詩成爲君哦。"]'),
('61e8d9a7-564a-40e8-b6b7-d23e2f30c5aa','鸚鵡螺','歐陽修','宋','宋诗','song-poetry','','[]','大哉滄海何茫茫，天地百寶皆中藏。',152,'全唐诗/poet.song.17000.json','["大哉滄海何茫茫，天地百寶皆中藏。", "牙鬚甲角爭光鋩，腥風怪雨灑幽荒。", "珊瑚玲瓏巧綴裝，珠宮貝闕爛煌煌。", "泥居殼屋細莫詳，紅螺行沙夜生光。", "負材自累遭刳腸，匹夫懷璧古所傷。", "濃沙剝蝕隱文章，磨以玉粉緣金黄，清罇旨酒列華堂。", "隴鳥回頭思故鄉，美人清歌蛾眉揚，一釂凜冽回春陽。", "物雖微遠用則彰，一螺千金價誰量，豈若泥下追含漿。"]'),
('9d2908dd-9c40-4a88-9926-8566288d631e','食糟民','歐陽修','宋','宋诗','song-poetry','','[]','田家種糯官釀酒，榷利秋毫升與斗。',184,'全唐诗/poet.song.17000.json','["田家種糯官釀酒，榷利秋毫升與斗。", "酒沽得錢糟棄物，大屋經年堆欲朽。", "酒醅瀺灂如沸湯，東風來吹酒甕香。", "纍纍罌與瓶，惟恐不得嘗。", "官沽味醲村酒薄，日飲官酒誠可樂。", "不見田中種糯人，釜無糜粥度冬春。", "還來就官買糟食，官吏散糟以爲德。", "嗟彼官吏者，其職稱長民。", "衣食不蠶耕，所學義與仁。", "仁當養人義適宜，言可聞達力可施。", "上不能寬國之利，下不能飽爾之饑。", "我飲酒，爾食糟。", "爾雖不我責，我責何由逃。"]'),
('238db1dc-7567-446b-a2da-ff80314baec7','送焦千之秀才','歐陽修','宋','宋诗','song-poetry','','[]','焦生獨立士，勢利不可恐。',168,'全唐诗/poet.song.17000.json','["焦生獨立士，勢利不可恐。", "誰言一身窮，自待九鼎重。", "有能揭之行，可謂仁者勇。", "呂侯相家子，德義勝華寵。", "焦生得其隨，道合若膠鞏。", "始生及吾門，除子喜驚踊。", "曰此難致寶，一失何由踵。", "自吾得二生，粲粲獲雙珙。", "奈何奪其一，使我意紛𦶇。", "吾嘗愛生材，抽擢方鬰蓊。", "猶須老霜雪，然後見森聳。", "況從主人賢，高行可傾竦。", "讀書趨簡要，害說去雜冗。", "新文時我寄，庶可蠲煩壅。"]'),
('b8324532-18c6-43c1-b7e2-6ff07a82bd00','伏日贈徐焦二生','歐陽修','宋','宋诗','song-poetry','','[]','徐生純明白玉璞，焦子皎潔寒泉冰。',256,'全唐诗/poet.song.17000.json','["徐生純明白玉璞，焦子皎潔寒泉冰。", "清光瑩爾互輝映，當暑自可消炎蒸。", "平湖綠波漲渺渺，高榭古木陰層層。", "嗟哉我豈不樂此，心雖欲往身未能。", "俸優食飽力不用，官閑日永睡莫興。", "不思高飛慕鴻鵠，反此愁卧償蚊蠅。", "三年永陽子所見，山林自放樂可勝。", "清泉白石對斟酌，巖花野鳥爲交朋。", "崎嶇磵谷窮上下，追逐猿狖爭超騰。", "酒美賓佳足自負，飲酣氣橫猶驕矜。", "奈何乖離纔幾日，蒼顔非舊白髮增。", "彊歡徒勞歌且舞，勉飲寧及合與升。", "行揩眼眵旋看物，坐見樓閣先愁登。", "頭輕目明脚力健，羨子志氣將飄凌。", "只今心意已如此，終竟事業知何稱。", "少壯及時宜努力，老大無堪還可憎。"]'),
('a5ddd7a3-805c-4d1f-9ca7-bab8992daabd','寄生槐','歐陽修','宋','宋诗','song-poetry','','[]','檜惟凌雲材，槐實凡木賤。',156,'全唐诗/poet.song.17000.json','["檜惟凌雲材，槐實凡木賤。", "奈何柔脆質，累此孤高幹。", "龍鱗老蒼蒼，鼠耳光粲粲。", "因緣初莫原，感吒徒自歎。", "偷生由附託，得勢爭葱蒨。", "方其榮盛時，曾莫見真贗。", "欲知窮悴節，宜試以霜霰。", "萌芽起微蘗，辨別乖先見。", "剪除初非難，長養遂成患。", "雖然根性殊，常恐枝葉亂。", "惟應植者深，幸不習而變。", "含容固有害，勦絕須明斷。", "惟當審斤斧，去惡無傷善。"]'),
('3b85e6e2-3430-472e-95f9-2bbdc258847b','韓公閱古堂','歐陽修','宋','宋诗','song-poetry','','[]','兵閑四十年，士不識金革。',288,'全唐诗/poet.song.17000.json','["兵閑四十年，士不識金革。", "水旱數千里，民流誰墾闢。", "公初來視之，嘻此乃予責。", "將法多益辦，萬千由十百。", "整齊談笑間，進退有寸尺。", "曰此易爲耳，在吾繩與墨。", "天成而地出，古所重民食。", "貯儲非一朝，人命在旦夕。", "惟茲將奈何，敢不竭吾力。", "木牛尚可運，玉罄猶走糴。", "因難乃見材，不止將有得。", "公言初未信，終歲考成績。", "驕墯識恩威，謳吟起羸瘠。", "貔貅著行伍，倉廩飽堆積。", "文章娛閑暇，傳記尋往昔。", "英英文與武，粲粲圖四壁。", "酒令列諸將，談鋒摧辯客。", "周旋顧視間，是不爲無益。", "循吏一州守，將軍萬夫敵。", "於公豈止然，事業本夔稷。", "富壽及黎庶，威名懾夷狄。", "當歸廟堂上，有位久虛席。", "大匠不揮斧，眾工隨指畫。", "眾容任羣材，文武各以職。"]'),
('fbc69e6e-007f-4abe-a72a-8c2fb8d99c6e','永州萬石亭','歐陽修','宋','宋诗','song-poetry','','[]','天於生子厚，稟予獨艱哉。',156,'全唐诗/poet.song.17000.json','["天於生子厚，稟予獨艱哉。", "超凌驟拔擢，過盛輒傷摧。", "苦其危慮心，常使鳴聲哀。", "投以空曠地，縱橫放天才。", "山窮與水險，下上極沿洄。", "故其於文章，出語多崔嵬。", "人迹所罕到，遺蹤久荒頹。", "王君好奇士，後二百年來。", "翦薙發幽薈，搜尋得瓊瑰。", "咸物不自貴，因人乃爲材。", "惟知古可慕，豈免今所咍。", "我亦奇子厚，開編每徘徊。", "作詩示同好，爲我銘山隈。"]'),
('924bcf82-ae55-44a9-b1d5-bb1e0c6a97c6','答原父','歐陽修','宋','宋诗','song-poetry','','[]','炎歊鬰然蒸，午景熾方燄。',216,'全唐诗/poet.song.17000.json','["炎歊鬰然蒸，午景熾方燄。", "子來清風興，蕭蕭吹几簟。", "又如沃瓊漿，遽飲不知厭。", "嗟予學苦晚，白首困鉛槧。", "危疑奚所質，孔孟久已窆。", "羣儒窒自私，惟子通且贍。", "幸時丐贏餘，屢得飽饑歉。", "嚴嚴春秋經，大法誰改覘。", "三才失綱紀，五代極昏墊。", "盜竊恣胠篋，英雄爭奮劒。", "興亡兩倉卒，事迹多遺欠。", "纔能紀成敗，豈暇誅姦僭。", "聞見患孤寡，是非誰證驗。", "嘗欣同好惡，遂乞指瑕玷。", "反蒙華衮襃，如譽嫫母豔。", "救非當在早，已暴何由斂。", "苟能哀廢痼，其可惜針砭。", "風舲或許邀，湖綠方濪濪。"]'),
('a9d88cff-96ed-471b-9a89-de313afd095f','蟲鳴','歐陽修','宋','宋诗','song-poetry','','[]','葉落秋水冷，眾鳥聲已停。',60,'全唐诗/poet.song.17000.json','["葉落秋水冷，眾鳥聲已停。", "陰氣入牆壁，百蟲皆夜鳴。", "蟲鳴催歲寒，唧唧機杼聲。", "時節忽已換，壯心空自驚。", "平明起照鏡，但畏白髮生。"]'),
('02554052-6221-4116-92cc-0f7a3fc4daa9','奉答子華學士安撫江南見寄之作','歐陽修','宋','宋诗','song-poetry','','[]','百姓病已久，一言難遽陳。',288,'全唐诗/poet.song.17000.json','["百姓病已久，一言難遽陳。", "良醫將治之，必究病所因。", "天下久無事，人情貴因循。", "優游以爲高，寬縱以爲仁。", "今日廢其小，皆謂不足論。", "明日壞其大，又云力難振。", "旁窺各陰拱，當職自逡巡。", "歲月寖隳頹，紀綱遂紛紜。", "坦坦萬里疆，蚩蚩九州民。", "昔而安且富，今也迫以貧。", "疾小不加理，浸淫將徧身。", "湯劑乃常藥，未能去深根。", "鍼艾有奇功，暫痛勿吟呻。", "痛定支體胖，乃知鍼艾神。", "猛寬相濟理，古語六經存。", "蠹弊革僥倖，濫官絕貪昏。", "牧羊而去狼，未爲不仁人。", "俊乂沉下位，惡去善乃伸。", "賢愚各得職，不治未之聞。", "此說乃其要，易知行每艱。", "遲疑與果决，利害反掌間。", "捨此欲有爲，吾知力徒煩。", "家至與戶到，飽饑而衣寒。", "三王所不能，豈特今所難。"]'),
('36be3ee2-b6de-49ce-adc0-3952f55ffcfc','送張洞推官赴永興經略司','歐陽修','宋','宋诗','song-poetry','','[]','自古天下事，及時難必成。',288,'全唐诗/poet.song.17000.json','["自古天下事，及時難必成。", "爲謀於未然，聰者或莫聽。", "患至而後圖，智者有不能。", "未遠前日悔，可爲來者銘。", "熙熙彼西人，老死織與耕。", "狂羝一朝叛，烽火四面驚。", "用兵五六年，首惡竟逃刑。", "仰賴天子聖，乾坤量包并。", "苗頑不率德，舜羽舞于庭。", "謂此雖異類，有生亦含情。", "藩籬被觸突，譬若豨與𦏪。", "馴擾以芻豢，可呼隨指令。", "稱藩效臣職，冠带復人形。", "四海得休息，瘡痍肉新生。", "敢問前孰失，恃安而弛兵。", "酒肴爲善將，循默乃名卿。", "慮患謂生事，高談笑難行。", "一方兵遽起，愚智共營營。", "上煩天子仁，旰食憂吾氓。", "謀議及臺早，幽棲訪巖扃。", "小利不足爲，涓流助滄溟。", "大功難速就，倉卒始改更。", "徒自益紛擾，何由集功名。", "乃知深遠畫，施設在安平。"]'),
('1d742439-f402-4de0-9cde-8bf661050684','寄聖俞','歐陽修','宋','宋诗','song-poetry','','[]','凌晨有客至自西，爲問詩老來何稽。',320,'全唐诗/poet.song.17000.json','["凌晨有客至自西，爲問詩老來何稽。", "京師車馬曜朝日，何用擾擾隨輪蹄。", "面顔憔悴暗塵土，文字光彩垂虹霓。", "空腸時如秋蚓叫，苦調或作寒蟬嘶。", "語言雖巧身事拙，捷徑耻蹈行非迷。", "我今俸祿飽餘賸，念子朝夕勤鹽齏。", "舟行每欲載米送，汴水六月乾無泥。", "乃知此事尚難必，何況仕路如天梯。", "朝廷樂善得賢眾，臺閣俊彥聯簪犀。", "朝陽鳴鳳爲時出，一枝豈惜容其棲。", "古來磊落材與知，窮達有命理莫齊。", "悠悠百年一瞬息，俯仰天地身醯雞。", "其間得失何足校，況與鳧鶩爭稗稊。", "憶在洛陽年各少，對花把酒傾玻璃。", "二十年間幾人在，在者憂患多乖睽。", "我今三載病不飲，眼眵不辨騧與驪。", "壯心銷盡憶閑處，生計易足纔蔬畦。", "優游琴酒逐漁釣，上下林壑相攀躋。", "及身彊健始爲樂，莫待衰病須扶携。", "行當買田清潁上，與子相伴把鋤犁。"]'),
('c2919fd9-5b91-41c2-ae3f-2e19531d6267','有馬示徐無黨','歐陽修','宋','宋诗','song-poetry','','[]','吾有千里馬，毛骨何蕭森。',132,'全唐诗/poet.song.17000.json','["吾有千里馬，毛骨何蕭森。", "疾馳如奔風，白日無留陰。", "除驅當大道，步驟中五音。", "馬雖有四足，遲速在吾心。", "六轡應吾手，調和如瑟琴。", "東西與南北，高下山與林。", "惟意所欲適，九州可周尋。", "至哉人與馬，兩樂不相侵。", "伯樂識其外，徒知價千金。", "王良得其性，此術固已深。", "良馬須善馭，吾言可爲箴。"]'),
('79f68abb-ac88-4c99-ba4e-1484beaadfc8','天辰','歐陽修','宋','宋诗','song-poetry','','[]','天形如車輪，晝夜常不息。',96,'全唐诗/poet.song.17000.json','["天形如車輪，晝夜常不息。", "三辰隨出沒，曾不差分刻。", "北辰居其所，帝座嚴尊極。", "眾星拱而環，大小各有職。", "不動以臨之，任德不任力。", "天辰主下土，萬物由生殖。", "一動與一靜，同功而異域。", "惟王知法此，所以治萬國。"]'),
('b0d4c7e3-775b-4075-87a5-5d846a0275dd','再和聖俞見答','歐陽修','宋','宋诗','song-poetry','','[]','兩畿相望東與西，書來三日猶爲稽。',320,'全唐诗/poet.song.17000.json','["兩畿相望東與西，書來三日猶爲稽。", "短篇投子譬瓦礫，敢辱報之金褭蹄。", "文章至寶被埋沒，氣象往往干雲霓。", "飛黄伯樂不世出，四顧驤首空長嘶。", "嗟哉我豈敢知子，論詩賴子初指迷。", "子言古淡有真味，大羹豈須調以齏。", "憐我區區欲彊學，跛鼈曾不離汙泥。", "問子初何得臻此，豈能直到無階梯。", "如其所得自勤苦，何憚入海求靈犀。", "周旋二紀陪唱和，凡翼每竝鸞凰棲。", "有時爭勝不量力，何異弱魯攻彊齊。", "念子京師苦憔悴，經年陋巷聽朝雞。", "兒啼妻噤午未飯，得米寧擇秕與稊。", "石上紫豪家故有，剡藤瑩滑如玻璃。", "追惟平昔念少壯，零落生死嗟分睽。", "一揮累紙恣奔放，駿若駕駱仍驂驪。", "腹雖枵虛氣豪橫，猶勝諂笑病夏畦。", "名聲不朽豈易得，仕宦得路終當躋。", "年來無物不可愛，花發有酒誰同携。", "問我居留亦何事，方春苦旱憂民犂。"]'),
('982993b7-8475-4d17-b3d2-d16c98f1acd1','感春雜言','歐陽修','宋','宋诗','song-poetry','','[]','鳩鳴兮屋上，雀噪兮簷間。',202,'全唐诗/poet.song.17000.json','["鳩鳴兮屋上，雀噪兮簷間。", "百鳥感春陽，有如動機關。", "雄雌相呼和，日夕聒聒不得閑。", "砌下兩株樹，枯條有誰攀。", "春風一夜來，花葉何班班。", "乃知天巧奪人力，能使枯木生紅顔。", "奈何人爲萬物靈，不及草木與飛翾。", "自從春來何所覺，但怪睡美不覺白日高南山。", "行逢百花不著眼，豈念四氣如回環。", "却思年少憶前事，雖有駔駿難追還。", "奈何來日尚可樂，曾不勉彊相牽扳。", "淥酒如春波，黄金爲誰慳。", "人生一世中，一步百險艱。", "俟河之清不可得，聯自歌此譏愚頑。"]'),
('07ca1dad-888f-4372-ab65-26606d7433d6','廬山高贈同年劉中允歸南康','歐陽修','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','廬山高哉幾千仞兮，根盤幾百里，巀然屹立乎長江。',333,'全唐诗/poet.song.17000.json','["廬山高哉幾千仞兮，根盤幾百里，巀然屹立乎長江。", "長江西來走其下，是爲揚瀾左里兮，洪濤巨浪日夕相舂撞。", "雲消風止水鏡浄，泊舟登岸而遠望兮。", "上摩青蒼以晻靄，下壓后土之鴻厖。", "試往造乎間兮，攀緣石凳窺空谾。", "千巖萬壑響松檜，懸崖巨石飛流淙。", "水聲聒聒亂人耳，六月飛雪灑石矼。", "仙翁釋子亦往往而逢兮，吾嘗惡其學幻而言哤。", "但見丹霞翠壁遠近映樓閣，晨鍾暮鼓杳靄羅幡幢。", "幽花野草不知其名兮，風吹露濕香澗谷，時有白鶴飛來雙。", "幽尋遠去不可極，便欲絕世遺紛痝。", "羨君買田筑室老其下，插秧盈疇兮釀酒盈缸。", "欲令浮嵐暖翠千萬狀，坐卧常對乎軒窗。", "君懷磊砢有至寶，世俗不辨珉與玒。", "策名爲吏二十載，青衫白首困一邦。", "寵榮聲利不可以苟屈兮，自非青雲白石有深趣，其氣兀硉何由降。", "丈夫壯節似君少，嗟我欲說安得巨筆如長杠。"]'),
('faa3b1b0-3c9f-4a98-9ca1-3117b6986a4f','送徐生之澠池','歐陽修','宋','宋诗','song-poetry','','[]','河南地望雄西京，相公好賢天下稱。',288,'全唐诗/poet.song.17000.json','["河南地望雄西京，相公好賢天下稱。", "吹噓死灰生氣燄，談笑暖律回嚴凝。", "曾陪罇俎被顧盻，羅列臺閣皆名卿。", "徐生南國後來秀，得官古縣依崤陵。", "脚靴手板實卑賤，賢儁未可吏事繩。", "携文百篇赴知己，西望未到氣已增。", "我昔初官便伊洛，當時意氣尤驕矜。", "主人樂士喜文學，幕府最盛多交朋。", "園林相映花百種，都邑四顧山千層。", "朝行綠槐聽流水，夜飲翠幙張紅燈。", "爾來飄流二十載，鬢髮蕭索垂霜冰。", "同時竝遊在者幾，舊事欲說無人應。", "文章無用等畫虎，名譽過耳如飛繩。", "榮華萬事不入眼，憂患百慮來填膺。", "羨子年少正得路，有如扶桑初日昇。", "名高場屋已得儁，世有龍門今復登。", "出門相送親與友，何異籬鷃瞻雲鵬。", "嗟吾筆硯久已格，感激短章因子興。"]'),
('a700186f-e9f7-4f32-a4ce-80477c002ffe','葛氏鼎','歐陽修','宋','宋诗','song-poetry','','[]','大河昔决東南流，蕭條東郡今遺湫。',288,'全唐诗/poet.song.17000.json','["大河昔决東南流，蕭條東郡今遺湫。", "我從故老問其由，云古五鼎藏高丘。", "地靈川秀草木稠，鬰鬰佳氣蒸常浮。", "惟物伏見數有周，祕藏奇怪神所搜。", "天昏地慘鬼哭幽，至寶欲出風雲愁。", "蕩摇山川失維陬，九龍大戰驅蛟虬。", "割然岸烈轟雲驫，滑人夜驚鳥嘲啁。", "婦走抱兒扶白頭，蒼生仰叫黄屋憂。", "聚徒百萬如蚍蜉，千金一掃隨浮漚。", "天旋海沸動九州，此鼎始出人間留。", "滑人得之不敢收，奇模古質非今侔。", "器大難用識者不，以示世俗遭揶揄。", "明堂會朝饗諸侯，饔官有品供王羞。", "調以五味烹全牛，時有用捨吾無求。", "二三子學雕琳球，見之始驚中歎愀。", "披荒斵古爭窮蒐，苦語難出聲咿嚘。", "馬圖出河龜負疇，自古怪說何悠悠。", "嗟吾老矣不能休，勉彊作詩慙效尤。"]'),
('f51ddc53-47b5-47fe-9e11-7ba60efad149','太白戲聖俞','歐陽修','宋','宋诗','song-poetry','','[]','開元無事二十年，五兵不用太白閑。',162,'全唐诗/poet.song.17000.json','["開元無事二十年，五兵不用太白閑。", "太白之精下人間，李白高歌蜀道難。", "蜀道之難難於上青天，李白落筆生雲煙。", "千奇萬險不可攀，却視蜀道猶平川。", "宮娃扶來白已醉，醉裏詩成醒不記。", "忽然乘興登名山，龍咆虎嘯松風寒。", "山頭婆娑弄明月，九域塵土悲人寰。", "吹笙飲酒紫陽家，紫陽真人駕雲車。", "空山流水空流花，飄然已去凌青霞。", "下看區區郊與島，螢飛露濕吟秋草。"]'),
('f660e346-8623-472c-b307-44465a729124','邊戶','歐陽修','宋','宋诗','song-poetry','','[]','家世爲邊戶，年年常備胡。',96,'全唐诗/poet.song.17000.json','["家世爲邊戶，年年常備胡。", "兒僮習鞍馬，婦女能彎弧。", "胡塵朝夕起，虜騎蔑如無。", "邂逅輒相射，殺傷兩常俱。", "自從澶州盟，南北結歡娛。", "雖云免戰鬭，兩地供賦租。", "將吏戒生事，廟堂爲遠圖。", "身居界河上，不敢界河漁。"]'),
('f2b8e430-c43a-4dcc-8c43-c9456717341d','梅聖俞寄銀杏','歐陽修','宋','宋诗','song-poetry','','[]','鵝毛贈千里，所重以其人。',84,'全唐诗/poet.song.17000.json','["鵝毛贈千里，所重以其人。", "鴨脚雖百箇，得之誠可珍。", "問予得之誰，詩老遠且貧。", "霜野摘林實，京師寄時新。", "封包雖甚微，採掇皆躬親。", "物賤以人貴，人賢棄而淪。", "開緘重嗟惜，詩以報慇懃。"]'),
('42a91dba-5b3c-44ae-b7b0-1c65d7edb813','與子華原父小飲坐中寄同州江十學士休復','歐陽修','宋','宋诗','song-poetry','','[]','歲晚忽不樂，相過偶乘閑。',168,'全唐诗/poet.song.17000.json','["歲晚忽不樂，相過偶乘閑。", "百年纔幾進，一笑得亦艱。", "有酒醉嘉客，無錢買妖鬟。", "問予官何爲，侍從聯朝班。", "朝廷多賢材，何用蒯與菅。", "白髮垂兩鬢，黄金腰九環。", "奈何章綬榮，飾此木石頑。", "於國略無補，有慙常在顔。", "幸蒙二三友，相與文字間。", "江子獨捨我，高鴻去難攀。", "秋風動沙苑，郡閣當南山。", "吟詠日多暇，詔條寬可頒。", "寒雲雪紛糅，幽鳥春緜蠻。", "勝事日向好，思君何時還。"]'),
('d02dbf69-1a67-4a7b-b38f-ea85af59bcd6','述懷','歐陽修','宋','宋诗','song-poetry','','[]','歲律忽其周，陰風慘遼夐。',276,'全唐诗/poet.song.17000.json','["歲律忽其周，陰風慘遼夐。", "孤懷念時節，朽質驚衰病。", "憶始來京師，街槐綠方映。", "清霜一以零，眾木少堅勁。", "物理固如此，人生寧久盛。", "當時不樹立，後世猶譏評。", "顧我實孤生，饑寒談孔孟。", "壯年猶勇爲，刺口論時政。", "中間蒙選擢，官實居諫諍。", "豈知身愈危，惟恐職不稱。", "十年困風波，九死出檻穽。", "再生君父恩，如報犬馬性。", "歸來見親識，握手相弔慶。", "丹心皎雖存，白髮生已迸。", "慙無羽毛彩，來與鸞凰竝。", "鎩翮追羣翔，孤唳驚眾聽。", "嚴嚴玉堂署，清禁肅而靜。", "職業愧論思，文章慙誥命。", "厚顔難久居，歸計無荒逕。", "偷閑就朋友，笑語雜嘲詠。", "歡情雖索寞，得酒猶豪橫。", "羣居固可樂，寵祿尤難幸。", "何日早收身，江湖一漁艇。"]'),
('9004499e-2a1e-43ce-bad8-d04a8ce33bdb','和劉原父澄心紙','歐陽修','宋','宋诗','song-poetry','','[]','君不見曼卿子美真奇才，久已零落埋黄埃。',259,'全唐诗/poet.song.17000.json','["君不見曼卿子美真奇才，久已零落埋黄埃。", "子美生窮死愈貴，殘章斷藁如瓊瑰。", "曼卿醉題紅粉壁，壁粉已剝昏煙煤。", "河傾崑崙勢曲折，雪壓太華高崔嵬。", "自從二子相繼沒，山川氣象皆低摧。", "君家雖有澄心紙，有敢下筆知誰哉。", "宣州詩翁餓欲死，黄鵠折翼鳴聲哀。", "有時得飽好言語，似聽高唱傾金罍。", "二子雖死此翁在，老手尚能工翦裁。", "奈何不寄反示我，如棄正論求俳詼。", "嗟我今衰不復昔，空能把卷闔且開。", "百年干戈流戰血，一國歌舞今荒臺。", "當時百物盡精好，往往遺棄淪蒿萊。", "君從何處得此紙，純堅瑩膩卷百枚。", "官曹職事喜床暇，臺閣唱和相追陪。", "文章自古世不乏，間出安知無後來。"]'),
('8accbf80-0439-4f0e-a403-bb817af4964c','奉使契丹道中答劉原父桑乾河見寄之作','歐陽修','宋','宋诗','song-poetry','','[]','憶昨初受命，同下紫宸朝。',180,'全唐诗/poet.song.17000.json','["憶昨初受命，同下紫宸朝。", "問君當何之，笑指北斗杓。", "共念到幾時，春風約回鑣。", "所持既異事，前後忽相遼。", "風月坐易失，山川行知遥。", "回頭三千里，雙闕在紫霄。", "我老倦鞍馬，安能事吟嘲。", "君才綽有餘，新句益飄飄。", "前日逢呂郭，解鞍憩山要。", "僮僕相問喜，馬鳴亦蕭蕭。", "出君桑乾詩，寄我慰寂寥。", "又喜前見君，相期駐征軺。", "雖知不久留，一笑樂亦聊。", "歸路踐冰雪，還愛脫狐貂。", "君行我即至，春酒待相邀。"]'),
('cd4dc4eb-65eb-4880-8012-ec17af41f307','書素屏','歐陽修','宋','宋诗','song-poetry','','[]','我行三千里，何物與我親。',120,'全唐诗/poet.song.17000.json','["我行三千里，何物與我親。", "念此尺素屏，曾不離我身。", "曠野多黄沙，當午白日昏。", "風力若牛弩，飛砂還射人。", "暮投山椒館，休此車馬勤。", "開屏置牀頭，輾轉夜向晨。", "卧聽穹廬外，北風驅雪雲。", "勿愁明日雪，且擁狐貂溫。", "君命固有嚴，羈旅誠苦辛。", "但苟一夕安，其餘非所云。"]'),
('5f3247c4-2f1e-4ed2-a93a-ff55aafa55fc','馬齧雪','歐陽修','宋','宋诗','song-poetry','','[]','馬饑齧雪渴飲冰，北風卷地來崢嶸。',112,'全唐诗/poet.song.17000.json','["馬饑齧雪渴飲冰，北風卷地來崢嶸。", "馬悲躑躅人不行，日暮塗遠千山橫。", "我謂行人止歎聲，馬當勉力無悲鳴。", "白溝南望如掌平，十里五里長短亭。", "臘雪銷盡春風輕，火燒原頭青草生。", "遠客還家紅袖迎，樂哉人馬歸有程。", "男兒雖有四方志，無事何須勤遠征。"]'),
('c90ee5bb-4f5c-4d45-86c6-d0d3bfa45e73','風吹沙','歐陽修','宋','宋诗','song-poetry','','[]','北風吹沙千里黄，馬行確犖悲摧藏。',64,'全唐诗/poet.song.17000.json','["北風吹沙千里黄，馬行確犖悲摧藏。", "當冬萬物慘顔色，冰雪射日生光芒。", "一年百日風塵道，安得朱顔長美好。", "攬鞍鞭馬行勿遲，酒熟花開二月時。"]'),
('6c1f0cc5-6ea8-47eb-b2dd-2dac7b798d7b','重贈劉原父','歐陽修','宋','宋诗','song-poetry','','[]','憶昨君當使北時，我往別君飲君家。',242,'全唐诗/poet.song.17000.json','["憶昨君當使北時，我往別君飲君家。", "愛君小鬟初買得，如手未觸新開花。", "醉中上馬不知夜，但見九陌燈火人諠譁。", "歸來不記與君別，酒醒起坐空咨嗟。", "自言我亦隨往矣，行即逢君何恨邪。", "豈知前後不相及，歲月忽忽行無涯。", "古北嶺口踏新雪，馬盂山西捍落霞。", "風雲暮慘失道路，磵谷夜靜聞麏䴥。", "行迷方嚮但看日，度盡山險方逾沙。", "客心漸遠誠易感，見君雖晚喜莫加。", "我後君歸祗十日，君先躍馬未足誇。", "新年花發見回鴈，歸路柳暗藏嬌鴉。", "而今春物已爛漫，念昔草木冰未芽。", "人生每苦勞事役，老去尚能憐物華。", "從今有暇即相過，安得載酒長盈車。"]'),
('c6fc939b-9ed6-4921-8c71-3f7c68cb1120','贈沈遵','歐陽修','宋','宋诗','song-poetry','','[]','羣動夜息浮雲陰，沈夫子彈醉翁吟。',236,'全唐诗/poet.song.17000.json','["羣動夜息浮雲陰，沈夫子彈醉翁吟。", "醉翁吟，以我名，我初聞之喜且驚。", "宮聲三疊何泠泠，酒行暫止四坐傾。", "有如風輕日煖好鳥語，夜靜山響春泉鳴。", "坐思千巖萬壑醉眠處，寫君三尺膝上橫。", "沈夫子，恨君不爲醉翁客，不見翁醉山間亭。", "翁歡不待絲與竹，把酒終日聽泉聲。", "有時醉倒枕谿石，青山白雲爲枕屏。", "花間百鳥喚不覺，日落山風吹自醒。", "我時四十猶彊力，自號醉翁聊戲客。", "爾來憂患十年間，鬢髮未老嗟先白。", "滁人思我雖未忘，見我今應不能識。", "沈夫子，愛君一罇復一琴，萬事不可干其心。", "自非曾是醉翁客，莫向俗耳求知音。"]'),
('044fac19-5f3f-4dc2-9bb4-bea362faaf35','答聖俞','歐陽修','宋','宋诗','song-poetry','','[]','人皆喜詩翁，有酒誰肯一醉之。',284,'全唐诗/poet.song.17000.json','["人皆喜詩翁，有酒誰肯一醉之。", "嗟我獨無酒，數往從翁何所爲。", "翁居南方我北走，世路離合安可期。", "汴渠千艘日上下，來及水門猶未知。", "五年不見勞夢寐，三日始往何其遲。", "城東賺河有名字，萬家棄水爲汙池。", "人居其上苟賢者，我視此水猶漣漪。", "入門下馬解衣带，共坐習習清風吹。", "溼薪熒熒煮薄茗，四顧壁立空無遺。", "萬錢方丈飽則止，一瓢飲水樂可涯。", "況出新詩數十首，珠璣大小光陸離。", "他人欲一不可有，君家筐篋滿莫持。", "才大名高乃富貴，豈比金紫包愚癡。", "貴賤同爲一丘土，聖賢獨如星日垂。", "道德內樂不假物，猶須朋友并良時。", "蟬聲漸已變秋意，得酒安問醇與醨。", "玉堂官閑無事業，親舊幸可從其私。", "與翁老矣會有幾，當棄百事勤追隨。"]'),
('8fa805a6-7129-4b08-b062-bb4e050f68bb','感興五首  其一','歐陽修','宋','宋诗','song-poetry','','[]','奉祠嚴祕館，攝事罄精誠。',72,'全唐诗/poet.song.17000.json','["奉祠嚴祕館，攝事罄精誠。", "歲晏悲木落，天寒聞鶴鳴。", "念昔丘壑趣，豈知朝市情。", "弱齡嬰仕宦，壯節慕功名。", "多病慙厚祿，早衰歎餘生。", "未知犬馬報，安得遂歸耕。"]'),
('3caa5b72-a637-4bfb-878f-7cb6fc8e6899','感興五首  其二','歐陽修','宋','宋诗','song-poetry','','[]','懷祿不知慙，人雖不吾責。',72,'全唐诗/poet.song.17000.json','["懷祿不知慙，人雖不吾責。", "貧交重意氣，握手猶感激。", "煌煌腰間金，兩鬢颯已白。", "有生天地間，壽考非金石。", "古人報一飯，君子不苟得。", "憂來自悲歌，涕淚下沾臆。"]'),
('62129818-5aef-4c8c-b1eb-27aae0a3c1ad','感興五首  其三','歐陽修','宋','宋诗','song-poetry','','[]','清夜雖云長，白日亦易晚。',96,'全唐诗/poet.song.17000.json','["清夜雖云長，白日亦易晚。", "循環百刻中，勢若丸走坂。", "盈虧自相補，得失何足算。", "餐霞可延年，飲酒誠自損。", "未知辛苦長，孰若適意短。", "二者一何偷，百年皆不免。", "顔回不著述，後世存愈遠。", "聖賢非虛名，惟善爲可勉。"]'),
('c4959e10-189a-42ba-907c-1d3476e46b67','感興五首  其四','歐陽修','宋','宋诗','song-poetry','','[]','仕宦希寸祿，庶無饑寒迫。',59,'全唐诗/poet.song.17000.json','["仕宦希寸祿，庶無饑寒迫。", "讀書文章，本以代耕織。", "學成頗自喜，祿厚愈多責。", "挾山以超海，事有非其力。", "君子貴量能，無輕食人食。"]'),
('54b789a5-ed90-4277-b62c-794a2f35a16a','感興五首  其五','歐陽修','宋','宋诗','song-poetry','','[]','唧唧復唧唧，夜歎曉未息。',72,'全唐诗/poet.song.17000.json','["唧唧復唧唧，夜歎曉未息。", "蟲聲急愈尖，病耳聞若刺。", "壯士易爲老，良時難再得。", "日月相隨東，天行自西北。", "三者不相謀，萬古無窮極。", "安知人間世，歲月忽已易。"]'),
('ecd0db25-5b0d-4419-ad78-be72939b05c2','吳學士石屏歌','歐陽修','宋','宋诗','song-poetry','','[]','晨光入林眾鳥驚，腷膊羣飛鴉亂鳴。',286,'全唐诗/poet.song.17000.json','["晨光入林眾鳥驚，腷膊羣飛鴉亂鳴。", "穿林四散投空去，黄口巢中饑待哺。", "雌者下啄雄高盤，雄雌相呼飛復還。", "空林無人鳥聲樂，古木參天枝屈蟠。", "下有怪石橫樹間，煙埋草沒苔蘚斑。", "借問此景誰圖寫，乃是吳家石屏者。", "虢工刳山取山骨，朝鑱暮斵非一日，萬象皆從石中出。", "吾嗟人愚不見天地造化之初難，乃云萬物生自然。", "豈知鎸鑱刻畫醜與妍，千狀萬態不可殫。", "神愁鬼泣晝夜不得閑，不然安得巧工妙手憊精竭思不可到，若無若有縹緲生雲煙。", "鬼神功成天地惜，藏在虢山深處石。", "惟人有心無不獲，天地雖神藏不得。", "又疑鬼神好勝憎吾儕，欲極奇怪窮吾才，乃傳張生自西來。", "吳家學士見且咍，醉點紫毫淋墨煤。", "君才自與鬼神鬭，嗟我老矣安能陪。"]'),
('2a7b3a3f-c1b7-47c2-bf5d-1e635c2bb1db','初食車螯','歐陽修','宋','宋诗','song-poetry','','[]','纍纍盤中蛤，來自海之涯。',215,'全唐诗/poet.song.17000.json','["纍纍盤中蛤，來自海之涯。", "坐客初未識，食之先歎嗟。", "五代昔乖隔，九州如剖瓜。", "東南限淮海，邈不通夷華。", "於時北州人，飲食陋莫加。", "雞豚爲異味，貴賤無等差。", "自從聖人出，天下爲一家。", "南產錯交廣，西珍富卭巴。", "水載每連舳，陸輸動盈車。", "谿潛細毛髮，海怪雄鬚牙。", "豈惟貴公侯，閭巷飽魚蝦。", "此蛤今始至，其來何晚邪。", "螯蛾聞二名久見南人誇。", "璀璨殼如玉，斑斕點生花。", "含漿不肯吐，得火遽已呀。", "共食惟恐後，急先屢成譁。", "但喜美無厭，豈思來甚遐。", "多慙海上翁，辛苦斵泥沙。"]'),
('039de303-feea-47c8-a37c-98e1da484da3','送裴如晦之吳江','歐陽修','宋','宋诗','song-poetry','','[]','雞鳴車馬馳，夜半聲未已。',120,'全唐诗/poet.song.17000.json','["雞鳴車馬馳，夜半聲未已。", "皇皇走聲利，與日爭寸晷。", "而我獨何爲，閑宴奉君子。", "京師十二門，四方來萬里。", "顧吾坐中人，暫聚浮雲爾。", "念子一扁舟，片帆如鳥起。", "文章富千箱，吏祿求斗米。", "白玉有時沽，青衫豈須恥。", "人生足憂患，合散乃常理。", "惟應當歡時，飲酒如飲水。"]'),
('5307b85c-bce5-494f-9249-c551b4d820a0','盤車圖','歐陽修','宋','宋诗','song-poetry','','[]','淺山嶙嶙，亂石矗矗，山石磽聱車碌碌。',232,'全唐诗/poet.song.17000.json','["淺山嶙嶙，亂石矗矗，山石磽聱車碌碌。", "山勢盤斜隨澗谷，側轍傾轅如欲覆。", "出乎兩崖之隘口，忽見百里之平陸。", "坡長坂峻牛力疲，天寒日暮人心速。", "楊襃忍饑官太學，得錢買此纔盈幅。", "愛其樹老石硬，山回路轉。", "高下曲直，橫斜隱見。", "妍媸嚮背各有態，遠近分毫皆可辨。", "自言昔有數家筆，畫古傳多名姓失。", "後來見者知謂誰，乞詩梅老聊稱述。", "古畫畫意不畫形，梅詩詠物無隱情。", "忘形得意知者寡，不若見詩如見畫。", "乃知楊生真好奇，此畫此詩兼有之。", "樂能自足乃爲富，豈必金玉名高貲。", "朝看畫，暮讀詩，楊生得此可不饑。"]'),
('902c884d-8626-473a-9ed3-2f82fb39230d','答梅聖俞莫登樓','歐陽修','宋','宋诗','song-poetry','','[]','莫登樓，樂哉都人方競遊，樓闕夜氣春煙浮。',188,'全唐诗/poet.song.17000.json','["莫登樓，樂哉都人方競遊，樓闕夜氣春煙浮。", "玉輪東來從海陬，纖靄洗盡當空留。", "燈光月色爛不收，火龍銜山祝千秋。", "緣竿踏索雜幻優，鼓喧管咽耳欲咻。", "清風嫋嫋夜悠悠，瑩蹄文角車如流。", "婭姹扶欄車兩頭，髧髦垂鬟嬌未羞。", "念昔年少追朋儔，輕衫駿馬今則不。", "中年病多昏兩眸，夜視曾不如鵂鶹。", "足雖欲往意已休，惟思睡眠擁衾裯。", "人心利害兩不謀，春陽稍愆天子憂。", "安得四野陰雲油，甘澤以時豐麥麰。", "遊騎踏泥非我愁。"]'),
('83e4c1f6-ffc9-42fb-a28b-2a3ab9b95c75','答聖俞莫飲酒','歐陽修','宋','宋诗','song-poetry','','[]','子謂莫飲酒，我謂莫作詩。',156,'全唐诗/poet.song.17000.json','["子謂莫飲酒，我謂莫作詩。", "花開木落蟲鳥悲，四時百物亂我思。", "朝吟摇頭暮蹙眉，雕肝琢腎聞退之。", "此翁此語還自違，豈如飲酒無所知。", "自古不飲無不死，惟有爲善不可遲。", "功施當世聖賢事，不然文章千載垂。", "其餘酩酊一罇酒，萬事崢嶸皆可齊。", "腐腸糟肉兩家說，計較屑屑何其卑。", "死生壽夭無足道，百年長短纔幾時。", "但飲酒，莫作詩，子其聽我言非癡。"]'),
('b264828d-fcf2-465d-8564-f1be584ddb35','思白兔雜言戲答公儀憶鶴之作','歐陽修','宋','宋诗','song-poetry','','[]','君家白鶴白雪毛，我家白兔白玉毫。',214,'全唐诗/poet.song.17000.json','["君家白鶴白雪毛，我家白兔白玉毫。", "誰將贈兩翁，謂此二物皎潔勝瓊瑶。", "已憐野性易馴擾，復愛仙格何孤高。", "玉兔四蹄不解舞，不如雙鶴能清嘷。", "低垂兩翅趁節拍，婆娑弄影誇嬌饒。", "兩翁念此二物者，久不見之心甚勞。", "京師少年殊好尚，意氣橫出爭雄豪。", "清罇美酒不輒飲，千金爭買紅顔韶。", "莫令少年聞我語，笑我乖僻遭譏嘲。", "或被偷開兩家籠，縱此二物令逍遥。", "兔奔滄海却入明月窟，鶴飛玉山千仞直上青松巢。", "索然兩衰翁，何以慰無憀。", "纖腰綠鬢既非老者事，玉山滄海一去何由招。"]'),
('fae30205-9527-4f48-8626-b253fa1f7fad','戲答聖俞','歐陽修','宋','宋诗','song-poetry','','[]','鶴行而啄，青玉嘴，枯松脚。',229,'全唐诗/poet.song.17000.json','["鶴行而啄，青玉嘴，枯松脚。", "兔蹲而纍，尖兩耳，攢四蹄。", "往往於人家高堂浄屋曾見之，錦裝玉軸掛壁垂。", "乍見拭目猶驚疑，羽毛襂褷眼睛活，若動不動如風吹。", "主人矜誇百金買，云此絕筆人間奇。", "畫師畫生不畫死，所得百分三二爾，豈如翫物翫其真。", "凡物可愛惟精神，況此二物物之珍。", "月光臨靜夜，雪色凌清晨。", "二物於此時，瑩無一點纖埃塵。", "不惟可醒醉翁醉，能使詩老詩思添清新。", "醉翁謂詩老，子勿誚我愚。", "老弄兔兒憐鶴雛，與子俱老其衰乎。", "奈何反捨我，欲問東家看舞姝。", "須防舞姝見客笑，白髮蒼顔君自照。"]'),
('209fb179-6918-4aae-be0b-b937be6c75c2','和梅龍圖公儀謝鷴','歐陽修','宋','宋诗','song-poetry','','[]','有詩鶴勿喜，無詩鷴勿悲。',276,'全唐诗/poet.song.17000.json','["有詩鶴勿喜，無詩鷴勿悲。", "人禽固異性，所趣各有宜。", "朝戲青竹林，暮棲高樹枝。", "咿呦山鹿鳴，格磔野鳥啼。", "聲音不相通，各以類自隨。", "使鶴居籠中，垂頭以聽詩。", "鶢鶋享鍾鼓，魚鳥見西施。", "鷴鶴不宜爭，所爭良可知。", "蚍蜉與蟻子，爲物固已微。", "當彼兩交鬭，勇如聞鼓鼙。", "有心皆好勝，未免爭是非。", "於我一何薄，於彼一何私。", "欄檻啄花卉，叫號驚睡兒。", "跳踉兩脚長，落泊雙翅垂。", "何足充翫好，於何定妍媸。", "鷴口不能言，夜夢以告之。", "主人起謝鷴，從我今幾時。", "僮奴謹守護，出入煩提携。", "逍遥遂棲息，飲啄安雄雌。", "花底弄日影，風前理毛衣。", "豈非主人恩，報效爾宜思。", "主人今白髮，把酒無翠眉。", "養鶴鷴又妬，我言堪解頤。"]'),
('ed6f85ac-da30-485b-a073-fea966a9c947','和聖俞感李花','歐陽修','宋','宋诗','song-poetry','','[]','昨日摘花初見桃，今日摘花還見李。',64,'全唐诗/poet.song.17000.json','["昨日摘花初見桃，今日摘花還見李。", "晴風暖日苦相催，春物所餘知有幾。", "中年多病壯心衰，對酒思歸未得歸。", "不及牆根花與草，春來隨處自芳菲。"]'),
('0312eaa6-d6df-45b3-b59c-78d6464ef318','折刑部海棠戲贈聖俞二首  其一','歐陽修','宋','宋诗','song-poetry','','[]','摇摇牆頭花，笑笑弄顔色。',84,'全唐诗/poet.song.17000.json','["摇摇牆頭花，笑笑弄顔色。", "荒凉眾草間，露此紅的皪。", "草木本無情，及時如自得。", "青春不可恃，白日忽已昃。", "繞之重吟哦，歸坐成歎息。", "人生浪自苦，得酒且開釋。", "不見宛陵翁，作詩頭早白。"]'),
('e4541760-0f3f-4a90-aff1-68bb6365d990','折刑部海棠戲贈聖俞二首  其二','歐陽修','宋','宋诗','song-poetry','','[]','摇摇牆頭花，豔豔爭青娥。',72,'全唐诗/poet.song.17000.json','["摇摇牆頭花，豔豔爭青娥。", "朝見開尚少，暮看繁已多。", "不惜花開繁，所惜時節過。", "昨日枝上紅，今日隨流波。", "物理固如此，去來知奈何。", "達人但飲酒，壯士徒悲歌。"]'),
('aeaca5a6-48f1-4bb5-aac1-f09462cb9cdb','刑部看竹效孟效體','歐陽修','宋','宋诗','song-poetry','','[]','花妍兒女姿，零落一何速。',100,'全唐诗/poet.song.17000.json','["花妍兒女姿，零落一何速。", "竹色君子德，猗猗寒更綠。", "京師多名園，車馬紛馳逐。", "春風紅紫時，見此蒼翠玉。", "凌亂迸青苔，蕭踈拂華屋。", "森森日影閑，濯濯生意足。", "幸此接清賞，寧辭薦芳醁。", "黄昏人去鎖空廊，枝上月明春鳥宿。"]'),
('af13720a-493b-467d-8dcd-9bd35021af77','贈沈博士歌','歐陽修','宋','宋诗','song-poetry','','[]','沈夫子，胡爲醉翁吟，醉翁豈能知爾琴。',286,'全唐诗/poet.song.17000.json','["沈夫子，胡爲醉翁吟，醉翁豈能知爾琴。", "滁山高絕滁水深，空巖悲風夜吹林。", "山溜白玉懸青岑，一瀉萬仞源莫尋。", "醉翁每來喜登臨，醉倒石上遺其簪，雲荒石老歲月侵。", "子有三尺徽黄金，寫我幽思窮崎嶔。", "自言愛此萬仞水，謂是太古之遺音。", "泉淙石亂到不平，指下嗚咽悲人心。", "時時弄餘聲，言語軟滑如春禽。", "嗟乎沈夫子，爾琴誠工彈且止。", "我昔被謫居滁山，名雖爲翁實少年。", "坐中醉客誰最賢，杜彬琵琶皮作絃。", "自從彬死世莫傳，玉練鎖聲入黄泉。", "死生聚散日零落，耳冷心衰翁索莫。", "國恩未報慙祿厚，世事多虞嗟力薄。", "顔摧鬢改真一翁，心以憂醉安知樂。", "沈夫子謂我，翁言何苦悲。", "人生百年間，飲酒能幾時。", "攬及推琴起視夜，仰見河漢西南移。"]'),
('fc598697-e681-4eb6-828d-c4223cfd7dd9','和聖俞李侯家鴨脚子','歐陽修','宋','宋诗','song-poetry','','[]','鴨脚生江南，名實未相浮。',168,'全唐诗/poet.song.17000.json','["鴨脚生江南，名實未相浮。", "絳囊因入貢，銀杏貴中州。", "致遠有餘力，好奇自賢侯。", "因令江上根，結實夷門秋。", "始摘纔三四，金奩獻凝旒。", "公卿不及識，天子百金酬。", "歲久子漸多，纍纍枝上稠。", "主人名好客，贈我比珠投。", "博望昔所徙，蒲萄安石榴。", "想其初來時，厥價與此侔。", "今也徧中國，籬根及牆頭。", "物性久雖在，人情逐時流。", "惟當記其始，後世知來由。", "是亦史官法，豈徒續君謳。"]'),
('3acbda01-8acf-4c63-b442-c1f363e7bd80','送吳生南歸','歐陽修','宋','宋诗','song-poetry','','[]','自我得曾子，於茲二十年。',288,'全唐诗/poet.song.17000.json','["自我得曾子，於茲二十年。", "今又得吳生，既得喜且歎。", "古士不並出，百年猶比肩。", "區區彼江西，其產多材賢。", "吳生初自疑，所擬豈其倫。", "我始見曾子，文章初亦然。", "崑崙傾黄河，渺漫盈百川。", "决疏以道之，漸斂收橫瀾。", "東溟知所歸，識路到不難。", "吳生始見我，袖藏新文篇。", "忽從布褐中，百寶寫我前。", "明珠雜璣貝，磊砢或不圓。", "問生久懷此，奈何初無聞。", "吳生不自隱，欲吐羞俛顔。", "少也不自重，不爲鄉人憐。", "中雖知自悔，學問苦賤貧。", "自謂久而信，力行困彌堅。", "今來决疑惑，幸冀蒙洗湔。", "我笑謂吳生，爾其聽我言。", "世所謂君子，何異於眾人。", "眾人爲不善，積微成滅身。", "君子能自知，改過不逡巡。", "惟於斯二者，愚智遂以分。", "顔回不貳過，後世稱其仁。"]'),
('730700f7-2831-4517-b7e6-83e6b7bd6e24','樂哉襄陽人送劉太尉從廣赴襄陽','歐陽修','宋','宋诗','song-poetry','','[]','嗟爾樂哉襄陽人，萬屋連甍清漢濱。',256,'全唐诗/poet.song.17000.json','["嗟爾樂哉襄陽人，萬屋連甍清漢濱。", "語言輕清微带秦，南通交廣西峨岷。", "羅縠纖麗藥物珍，枇杷甘橘薦清罇。", "磊落金盤爛璘璘，槎頭縮項昔所聞。", "黄橙擣齏香復辛，春雷動地竹走根。", "錦苞玉筍味爭新，鳳林花發南山春。", "掩映谷口藏山門，樓臺金碧瓦鱗鱗。", "峴首高亭倚浮雲，漢水如天瀉沄沄。", "斜陽返照白鳥羣，兩岸桑柘雜耕耘。", "文王遺化已寂寞，千載誰復思其仁。", "荆州漢魏以來重，古今相望多名臣。", "嗟爾樂哉襄陽人，道扶白髮抱幼孫。", "遠迎劉侯朱兩輪，劉侯年少氣甚淳。", "詩書學問若寒士，罇俎談笑多嘉賓。", "往時邢洺有善政，至今遺愛留其民。", "誰能持我詩以往，爲我先賀襄陽人。"]'),
('084eff9f-45c0-459d-bd61-501721ac5cf6','奉酬揚州劉舍人見寄之作','歐陽修','宋','宋诗','song-poetry','','[]','別君今幾時，歲月如插羽。',132,'全唐诗/poet.song.17000.json','["別君今幾時，歲月如插羽。", "悠悠寢與食，忽忽朝復暮。", "紛紛竟何爲，凜凜還自懼。", "朝廷無獻納，倉廩徒耗蠹。", "風霜苦見侵，衰病日增故。", "江湖豈不思，懇悃布已屢。", "美哉廣陵公，風政傳道路。", "優游侍從臣，左右天子顧。", "君來一何遲，我請亦有素。", "何當兩還分，尚冀一相遇。", "把手或未能，尺書幸時寓。"]'),
('6547b519-8ae6-4a8f-9c45-a3fd9d3df10a','西齋手植菊花過節始開偶書奉呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','秋風吹浮雲，寒雨灑清曉。',132,'全唐诗/poet.song.17000.json','["秋風吹浮雲，寒雨灑清曉。", "鮮鮮牆下菊，顔色一何好。", "好色豈能常，得時仍不早。", "文章損精神，何用覷天巧。", "四時悲代謝，萬物惜調槁。", "豈知寒鑑中，兩鬢甚秋草。", "東城彼詩翁，學問同少小。", "風塵世事多，日月良會少。", "我有一罇酒，念君思共倒。", "上浮黄金蕊，送以清歌裊。", "爲君發朱顔，可以却君老。"]'),
('fb53c9e7-9db5-4542-a9a8-06a06f344c10','於劉功曹家見楊直講女奴彈琵琶戲作呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','大絃聲遲小絃促，十歲嬌兒彈啄木。',260,'全唐诗/poet.song.17000.json','["大絃聲遲小絃促，十歲嬌兒彈啄木。", "啄木不啄新生枝，惟啄槎牙枯樹腹。", "花繁蔽日鎖空園，樹老參天杳深谷。", "不見啄木鳥，但聞啄木聲。", "春風和暖百鳥語，山路磽确行人行。", "啄木飛從何處來，花間葉底時丁丁。", "林空山靜啄愈響，行人舉頭飛鳥驚。", "嬌兒身小指撥硬，功曹廳冷絃索鳴。", "繁聲急節傾四坐，爲爾飲盡黄金觥。", "楊君好雅心不俗，太學官卑飯脫粟。", "嬌兒兩幅青布裙，三脚木牀坐調曲。", "奇書古畫不論價，盛以錦囊裝玉軸。", "披圖掩卷有時倦，卧聽琵琶仰看屋。", "客來呼兒旋梳洗，滿額花鈿貼黄菊。", "雖然可愛眉目秀，無奈長饑頭頸縮。", "宛陵詩翁勿誚渠，人生自足乃爲娛，此兒此曲翁家無。"]'),
('24752fd3-f05f-46ea-ba42-6b53c9947eb8','長句送陸子履學士通判宿州','歐陽修','宋','宋诗','song-poetry','','[]','古人相馬不相皮，瘦馬雖瘦骨法奇。',200,'全唐诗/poet.song.17000.json','["古人相馬不相皮，瘦馬雖瘦骨法奇。", "世無伯樂良可嗤，千金市馬惟市肥。", "騏驥伏櫪兩耳垂，夜聞秋風仰秣嘶。", "一朝絡以黄金羈，旦刷吳越暮燕陲。", "丈夫可憐憔悴時，世俗庸庸皆見遺。", "子履自少聲名馳，落筆文章天下知。", "開懷吐胸不自疑，世路迫窄多穽機。", "鬢毛零落風霜摧，十年江湖千首詩。", "歸來京國舊遊非，大笑相逢索酒巵。", "酒酣猶能弄峨眉，山川摇落百草腓。", "愛君不改青松枝，念君明當整驂騑。", "贈以瑶華期早歸，豈惟朋友相追隨，坐使臺閣生光輝。"]'),
('98f587a8-cbcf-48d3-97c7-58c6560bb4a3','送公期得假歸絳','歐陽修','宋','宋诗','song-poetry','','[]','風吹積雪銷太行，水暖河橋楊柳芳。',64,'全唐诗/poet.song.17000.json','["風吹積雪銷太行，水暖河橋楊柳芳。", "少年初仕即京國，故里幾歸成鬢霜。", "山行馬瘦春泥滑，野飯天寒餳粥香。", "留連芳物佳節過，束带還來朝未央。"]'),
('14cf8149-f809-4f55-80a9-f620f7af3d01','送宋次道學士赴太平州','歐陽修','宋','宋诗','song-poetry','','[]','古堤老柳藏春煙，桃花水下清明前。',128,'全唐诗/poet.song.17000.json','["古堤老柳藏春煙，桃花水下清明前。", "江南太守見之笑，擊鼓插旗催解船。", "侍中令德宜有後，學士清才方少年。", "文章秀粹得家法，筆畫點綴多餘妍。", "藏書萬卷復强記，故事累朝能口傳。", "來居侍從乃其職，遠置州郡誰謂然。", "交游一時盡英俊，車馬兩岸來聯翩。", "船頭朝轉暮千里，有酒胡不爲留連。"]'),
('cdb13add-7aa7-4960-a3d7-cafcb607d003','謝觀文王尚書惠西京牡丹','歐陽修','宋','宋诗','song-poetry','','[]','京師輕薄兒，意氣多豪俠。',299,'全唐诗/poet.song.17000.json','["京師輕薄兒，意氣多豪俠。", "爭誇朱顔事年少，肯慰白髮將花插。", "尚書好事與俗殊，憐我霜毛苦蕭颯。", "贈以洛陽花滿盤，鬭麗爭奇紅紫雜。", "兩京相去五百里，幾日馳來足何捷。", "紫檀金粉香未吐，綠萼紅苞露猶浥。", "謂我嘗爲各陽客，頗向此花曾涉獵。", "憶昔進士初登科，始事相公沿吏牒。", "河南官屬盡賢俊，洛城池籞相連接。", "我時年纔二十餘，每到花開如蛺蝶。", "姚黄魏紅腰带鞓，潑墨齊頭藏綠葉。", "鶴翎添色又其次，此外雖妍猶婢妾。", "爾來不覺三十年，歲月纔如熟羊胛。", "無情草木不改色，多難人生摧拉。", "見花了了雖舊識，感物依依幾抆睫。", "念昔逢花必沽酒，起坐驩呼屢傾榼。", "而今得酒復何爲，愛花繞之空百匝。", "心衰力懶難勉彊，與昔一何殊勇怯。", "感公意厚不知報，墨筆淋漓口徒囁。"]'),
('de21e090-c05f-44f8-a488-8215b02bc4ff','送朱職方提舉運鹽','歐陽修','宋','宋诗','song-poetry','','[]','齊人謹鹽筴，伯者之事爾。',288,'全唐诗/poet.song.17000.json','["齊人謹鹽筴，伯者之事爾。", "計口收其餘，登耗以生齒。", "民充國亦富，粲若有條理。", "惟非三王法，儒者猶爲恥。", "後世益不然，榷奪由漢始。", "權量自持操，屑屑已甚矣。", "穴竈如蜂房，熬波銷海水。", "豈知戴白民，食淡有至死。", "物艱利俞厚，令出姦隨起。", "良民陷盜賊，峻法難禁止。", "問官得幾何，月課煩笞箠。", "公私兩皆然，巧拙可知己。", "英英職方郎，文行粹而美。", "連年宿與泗，有政皆可紀。", "忽來從辟書，感激赴知己。", "閔然哀遠人，吐策獻天子。", "治國如治身，四民猶四體。", "奈何窒其一，無異鈦厥趾。", "工作百商行，本末相表裏。", "臣請通其流，爲國掃泥滓。", "金錢歸府藏，滋味飽閭里。", "利害難先言，幾月可較比。", "鹽官皆謂然，丞相曰可喜。", "適時乃爲才，高論徒譎詭。"]'),
('60427a91-5089-402f-b757-ff18a9304242','嘗新茶呈聖俞','歐陽修','宋','宋诗','song-poetry','','[]','建安三千里，京師三月嘗新茶。',240,'全唐诗/poet.song.17000.json','["建安三千里，京師三月嘗新茶。", "人情好先務取勝，百物貴早相矜誇。", "年窮臘盡春欲動，蟄雷未起驅龍蛇。", "夜聞擊鼓滿山谷，千人助叫聲喊呀。", "萬木寒癡睡不醒，惟有此樹先萌芽。", "乃知此爲最靈物，宜其獨得天地之英華。", "終朝採摘不盈掬，通犀銙小圓復窊。", "鄙哉穀雨槍與旗，多不足貴如刈麻。", "建安太守急寄我，香蒻包裹封題斜。", "泉甘器潔天色好，坐中揀擇客亦嘉。", "新香嫩色如始造，不似來遠從天涯。", "停匙側盞試水路，拭目向空看乳花。", "可憐俗夫把金錠，猛火炙背如暇蟇。", "由來真物有真賞，坐逢詩老頻咨嗟。", "須臾共起索酒飲，何異奏雅終淫哇。"]'),
('c50f47a8-f7c4-4516-b95a-4a2999525f20','次韻再作','歐陽修','宋','宋诗','song-poetry','','[]','吾年向老世味薄，所好未衰惟飲茶。',242,'全唐诗/poet.song.17000.json','["吾年向老世味薄，所好未衰惟飲茶。", "建谿苦遠雖不到，自少嘗見閩人誇。", "每嗤江浙凡茗草，叢生狼藉惟藏蛇。", "豈如含膏入香作金餅，蜿蜒兩龍戲以呀。", "其餘品第亦奇絕，愈小愈精皆露芽。", "泛之白花如粉乳，乍見紫面生光華。", "手持心愛不欲碾，有類弄印幾成窊。", "論功可以療百疾，輕身久服勝胡麻。", "我謂斯言頗過矣，其實最能祛睡邪。", "茶官貢餘偶分寄，地遠物新來意嘉。", "新烹屢酌不知厭，自謂此樂真無涯。", "未言久食成手顫，已覺疾饑生眼花。", "客遭水厄疲捧椀，口吻無異蝕月蟇。", "僮奴傍視疑復笑，嗜好乖僻誠堪嗟。", "更蒙酬句怪可駭，兒曹助噪聲哇哇。"]'),
('88fa9053-09e0-43f2-9f30-2aad3a1280d1','樂郊詩','歐陽修','宋','宋诗','song-poetry','','[]','樂郊何所樂，所樂從公遊。',204,'全唐诗/poet.song.17000.json','["樂郊何所樂，所樂從公遊。", "三日公不出，其民蹙然愁。", "一聞車馬音，從者如雲浮。", "吾問鄆之人，無乃失業不。", "云惟安其業，然後樂其休。", "樂郊何所有，胡不考公詩。", "有山在其東，有水出逶夷。", "有臺以臨望，有沼以游嬉。", "俯仰迷上下，朱欄映清池。", "草木非一種，青紅隨四時。", "其餘雖瑣屑，處置各有宜。", "樂郊何以名，吾爲本其意。", "自古賢哲人，所存非一世。", "當時偶然迹，來者因不廢。", "鄆非公久留，公去民孰賴。", "此亭公所登，此樹公所憩。", "俾民百年思，豈取一日醉。"]'),
('10349d16-4703-43df-ae62-a0df8a01df5b','洗兒歌','歐陽修','宋','宋诗','song-poetry','','[]','月暈王色如虹蜺，深山猛虎夜生兒。',128,'全唐诗/poet.song.17000.json','["月暈王色如虹蜺，深山猛虎夜生兒。", "虎兒可愛光陸離，開眼已有百步威。", "詩翁雖老神骨秀，想見嬌嬰目與眉。", "木星之精爲紫氣，照山生玉水生犀。", "兒翁不比他兒翁，三十年名天下知。", "材高位下眾所惜，天與此兒聊慰之。", "翁家洗兒眾人喜，不惜金錢散閭里。", "宛陵他日見高門，車馬煌煌梅氏子。"]'),
('80cd912a-57b1-4fac-b4b6-a37de44d9ef9','鳴鳩','歐陽修','宋','宋诗','song-poetry','','[]','天將陰，鳴鳩逐婦鳴中林，鳩婦怒啼無好音。',195,'全唐诗/poet.song.17000.json','["天將陰，鳴鳩逐婦鳴中林，鳩婦怒啼無好音。", "天雨止，鳩呼雪歸鳴且喜，婦不亟歸呼不已。", "逐之其去恨不早，呼不肯來固其理。", "吾老病骨知陰晴，每愁天陰聞此聲。", "日長思睡不可得，遭爾聒聒何時停。", "眾鳥笑鳴鳩，爾拙固無匹。", "不能娶巧婦，以共營家室。", "寄巢生子四散飛，一身有婦長相失。", "夫婦之恩重太山，背恩棄義須臾間。", "心非無情不得已，物有至拙誠可憐。", "君不見人心百態巧且艱，臨危利害兩相關。", "朝爲親戚暮仇敵，自古常嗟交道難。"]'),
('89ae1ba0-9067-4502-9871-108e86bc5607','代鳩婦言','歐陽修','宋','宋诗','song-poetry','','[]','斑然錦翼花簇簇，雄雌相隨樂不足。',112,'全唐诗/poet.song.17000.json','["斑然錦翼花簇簇，雄雌相隨樂不足。", "抱雛出卵翅羽成，豈料一朝還反目。", "人言嫁雞逐雞飛，安知嫁鳩被鳩逐。", "古來有盛必有衰，富貴莫忘貧賤時。", "女棄父母嫁曰歸，中道捨君何所之。", "天生萬物各有類，誰謂鳥獸爲無知。", "雖無仁義不情愛，苟聞此言寧不悲。"]'),
('4e1e9914-44cb-4d41-a645-562e5f69dc2e','看花呈子華內翰','歐陽修','宋','宋诗','song-poetry','','[]','老雖可憎還可嗟，病眼眵昏愁看花。',128,'全唐诗/poet.song.17000.json','["老雖可憎還可嗟，病眼眵昏愁看花。", "不知花開桃與李，但見紅白何交加。", "春深雨露新洗濯，日暖金碧相輝華。", "浮香著物收不得，含意欲吐情無涯。", "可愛踈簾靜相對，最宜落日初西斜。", "時傾賜壺共斟酌，及此峰鳥方諠譁。", "凡花易見不足數，禁籞難到堪歸誇。", "老病對此不知厭，年少何用苦思家。"]'),
('2dfc22b9-80f4-4de5-a6c2-6494ea150521','啼鳥','歐陽修','宋','宋诗','song-poetry','','[]','提葫蘆，提葫蘆，不用沽美酒。',140,'全唐诗/poet.song.17000.json','["提葫蘆，提葫蘆，不用沽美酒。", "宮壺日賜新撥醅，老病足以扶衰朽。", "百舌子，百舌子，莫道泥滑滑。", "宮花正好愁雨來，暖日方催花亂發。", "苑樹千重綠暗春，珍禽綵羽自成羣。", "花開祗慣迎黄屋，鳥語初驚見外人。", "千聲百囀忽飛去，枝上自落紅紛紛。", "畫簾陰陰隔宮燭，禁漏杳杳深千門。", "可憐枕上五更聽，不似滁州山裏聞。"]');
